      className={`px-2 py-0.5 rounded transition-all ${path.length === 0 ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-500/30' : 'hover:bg-white/10 hover:text-fuchsia-400'}`}
    >
      Global
    </button>
    {path.map((segment, idx) => (
      <React.Fragment key={idx}>
        <span className="text-slate-600 mx-0.5">/</span>
        <button 
          onClick={() => onNavigate(idx)} 
          className={`px-2 py-0.5 rounded transition-all ${idx === path.length - 1 ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-500/30' : 'hover:bg-white/10 hover:text-fuchsia-400'}`}
        >
          {segment}
        </button>
      </React.Fragment>
    ))}
  </div>
);

interface WidgetContainerProps {
  widget: WidgetConfig;
  mode: EditMode;
  data: any[];
  onAnalyze: (widget: WidgetConfig, currentData: any[]) => void;
  onResize?: (id: string, w: number, h: number) => void;
}

export const WidgetContainer: React.FC<WidgetContainerProps> = ({ widget, mode, data, onAnalyze, onResize }) => {
  const [drillPath, setDrillPath] = useState<string[]>([]);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isResizing, setIsResizing] = useState(false);

  const currentLevelIndex = Math.min(drillPath.length, DRILL_HIERARCHY.length - 1);
  const currentLevel = DRILL_HIERARCHY[currentLevelIndex];
  const canDrill = drillPath.length < DRILL_HIERARCHY.length;

  // Filter data based on current drill-down path
  const filteredData = useMemo(() => {
    let result = data;
    drillPath.forEach((val, idx) => {
      const dim = DRILL_HIERARCHY[idx];
      result = result.filter(item => String(item[dim]) === val);
    });
    return result;
  }, [data, drillPath]);

  const handleDrill = (val: string) => {
    if (drillPath.length < DRILL_HIERARCHY.length) {
      setDrillPath([...drillPath, val]);
    }
  };

  const handleNavigate = (idx: number) => {
    setDrillPath(drillPath.slice(0, idx + 1));
  };

  const handleLevelUp = () => {
    setDrillPath(drillPath.slice(0, -1));
  };

  // Resizing Logic
  const handleMouseDown = (e: React.MouseEvent) => {
    if (mode !== EditMode.PRO || !onResize) return;
    e.preventDefault();
    setIsResizing(true);

    const startX = e.clientX;
    const startY = e.clientY;
    const startW = widget.w;
    const startH = widget.h;

    // Approximate grid dimensions
    const gridEl = containerRef.current?.parentElement;
    const gridWidth = gridEl ? gridEl.clientWidth : 1000;
    const colWidth = gridWidth / 12; 
    const rowHeight = 100; // Estimated row height base

    const handleMouseMove = (moveEvent: MouseEvent) => {
      const deltaX = moveEvent.clientX - startX;
      const deltaY = moveEvent.clientY - startY;

      const deltaCols = Math.round(deltaX / colWidth);
      const deltaRows = Math.round(deltaY / rowHeight);

      const newW = Math.max(3, Math.min(12, startW + deltaCols));
      const newH = Math.max(1, Math.min(8, startH + deltaRows));

      if (newW !== widget.w || newH !== widget.h) {
         onResize(widget.id, newW, newH);
      }
    };

    const handleMouseUp = () => {
      setIsResizing(false);
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };

    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  };

  return (
    <div 
      ref={containerRef}
      className={`glass-panel rounded-3xl flex flex-col transition-all relative group/widget backdrop-blur-md ${isResizing ? 'z-50 border-fuchsia-500 shadow-2xl' : 'hover:border-fuchsia-500/30'}`}
      style={{ 
        gridColumn: `span ${widget.w}`, 
        gridRow: `span ${widget.h}`,
        userSelect: isResizing ? 'none' : 'auto'
      }}
    >
      {widget.type !== VizType.KPI_CARD && (
        <div className="px-6 py-4 border-b border-white/5 flex items-center justify-between bg-white/[0.02] rounded-t-3xl">
          <div className="flex flex-col">
            <span className="text-sm font-black text-white tracking-tight uppercase drop-shadow-sm">{widget.title}</span>
            <Breadcrumbs path={drillPath} onNavigate={handleNavigate} />
          </div>
          <div className="flex items-center gap-2">
            <button
               onClick={() => onAnalyze(widget, filteredData)}
               className="flex items-center gap-1.5 px-3 py-1.5 bg-white/5 border border-white/10 rounded-lg text-[10px] font-bold text-slate-400 uppercase tracking-wider hover:text-white hover:bg-white/10 hover:border-white/20 transition-all shadow-sm"
            >
              <Icons.Sparkles /> Analyze
            </button>
            {drillPath.length > 0 && (
              <button 
                onClick={handleLevelUp}
                className="p-1.5 hover:bg-white/10 rounded-lg text-slate-500 hover:text-white transition-colors"
                title="Go up one level"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 10l7-7m0 0l7 7m-7-7v18" />
                </svg>
              </button>
            )}
          </div>
        </div>
      )}

      {widget.type === VizType.KPI_CARD && (
         <div className="absolute top-4 right-4 opacity-0 group-hover/widget:opacity-100 transition-opacity z-20">
            <button onClick={() => onAnalyze(widget, filteredData)} className="p-2 bg-fuchsia-500/20 text-fuchsia-300 rounded-full shadow-sm hover:scale-110 transition-transform">
               <Icons.Sparkles />
            </button>
         </div>
      )}

      <div className="flex-1 p-6 relative overflow-hidden">
        <ChartRenderer 
          config={widget} 
          data={filteredData} 
          onDrill={handleDrill} 
          currentLevel={currentLevel}
          drillPath={drillPath}
          canDrill={canDrill}
        />
      </div>

      {/* Resize Handle */}
      {mode === EditMode.PRO && (
        <div 
          onMouseDown={handleMouseDown}
          className="absolute bottom-0 right-0 w-6 h-6 cursor-se-resize z-20 flex items-center justify-center opacity-0 group-hover/widget:opacity-100 transition-opacity"
        >
          <svg className="w-4 h-4 text-fuchsia-500 transform rotate-45" fill="none" viewBox="0 0 24 24" stroke="currentColor">
             <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 5v14m7-14v14" />
          </svg>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Icons } from '../constants';
import { parsePrompt } from '../services/aiService';
import { WidgetConfig, SemanticModel, VizType } from '../types';

interface MagicBarProps {
  onWidgetGenerated: (widget: WidgetConfig) => void;
  semanticModel?: SemanticModel;
}

export const MagicBar: React.FC<MagicBarProps> = ({ onWidgetGenerated, semanticModel }) => {
  const [query, setQuery] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setIsGenerating(true);
    setShowSuggestions(false);
    try {
      const widget = await parsePrompt(query, semanticModel);
      onWidgetGenerated(widget);
      setQuery('');
    } catch (error) {
      console.error("AI Generation failed", error);
    } finally {
      setIsGenerating(false);
    }
  };

  const suggestions = Object.values(VizType).filter(type => 
    type.toLowerCase().includes(query.toLowerCase()) && query.length > 0
  );

  return (
    <div className="fixed bottom-8 left-1/2 transform -translate-x-1/2 w-full max-w-2xl px-4 z-50">
      <form onSubmit={handleSubmit} className="relative group">
        <div className={`absolute -inset-0.5 bg-gradient-to-r from-fuchsia-600 to-purple-600 rounded-full opacity-75 blur transition duration-500 ${isGenerating ? 'animate-pulse' : 'group-hover:opacity-100'}`}></div>
        <div className="relative flex items-center bg-slate-900/90 backdrop-blur-xl rounded-full p-2 pl-4 shadow-2xl border border-white/20">
          <div className={`text-fuchsia-400 mr-3 ${isGenerating ? 'animate-spin' : ''}`}>
             <Icons.Sparkles />
          </div>
          <input 
            ref={inputRef}
            type="text" 
            value={query}
            onChange={(e) => {
                setQuery(e.target.value);
                setShowSuggestions(true);
            }}
            onFocus={() => setShowSuggestions(true)}
            onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
            placeholder={isGenerating ? "Designing your widget..." : "Ask OmniGen... (e.g. 'Trend of sales over time')"}
            className="flex-1 bg-transparent border-none outline-none text-slate-100 placeholder-slate-500 font-medium text-sm"
            disabled={isGenerating}
          />
          <button 
            type="submit"
            disabled={!query.trim() || isGenerating}
            className={`p-2 rounded-full transition-all duration-300 ${query.trim() ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-500/50 scale-100' : 'bg-slate-800 text-slate-600 scale-90'}`}
          >
            <svg className="w-5 h-5 transform rotate-90" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
            </svg>
          </button>
        </div>

        {/* Search Suggestions Dropdown */}
        {showSuggestions && query.length > 0 && suggestions.length > 0 && (
           <div className="absolute bottom-full left-6 right-6 mb-2 bg-slate-900/95 backdrop-blur-xl border border-white/10 rounded-2xl shadow-xl overflow-hidden animate-in slide-in-from-bottom-2">
              <div className="p-2">
                 <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest px-3 py-2">Suggested Viz Types</div>
                 {suggestions.map((type) => (
                    <button
                       key={type}
                       type="button"
                       onClick={() => {
                           setQuery(`Create a ${type} showing `);
                           inputRef.current?.focus();
                       }}
                       className="w-full text-left px-3 py-2 text-sm text-slate-300 hover:bg-white/10 hover:text-white rounded-lg transition-colors flex items-center justify-between group/item"
                    >
                       <span>{type}</span>
                       <span className="opacity-0 group-hover/item:opacity-100 text-[10px] text-fuchsia-400">Use Type</span>
                    </button>
                 ))}
              </div>
           </div>
        )}
      </form>

      {/* Default Prompt Pills */}
      {!query && !isGenerating && (
         <div className="absolute -top-12 left-1/2 transform -translate-x-1/2 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity duration-300 delay-150 pointer-events-none">
            <div className="px-3 py-1.5 bg-slate-900/90 backdrop-blur rounded-xl text-[10px] font-bold text-slate-400 shadow-lg border border-white/10">"Show Sales Trend"</div>
            <div className="px-3 py-1.5 bg-slate-900/90 backdrop-blur rounded-xl text-[10px] font-bold text-slate-400 shadow-lg border border-white/10">"Regional Breakdown"</div>
         </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect, useCallback } from 'react';
