import { GoogleGenAI, Type } from "@google/genai";
import { VizType, WidgetConfig, SemanticModel, AnalysisResult } from '../types';

// Fallback heuristic logic for when API key is missing or offline
const heuristicParse = (prompt: string): WidgetConfig => {
  const lower = prompt.toLowerCase();
  const id = `ai-${Date.now()}`;

  let type = VizType.KPI_CARD;
  let w = 3;
  let h = 1;

  if (lower.includes('scatter') || lower.includes('correlation') || lower.includes('relationship')) {
    type = VizType.SCATTER;
    w = 6;
    h = 4;
  } else if (lower.includes('heat') || lower.includes('matrix') || lower.includes('density')) {
    type = VizType.HEATMAP;
    w = 6;
    h = 4;
  } else if (lower.includes('tree') || lower.includes('hierarchy') || lower.includes('composition')) {
    type = VizType.TREEMAP;
    w = 8;
    h = 4;
  } else if (lower.includes('flow') || lower.includes('journey') || lower.includes('sankey')) {
    type = VizType.SANKEY;
    w = 12;
    h = 4;
  } else if (lower.includes('trend') || lower.includes('growth') || lower.includes('over time')) {
    type = VizType.TIME_SERIES;
    w = 6;
    h = 3;
  } else if (lower.includes('breakdown') || lower.includes('compare') || lower.includes('vs') || lower.includes('distribution')) {
    type = VizType.BAR;
    w = 6;
    h = 3;
  } else if (lower.includes('map') || lower.includes('geo')) {
    type = VizType.GEO_MAP;
    w = 6;
    h = 4;
  } else if (lower.includes('funnel') || lower.includes('conversion') || lower.includes('pipeline')) {
      type = VizType.FUNNEL;
      w = 6;
      h = 3;
  }

  const title = prompt.length > 5 ? prompt.split(' ').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(' ') : 'AI Insight';

  return {
    id,
    type,
    title,
    x: 0,
    y: 0,
    w,
    h,
  };
};

// Smart aggregation for analysis to handle larger datasets
const smartSampleData = (data: any[]): any[] => {
  if (data.length <= 50) return data;

  // Identify schema
  const sample = data[0];
  const numericKeys = Object.keys(sample).filter(k => typeof sample[k] === 'number');
  const stringKeys = Object.keys(sample).filter(k => typeof sample[k] === 'string');
  const groupKey = stringKeys.find(k => k.toLowerCase().includes('date') || k.toLowerCase().includes('category') || k.toLowerCase().includes('region')) || stringKeys[0] || 'id';

  // Aggregate
  const grouped: Record<string, any> = {};
  data.forEach(row => {
    const key = row[groupKey];
    if (!grouped[key]) {
      grouped[key] = { ...row };
      numericKeys.forEach(nk => grouped[key][nk] = 0);
    }
    numericKeys.forEach(nk => grouped[key][nk] += (row[nk] || 0));
  });

  let result = Object.values(grouped);

  // If still too large, sort by significant metric and take top 30
  if (result.length > 30 && numericKeys.length > 0) {
      // Pick first metric to sort by
      const sortKey = numericKeys[0];
      result.sort((a, b) => b[sortKey] - a[sortKey]);
      result = result.slice(0, 30);
  }

  return result.slice(0, 30);
};

export const parsePrompt = async (prompt: string, semanticModel?: SemanticModel): Promise<WidgetConfig> => {
  // 1. Check for API Key availability
  if (!process.env.API_KEY) {
    console.warn("[OmniGen] No API_KEY found. Using heuristic fallback.");
    return new Promise((resolve) => {
      setTimeout(() => resolve(heuristicParse(prompt)), 800);
    });
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const availableMetrics = semanticModel?.metrics.map(m => m.name).join(', ') || 'Sales, Users, Conversion';
    const availableDimensions = semanticModel?.dimensions.map(d => d.name).join(', ') || 'Date, Region, Category';

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `
        You are an expert data visualization architect.
        User Request: "${prompt}"

        Available Data Fields:
        - Metrics: ${availableMetrics}
        - Dimensions: ${availableDimensions}

        Task: Generate a JSON configuration for a dashboard widget that best visualizes this request.

        Rules:
        - Select the most appropriate 'type' from: ${Object.values(VizType).join(', ')}.
        - Use 'scatter' for correlations, 'heatmap' for density/matrix, 'treemap' for hierarchical composition.
        - 'w' (width) should be between 3 and 12. 
        - 'h' (height) should be between 1 and 4.
        - KPI cards should be small (3x1). Complex charts should be larger (6x3 or 6x4).
        - 'id' should be unique (use a random string suffix).
        - 'x' and 'y' should be 0 (the grid layout handles placement).
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            type: { 
              type: Type.STRING, 
              enum: Object.values(VizType) 
            },
            title: { type: Type.STRING },
            w: { type: Type.INTEGER },
            h: { type: Type.INTEGER },
            x: { type: Type.INTEGER },
            y: { type: Type.INTEGER }
          },
          required: ["id", "type", "title", "w", "h", "x", "y"]
        }
      }
    });

    const text = response.text;
    if (text) {
      const config = JSON.parse(text) as WidgetConfig;
      config.id = config.id || `gen-${Date.now()}`;
      return config;
    }

    throw new Error("Empty response from AI");

  } catch (error) {
    console.error("[OmniGen] AI Generation failed, falling back to heuristics:", error);
    return heuristicParse(prompt);
  }
};

export const generateAnalysis = async (title: string, data: any[]): Promise<AnalysisResult> => {
  // Fallback for demo/offline
  if (!process.env.API_KEY) {
    return new Promise((resolve) => {
      setTimeout(() => resolve({
        summary: `Analysis of ${title} indicates a stable trend with minor fluctuations. The data suggests consistent performance across the selected timeframe.`,
        drivers: ["Consistent user engagement", "Seasonal baseline effects"],
        recommendations: ["Monitor for upcoming seasonal spikes", "Investigate lower performing segments"],
        sentiment: "neutral",
        marketContext: "Similar industries typically see a 5-10% variance in this period due to macroeconomic factors.",
        sources: [
            { title: "Global Industry Report 2024", uri: "#" },
            { title: "Market Trends Daily", uri: "#" }
        ]
      }), 1500);
    });
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Aggregation Logic for large datasets
    const aggregatedData = smartSampleData(data);
    const dataSample = JSON.stringify(aggregatedData);

    // Parallel execution: Internal Analysis (JSON) + External Context (Search)
    const [internalResponse, externalResponse] = await Promise.all([
        ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `
              Role: Senior Business Analyst.
              Task: Analyze the following dataset for a chart titled "${title}".
              Data (Aggregated Sample): ${dataSample}

              Provide:
              1. An executive summary (max 2 sentences).
              2. Key drivers/factors (max 3 bullet points).
              3. Strategic recommendations (max 2).
              4. Overall sentiment.
            `,
            config: {
              responseMimeType: "application/json",
              responseSchema: {
                type: Type.OBJECT,
                properties: {
                  summary: { type: Type.STRING },
                  drivers: { type: Type.ARRAY, items: { type: Type.STRING } },
                  recommendations: { type: Type.ARRAY, items: { type: Type.STRING } },
                  sentiment: { type: Type.STRING, enum: ["positive", "negative", "neutral"] }
                }
              }
            }
        }),
        ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Briefly summarize the latest market trends, industry benchmarks, or news related to the business topic: "${title}". Focus on high-level business implications. Keep it under 50 words.`,
            config: {
                tools: [{googleSearch: {}}]
            }
        })
    ]);

    const result = JSON.parse(internalResponse.text!) as AnalysisResult;

    // Attach External Context
    if (externalResponse.text) {
        result.marketContext = externalResponse.text;
    }

    // Attach Grounding Sources
    const chunks = externalResponse.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) {
        result.sources = chunks
            .map((c: any) => c.web ? { title: c.web.title, uri: c.web.uri } : null)
            .filter((c: any) => c !== null);
    }

    return result;

  } catch (error) {
    console.error("Analysis failed", error);
    return {
       summary: "Could not generate analysis at this time.",
       drivers: [],
       recommendations: [],
       sentiment: "neutral"
    };
  }
};

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { WidgetConfig, EditMode, VizType } from '../types';
import { ChartRenderer } from './ChartRenderer';
import { Icons } from '../constants';

const DRILL_HIERARCHY = ['region', 'category', 'date'];

interface BreadcrumbsProps {
  path: string[];
  onNavigate: (index: number) => void;
}

const Breadcrumbs: React.FC<BreadcrumbsProps> = ({ path, onNavigate }) => (
  <div className="flex items-center gap-1 text-[10px] font-bold text-slate-500 uppercase tracking-widest mt-1.5 px-0.5">
    <button 
      onClick={() => onNavigate(-1)} 
      className={`px-2 py-0.5 rounded transition-all ${path.length === 0 ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-500/30' : 'hover:bg-white/10 hover:text-fuchsia-400'}`}
    >
      Global
    </button>
    {path.map((segment, idx) => (
      <React.Fragment key={idx}>
        <span className="text-slate-600 mx-0.5">/</span>
        <button 
          onClick={() => onNavigate(idx)} 
          className={`px-2 py-0.5 rounded transition-all ${idx === path.length - 1 ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-500/30' : 'hover:bg-white/10 hover:text-fuchsia-400'}`}
        >
          {segment}
        </button>
      </React.Fragment>
    ))}
  </div>
);

interface WidgetContainerProps {
  widget: WidgetConfig;
  mode: EditMode;
  data: any[];
  onAnalyze: (widget: WidgetConfig, currentData: any[]) => void;
  onResize?: (id: string, w: number, h: number) => void;
}

export const WidgetContainer: React.FC<WidgetContainerProps> = ({ widget, mode, data, onAnalyze, onResize }) => {
  const [drillPath, setDrillPath] = useState<string[]>([]);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isResizing, setIsResizing] = useState(false);

  const currentLevelIndex = Math.min(drillPath.length, DRILL_HIERARCHY.length - 1);
  const currentLevel = DRILL_HIERARCHY[currentLevelIndex];
  const canDrill = drillPath.length < DRILL_HIERARCHY.length;

  // Filter data based on current drill-down path
  const filteredData = useMemo(() => {
    let result = data;
    drillPath.forEach((val, idx) => {
      const dim = DRILL_HIERARCHY[idx];
      result = result.filter(item => String(item[dim]) === val);
    });
    return result;
  }, [data, drillPath]);

  const handleDrill = (val: string) => {
    if (drillPath.length < DRILL_HIERARCHY.length) {
      setDrillPath([...drillPath, val]);
    }
  };

  const handleNavigate = (idx: number) => {
    setDrillPath(drillPath.slice(0, idx + 1));
  };

  const handleLevelUp = () => {
    setDrillPath(drillPath.slice(0, -1));
  };

  // Resizing Logic
  const handleMouseDown = (e: React.MouseEvent) => {
    if (mode !== EditMode.PRO || !onResize) return;
    e.preventDefault();
    setIsResizing(true);

    const startX = e.clientX;
    const startY = e.clientY;
    const startW = widget.w;
    const startH = widget.h;

    // Approximate grid dimensions or calculate dynamically
    const node = containerRef.current;
    if (!node) return;

    const rect = node.getBoundingClientRect();
    const cellWidth = rect.width / startW;
    const cellHeight = rect.height / startH;

    const handleMouseMove = (moveEvent: MouseEvent) => {
      const deltaX = moveEvent.clientX - startX;
      const deltaY = moveEvent.clientY - startY;

      // Calculate new dimensions based on grid cell size
      const newW = Math.max(3, Math.min(12, startW + Math.round(deltaX / cellWidth)));
      const newH = Math.max(1, Math.min(8, startH + Math.round(deltaY / cellHeight)));

      if (newW !== widget.w || newH !== widget.h) {
         onResize(widget.id, newW, newH);
      }
    };

    const handleMouseUp = () => {
      setIsResizing(false);
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };

    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  };

  return (
    <div 
      ref={containerRef}
      className={`glass-panel rounded-3xl flex flex-col transition-all relative group/widget backdrop-blur-md ${isResizing ? 'z-50 border-fuchsia-500 shadow-2xl' : 'hover:border-fuchsia-500/30'}`}
      style={{ 
        gridColumn: `span ${widget.w}`, 
        gridRow: `span ${widget.h}`,
        userSelect: isResizing ? 'none' : 'auto'
      }}
    >
      {widget.type !== VizType.KPI_CARD && (
        <div className="px-6 py-4 border-b border-white/5 flex items-center justify-between bg-white/[0.02] rounded-t-3xl">
          <div className="flex flex-col">
            <span className="text-sm font-black text-white tracking-tight uppercase drop-shadow-sm">{widget.title}</span>
            <Breadcrumbs path={drillPath} onNavigate={handleNavigate} />
          </div>
          <div className="flex items-center gap-2">
            <button
               onClick={() => onAnalyze(widget, filteredData)}
               className="flex items-center gap-1.5 px-3 py-1.5 bg-white/5 border border-white/10 rounded-lg text-[10px] font-bold text-slate-400 uppercase tracking-wider hover:text-white hover:bg-white/10 hover:border-white/20 transition-all shadow-sm"
            >
              <Icons.Sparkles /> Analyze
            </button>
            {drillPath.length > 0 && (
              <button 
                onClick={handleLevelUp}
                className="p-1.5 hover:bg-white/10 rounded-lg text-slate-500 hover:text-white transition-colors"
                title="Go up one level"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 10l7-7m0 0l7 7m-7-7v18" />
                </svg>
              </button>
            )}
          </div>
        </div>
      )}

      {widget.type === VizType.KPI_CARD && (
         <div className="absolute top-4 right-4 opacity-0 group-hover/widget:opacity-100 transition-opacity z-20">
            <button onClick={() => onAnalyze(widget, filteredData)} className="p-2 bg-fuchsia-500/20 text-fuchsia-300 rounded-full shadow-sm hover:scale-110 transition-transform">
               <Icons.Sparkles />
            </button>
         </div>
      )}

      <div className="flex-1 p-6 relative overflow-hidden">
        <ChartRenderer 
          config={widget} 
          data={filteredData} 
          onDrill={handleDrill} 
          currentLevel={currentLevel}
          drillPath={drillPath}
          canDrill={canDrill}
        />
      </div>

      {/* Resize Handle */}
      {mode === EditMode.PRO && (
        <div 
          onMouseDown={handleMouseDown}
          className="absolute bottom-0 right-0 w-6 h-6 cursor-se-resize z-20 flex items-center justify-center opacity-0 group-hover/widget:opacity-100 transition-opacity"
        >
          <svg className="w-4 h-4 text-fuchsia-500 transform rotate-45" fill="none" viewBox="0 0 24 24" stroke="currentColor">
             <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 5v14m7-14v14" />
          </svg>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Icons } from '../constants';
import { parsePrompt } from '../services/aiService';
import { WidgetConfig, SemanticModel, VizType } from '../types';

interface MagicBarProps {
  onWidgetGenerated: (widget: WidgetConfig) => void;
  semanticModel?: SemanticModel;
}

export const MagicBar: React.FC<MagicBarProps> = ({ onWidgetGenerated, semanticModel }) => {
  const [query, setQuery] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setIsGenerating(true);
    setShowSuggestions(false);
    try {
      const widget = await parsePrompt(query, semanticModel);
      onWidgetGenerated(widget);
      setQuery('');
    } catch (error) {
      console.error("AI Generation failed", error);
    } finally {
      setIsGenerating(false);
    }
  };

  const suggestions = Object.values(VizType).filter(type => 
    type.toLowerCase().includes(query.toLowerCase()) && query.length > 0
  );

  return (
    <div className="fixed bottom-8 left-1/2 transform -translate-x-1/2 w-full max-w-2xl px-4 z-50">
      <form onSubmit={handleSubmit} className="relative group">
        <div className={`absolute -inset-0.5 bg-gradient-to-r from-fuchsia-600 to-purple-600 rounded-full opacity-75 blur transition duration-500 ${isGenerating ? 'animate-pulse' : 'group-hover:opacity-100'}`}></div>
