import React, { useMemo } from 'react';
import { Icons } from '../constants';
import { VizType, WidgetConfig } from '../types';
import { VizArea } from './VizArea';
import { VizBar } from './VizBar';
import { VizKPI } from './VizKPI';
import { VizScatter } from './VizScatter';
import { VizHeatmap } from './VizHeatmap';
import { VizTreemap } from './VizTreemap';

interface ChartRendererProps {
  config: WidgetConfig;
  data: any[];
  onDrill: (value: string) => void;
  currentLevel: string;
  drillPath: string[];
  canDrill: boolean;
}

export const ChartRenderer: React.FC<ChartRendererProps> = ({ config, data, onDrill, currentLevel, drillPath, canDrill }) => {

  // -- Standard Aggregation (Bar, Line, KPI) --
  const standardData = useMemo(() => {
    if ([VizType.SCATTER, VizType.HEATMAP, VizType.TREEMAP].includes(config.type)) return [];

    const metric = config.metric || 'sales';
    const agg: Record<string, any> = {};

    data.forEach(item => {
      const key = String(item[currentLevel] || 'Unknown');
      if (!agg[key]) {
        agg[key] = { [currentLevel]: key };
        agg[key][metric] = 0;
        // Ensure default metrics exist for templates that might rely on them hardcoded
        if (metric !== 'sales') agg[key]['sales'] = 0;
        if (metric !== 'users') agg[key]['users'] = 0;
      }
      agg[key][metric] += Number(item[metric] || 0);

      // Accumulate defaults if they exist in data
      if (metric !== 'sales' && item.sales) agg[key]['sales'] += Number(item.sales);
      if (metric !== 'users' && item.users) agg[key]['users'] += Number(item.users);
    });

    return Object.values(agg).sort((a, b) => String(a[currentLevel]).localeCompare(String(b[currentLevel])));
  }, [data, currentLevel, config.type, config.metric]);

  // -- Scatter Data (Raw) --
  const scatterData = useMemo(() => {
    if (config.type !== VizType.SCATTER) return [];
    return data.map(d => ({
        ...d,
        // Ensure numeric values for the selected keys
        [config.dimension || 'sales']: Number(d[config.dimension || 'sales'] || 0),
        [config.secondaryDimension || 'users']: Number(d[config.secondaryDimension || 'users'] || 0),
        [config.metric || 'conversion']: Number(d[config.metric || 'conversion'] || 0),
    }));
  }, [data, config.type, config.dimension, config.secondaryDimension, config.metric]);

  // -- Heatmap Data (Pivoted) --
  const heatmapData = useMemo(() => {
    if (config.type !== VizType.HEATMAP) return [];
    // Default Dimensions: Region vs Category
    const xKey = config.dimension || 'category';
    const yKey = config.secondaryDimension || 'region';
    const valKey = config.metric || 'sales';

    const agg: Record<string, any> = {};
    data.forEach(item => {
        const x = String(item[xKey] || 'N/A');
        const y = String(item[yKey] || 'N/A');
        const key = `${x}-${y}`;
        if(!agg[key]) agg[key] = { [xKey]: x, [yKey]: y, [valKey]: 0 };
        agg[key][valKey] += Number(item[valKey] || 0);
    });
    return Object.values(agg);
  }, [data, config.type, config.dimension, config.secondaryDimension, config.metric]);

  // -- Treemap Data (Hierarchical) --
  const treemapData = useMemo(() => {
      if (config.type !== VizType.TREEMAP) return [];
      const valKey = config.metric || 'sales';
      // Group by current Level
      const agg: Record<string, number> = {};
      data.forEach(item => {
          const key = String(item[currentLevel] || 'Unknown');
          agg[key] = (agg[key] || 0) + Number(item[valKey] || 0);
      });
      return Object.entries(agg).map(([name, size]) => ({ name, size }));
  }, [data, config.type, currentLevel, config.metric]);

  // Render Logic
  switch (config.type) {
    case VizType.TIME_SERIES:
      return <VizArea 
        data={standardData} 
        onDrill={onDrill} 
        currentLevel={currentLevel} 
        drillPath={drillPath} 
        canDrill={canDrill}
        metric={config.metric || 'sales'}
      />;

    case VizType.BAR:
      return <VizBar 
        data={standardData} 
        onDrill={onDrill} 
        currentLevel={currentLevel} 
        drillPath={drillPath} 
        canDrill={canDrill}
        metric={config.metric || 'sales'}
      />;

    case VizType.KPI_CARD:
      const metric = config.metric || 'sales';
      // Calculate total dynamically based on metric
      const total = standardData.reduce((acc, curr) => acc + (Number(curr[metric]) || 0), 0);
      return <VizKPI title={config.title} value={`${total.toLocaleString()}`} trend="--" isPositive={true} />;

    case VizType.SCATTER:
        return <VizScatter 
          data={scatterData} 
          xKey={config.dimension || 'sales'}
          yKey={config.secondaryDimension || 'users'}
          zKey={config.metric || 'conversion'}
        />;

    case VizType.HEATMAP:
        return <VizHeatmap 
          data={heatmapData} 
          xKey={config.dimension || 'category'} 
          yKey={config.secondaryDimension || 'region'} 
          valKey={config.metric || 'sales'} 
        />;

    case VizType.TREEMAP:
        return <VizTreemap data={treemapData} />;

    default:
      return (
        <div className="flex flex-col items-center justify-center h-full text-slate-600 gap-2">
          <Icons.Dashboard />
          <span className="text-xs font-semibold uppercase tracking-widest">{config.type} Placeholder</span>
        </div>
      );
  }
};

import React, { useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend, Cell } from 'recharts';
import { VizTooltip } from './VizTooltip';

interface VizBarProps {
  data: any[];
  onDrill: (value: string) => void;
  currentLevel: string;
  drillPath: string[];
  canDrill: boolean;
  metric?: string;
}

export const VizBar: React.FC<VizBarProps> = ({ data, onDrill, currentLevel, drillPath, canDrill, metric = 'sales' }) => {
  const [hiddenSeries, setHiddenSeries] = useState<Set<string>>(new Set());

  const handleLegendClick = (o: any) => {
    const { dataKey } = o;
    setHiddenSeries(prev => {
      const next = new Set(prev);
      if (next.has(dataKey)) next.delete(dataKey);
      else next.add(dataKey);
      return next;
    });
  };

  const handleClick = (state: any) => {
    if (state && state.activeLabel) {
      onDrill(String(state.activeLabel));
    } else if (state && state.activePayload && state.activePayload[0]) {
      const val = state.activePayload[0].payload[currentLevel];
      if (val) onDrill(String(val));
    }
  };

  const commonAxisProps = {
    axisLine: false,
    tickLine: false,
    tick: { fontSize: 10, fill: '#94a3b8', fontWeight: 600 }
  };

  return (
    <ResponsiveContainer width="100%" height="100%">
      <BarChart data={data} onClick={handleClick} cursor="pointer">
        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#334155" opacity={0.3} />
        <XAxis dataKey={currentLevel} {...commonAxisProps} />
        <YAxis {...commonAxisProps} />
        <Tooltip 
          content={<VizTooltip currentLevel={currentLevel} drillPath={drillPath} canDrill={canDrill} />}
          cursor={{ fill: '#a855f7', opacity: 0.1 }}
          allowEscapeViewBox={{ x: true, y: true }}
          wrapperStyle={{ zIndex: 50, outline: 'none' }}
        />
        <Legend 
          onClick={handleLegendClick}
          wrapperStyle={{ paddingTop: '10px', fontSize: '10px', fontWeight: 'bold', textTransform: 'uppercase', cursor: 'pointer', color: '#cbd5e1' }}
        />
        {!hiddenSeries.has(metric) && (
          <Bar name={metric} dataKey={metric} radius={[6, 6, 0, 0]}>
            {data.map((_, index) => (
              <Cell key={`cell-${metric}-${index}`} fill={index % 2 === 0 ? '#a855f7' : '#8b5cf6'} className="hover:opacity-80 transition-opacity filter drop-shadow-[0_0_8px_rgba(168,85,247,0.4)]" />
            ))}
          </Bar>
        )}
        {/* Fallback/Secondary bar if metrics are strictly sales/users and not dynamic - optional, but good for templates */}
        {metric === 'sales' && !hiddenSeries.has('users') && (
           <Bar name="users" dataKey="users" radius={[6, 6, 0, 0]}>
             {data.map((_, index) => (
               <Cell key={`cell-users-${index}`} fill={index % 2 === 0 ? '#ec4899' : '#db2777'} className="hover:opacity-80 transition-opacity filter drop-shadow-[0_0_8px_rgba(236,72,153,0.4)]" />
             ))}
           </Bar>
        )}
      </BarChart>
    </ResponsiveContainer>
  );
};

