  const currentLevelIndex = Math.min(drillPath.length, DRILL_HIERARCHY.length - 1);
  const currentLevel = DRILL_HIERARCHY[currentLevelIndex];
  const canDrill = drillPath.length < DRILL_HIERARCHY.length;

  // Extract available keys from data for settings dropdowns
  const dataKeys = useMemo(() => data.length > 0 ? Object.keys(data[0]) : [], [data]);

  // Filter data based on current drill-down path
  const filteredData = useMemo(() => {
    let result = data;
    drillPath.forEach((val, idx) => {
      const dim = DRILL_HIERARCHY[idx];
      result = result.filter(item => String(item[dim]) === val);
    });
    return result;
  }, [data, drillPath]);

  const handleDrill = (val: string) => {
    if (drillPath.length < DRILL_HIERARCHY.length) {
      setDrillPath([...drillPath, val]);
    }
  };

  const handleNavigate = (idx: number) => {
    setDrillPath(drillPath.slice(0, idx + 1));
  };

  const handleLevelUp = () => {
    setDrillPath(drillPath.slice(0, -1));
  };

  // --- Resize Handler ---
  const handleResizeStart = (e: React.MouseEvent) => {
    if (mode !== EditMode.PRO || !onResize) return;
    e.preventDefault();
    e.stopPropagation();
    setIsResizing(true);

    const startX = e.clientX;
    const startY = e.clientY;
    const startW = widget.w;
    const startH = widget.h;

    // Grid Calculation (Gap-Aware)
    const GAP = 24; 
    const ROW_HEIGHT = 100; // Matches auto-rows-[100px] in App.tsx
    const parent = containerRef.current?.offsetParent as HTMLElement;
    if (!parent) return;

    const parentWidth = parent.clientWidth;
    // 12 columns, 11 gaps
    const cellWidth = (parentWidth - (11 * GAP)) / 12;

    const stepX = cellWidth + GAP;
    const stepY = ROW_HEIGHT + GAP;

    const handleMouseMove = (moveEvent: MouseEvent) => {
      const deltaX = moveEvent.clientX - startX;
      const deltaY = moveEvent.clientY - startY;

      const deltaCols = Math.round(deltaX / stepX);
      const deltaRows = Math.round(deltaY / stepY);

      // Constraint resizing to grid bounds and min size
      const newW = Math.max(2, Math.min(12 - widget.x, startW + deltaCols));
      const newH = Math.max(1, Math.min(12, startH + deltaRows));

      if (newW !== widget.w || newH !== widget.h) {
         onResize(widget.id, newW, newH);
      }
    };

    const handleMouseUp = () => {
      setIsResizing(false);
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };

    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  };

  // --- Drag Handler ---
  const handleDragStart = (e: React.MouseEvent) => {
    if (mode !== EditMode.PRO || !onMove) return;
    if ((e.target as HTMLElement).closest('button')) return;

    e.preventDefault();
    setIsDragging(true);

    const startX = e.clientX;
    const startY = e.clientY;
    const startGridX = widget.x;
    const startGridY = widget.y;

    // Grid Calculation (Gap-Aware)
    const GAP = 24; 
    const ROW_HEIGHT = 100; // Matches auto-rows-[100px] in App.tsx
    const parent = containerRef.current?.offsetParent as HTMLElement;
    if (!parent) return;

    const parentWidth = parent.clientWidth;
    const cellWidth = (parentWidth - (11 * GAP)) / 12;

    const stepX = cellWidth + GAP;
    const stepY = ROW_HEIGHT + GAP;

    const handleMouseMove = (moveEvent: MouseEvent) => {
        const deltaX = moveEvent.clientX - startX;
        const deltaY = moveEvent.clientY - startY;

        const moveCols = Math.round(deltaX / stepX);
        const moveRows = Math.round(deltaY / stepY);

        const newX = Math.max(0, Math.min(12 - widget.w, startGridX + moveCols));
        const newY = Math.max(0, startGridY + moveRows);

        if (newX !== widget.x || newY !== widget.y) {
           onMove(widget.id, newX, newY);
        }
    };

    const handleMouseUp = () => {
        setIsDragging(false);
        document.removeEventListener('mousemove', handleMouseMove);
        document.removeEventListener('mouseup', handleMouseUp);
    };

    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  };

  return (
    <div 
      ref={containerRef}
      className={`glass-panel rounded-3xl flex flex-col transition-all relative group/widget backdrop-blur-md 
        ${isResizing || isDragging ? 'z-50 border-fuchsia-500 shadow-2xl scale-[1.02]' : 'hover:border-fuchsia-500/30'}
        ${mode === EditMode.PRO ? 'cursor-grab active:cursor-grabbing' : ''}
      `}
      style={{ 
        gridColumn: `span ${widget.w}`, 
        gridRow: `span ${widget.h}`,
        ...(widget.x > 0 || widget.y > 0 ? {
            gridColumnStart: widget.x + 1,
            gridRowStart: widget.y + 1
        } : {}),
        userSelect: isResizing || isDragging ? 'none' : 'auto'
      }}
      onMouseDown={handleDragStart}
    >
      {/* Settings Overlay */}
      {showSettings && (
          <div className="absolute inset-0 bg-slate-900/95 z-40 p-6 flex flex-col gap-4 animate-in fade-in rounded-3xl" onMouseDown={(e) => e.stopPropagation()}>
              <div className="flex justify-between items-center border-b border-white/10 pb-4">
                  <span className="font-bold text-white uppercase tracking-wider">Configure Widget</span>
                  <button onClick={() => setShowSettings(false)} className="text-slate-400 hover:text-white"><Icons.Settings /></button>
              </div>

              <div className="space-y-4 overflow-y-auto custom-scrollbar">
                  <div>
                      <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Title</label>
                      <input 
                          type="text" 
                          value={widget.title} 
                          onChange={(e) => onUpdate?.(widget.id, { title: e.target.value })}
                          className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:border-fuchsia-500 outline-none"
                      />
                  </div>

                  <div>
                      <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Dimension (X-Axis)</label>
                      <select 
                          value={widget.dimension || ''} 
                          onChange={(e) => onUpdate?.(widget.id, { dimension: e.target.value })}
                          className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:border-fuchsia-500 outline-none"
                      >
                          <option value="">Auto</option>
                          {dataKeys.map(k => <option key={k} value={k}>{k}</option>)}
                      </select>
                  </div>

                  <div>
                      <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Secondary Dimension (Y-Axis)</label>
                      <select 
                          value={widget.secondaryDimension || ''} 
                          onChange={(e) => onUpdate?.(widget.id, { secondaryDimension: e.target.value })}
                          className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:border-fuchsia-500 outline-none"
                      >
                          <option value="">None</option>
                          {dataKeys.map(k => <option key={k} value={k}>{k}</option>)}
                      </select>
                  </div>

                  <div>
                      <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Metric (Value)</label>
                      <select 
                          value={widget.metric || ''} 
                          onChange={(e) => onUpdate?.(widget.id, { metric: e.target.value })}
                          className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:border-fuchsia-500 outline-none"
                      >
                          <option value="">Auto</option>
                          {dataKeys.map(k => <option key={k} value={k}>{k}</option>)}
                      </select>
                  </div>
              </div>
          </div>
      )}

      {widget.type !== VizType.KPI_CARD && (
        <div className="px-6 py-4 border-b border-white/5 flex items-center justify-between bg-white/[0.02] rounded-t-3xl">
          <div className="flex flex-col">
            <span className="text-sm font-black text-white tracking-tight uppercase drop-shadow-sm">{widget.title}</span>
            <Breadcrumbs path={drillPath} onNavigate={handleNavigate} />
          </div>
          <div className="flex items-center gap-2">
            {mode === EditMode.PRO && (
                <button 
                    onClick={(e) => { e.stopPropagation(); setShowSettings(!showSettings); }}
                    className="p-1.5 hover:bg-white/10 rounded-lg text-slate-500 hover:text-white transition-colors"
                >
                    <Icons.Settings />
                </button>
            )}
            <button
               onClick={(e) => { e.stopPropagation(); onAnalyze(widget, filteredData); }}
               className="flex items-center gap-1.5 px-3 py-1.5 bg-white/5 border border-white/10 rounded-lg text-[10px] font-bold text-slate-400 uppercase tracking-wider hover:text-white hover:bg-white/10 hover:border-white/20 transition-all shadow-sm"
            >
              <Icons.Sparkles /> Analyze
            </button>
            {drillPath.length > 0 && (
              <button 
                onClick={(e) => { e.stopPropagation(); handleLevelUp(); }}
                className="p-1.5 hover:bg-white/10 rounded-lg text-slate-500 hover:text-white transition-colors"
                title="Go up one level"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 10l7-7m0 0l7 7m-7-7v18" />
                </svg>
              </button>
            )}
          </div>
        </div>
      )}

      {widget.type === VizType.KPI_CARD && (
         <div className="absolute top-4 right-4 opacity-0 group-hover/widget:opacity-100 transition-opacity z-20 flex gap-2">
            {mode === EditMode.PRO && (
                <button onClick={(e) => { e.stopPropagation(); setShowSettings(!showSettings); }} className="p-2 bg-slate-800 text-slate-300 rounded-full shadow-sm hover:scale-110 transition-transform">
                   <Icons.Settings />
                </button>
            )}
            <button onClick={(e) => { e.stopPropagation(); onAnalyze(widget, filteredData); }} className="p-2 bg-fuchsia-500/20 text-fuchsia-300 rounded-full shadow-sm hover:scale-110 transition-transform">
               <Icons.Sparkles />
            </button>
         </div>
      )}

      <div className="flex-1 p-6 relative overflow-hidden" onMouseDown={(e) => e.stopPropagation()}>
        <ChartRenderer 
          config={widget} 
          data={filteredData} 
          onDrill={handleDrill} 
          currentLevel={currentLevel}
          drillPath={drillPath}
          canDrill={canDrill}
        />
      </div>

      {/* Resize Handle */}
      {mode === EditMode.PRO && (
        <div 
          onMouseDown={handleResizeStart}
          className="absolute bottom-0 right-0 w-6 h-6 cursor-se-resize z-20 flex items-center justify-center opacity-0 group-hover/widget:opacity-100 transition-opacity"
        >
          <svg className="w-4 h-4 text-fuchsia-500 transform rotate-45" fill="none" viewBox="0 0 24 24" stroke="currentColor">
             <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 5v14m7-14v14" />
          </svg>
        </div>
      )}
    </div>
  );
};

/**
 * OmniGen Type Definitions
 * 
 * This file contains all shared interfaces and constants for the application.
 */

/**
 * Grid Layout Configuration
 * Corresponds to Tailwind classes: grid-cols-12, gap-6 (24px), auto-rows-[100px]
 */
export const GRID_SYSTEM = {
  COLS: 12,
  ROW_HEIGHT_PX: 100,
  GAP_PX: 24, // tailwind gap-6
};

export enum EditMode {
  SAFE = 'SAFE', // Prevents overlapping widgets
  PRO = 'PRO'    // Allows advanced editing (resizing, moving)
}

export enum VizType {
  TABLE = 'table',
  PIVOT = 'pivot',
  TIME_SERIES = 'time-series',
  FUNNEL = 'funnel',
  COHORT = 'cohort',
  GEO_MAP = 'geo-map',
  SANKEY = 'sankey',
  NETWORK = 'network',
  BAR = 'bar',
  COLUMN = 'column',
  STACKED_BAR = 'stacked-bar',
  SCATTER = 'scatter',
  HISTOGRAM = 'histogram',
  HEATMAP = 'heatmap',
  TREEMAP = 'treemap',
  BOX_PLOT = 'box-plot',
  GAUGE = 'gauge',
  WATERFALL = 'waterfall',
  KPI_CARD = 'kpi-card'
}

/**
 * Represents the inferred semantic layer of the dataset.
 * Used by the AI to generate relevant visualizations.
 */
export interface SemanticModel {
  entities: { name: string; description: string; likely_keys: string[]; example_fields: string[] }[];
  metrics: { name: string; definition: string; aggregation: string; grain: string; caveats?: string }[];
  dimensions: { name: string; type: string; examples: string[] }[];
  relationships: { from_entity: string; to_entity: string; join_keys: string[]; join_type: string; confidence: number }[];
  kpis: { name: string; metric: string; goal_direction: 'up' | 'down'; target: string; alert_threshold: string }[];
  glossary: { term: string; meaning: string; synonyms: string[] }[];
  quality_flags: { issue: string; impacted_fields: string[]; severity: 'low' | 'medium' | 'high'; suggested_fix: string }[];
  assumptions: { assumption: string; impact: string; confirm_by: string }[];
}

/**
 * Configuration for a single dashboard widget.
 * x, y, w, h are in Grid Units (not pixels).
 */
export interface WidgetConfig {
  id: string;
  type: VizType;
  title: string;
  metric?: string;             // The primary numeric value to plot
  dimension?: string;          // The primary grouping key (X-Axis)
  secondaryDimension?: string; // The secondary grouping key (Legend/Y-Axis)
  filter?: Record<string, any>;
  w: number; // Width in grid columns (1-12)
  h: number; // Height in grid rows
  x: number; // Column start (0-11)
  y: number; // Row start
}

export interface DashboardTemplate {
  id: string;
  name: string;
  category: string;
  archetype: 'Executive' | 'Ops' | 'Analyst';
  description: string;
  widgets: WidgetConfig[];
  difficulty: 'Novice' | 'Intermediate' | 'Pro';
}

export interface AnalysisResult {
  summary: string;
  drivers: string[];
  recommendations: string[];
  sentiment: 'positive' | 'negative' | 'neutral';
  marketContext?: string;
  sources?: { title: string; uri: string }[];
}

import React, { useState, useMemo, useRef } from 'react';
import { WidgetConfig, EditMode, VizType, GRID_SYSTEM } from '../types';
import { ChartRenderer } from './ChartRenderer';
import { Icons } from '../constants';

const DRILL_HIERARCHY = ['region', 'category', 'date'];

interface BreadcrumbsProps {
  path: string[];
  onNavigate: (index: number) => void;
}

const Breadcrumbs: React.FC<BreadcrumbsProps> = ({ path, onNavigate }) => (
  <div className="flex items-center gap-1 text-[10px] font-bold text-slate-500 uppercase tracking-widest mt-1.5 px-0.5">
    <button 
      onClick={() => onNavigate(-1)} 
      className={`px-2 py-0.5 rounded transition-all ${path.length === 0 ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-500/30' : 'hover:bg-white/10 hover:text-fuchsia-400'}`}
    >
      Global
    </button>
    {path.map((segment, idx) => (
      <React.Fragment key={idx}>
        <span className="text-slate-600 mx-0.5">/</span>
        <button 
          onClick={() => onNavigate(idx)} 
          className={`px-2 py-0.5 rounded transition-all ${idx === path.length - 1 ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-500/30' : 'hover:bg-white/10 hover:text-fuchsia-400'}`}
        >
          {segment}
        </button>
      </React.Fragment>
    ))}
  </div>
);

interface WidgetContainerProps {
  widget: WidgetConfig;
  mode: EditMode;
  data: any[];
  onAnalyze: (widget: WidgetConfig, currentData: any[]) => void;
  onResize?: (id: string, w: number, h: number) => void;
  onMove?: (id: string, x: number, y: number) => void;
  onUpdate?: (id: string, updates: Partial<WidgetConfig>) => void;
  occupiedCells?: Set<string>;
}

export const WidgetContainer: React.FC<WidgetContainerProps> = ({ widget, mode, data, onAnalyze, onResize, onMove, onUpdate }) => {
  const [drillPath, setDrillPath] = useState<string[]>([]);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isResizing, setIsResizing] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const [showSettings, setShowSettings] = useState(false);

  const currentLevelIndex = Math.min(drillPath.length, DRILL_HIERARCHY.length - 1);
  const currentLevel = DRILL_HIERARCHY[currentLevelIndex];
  const canDrill = drillPath.length < DRILL_HIERARCHY.length;

  // Extract available keys from data for settings dropdowns
  const dataKeys = useMemo(() => data.length > 0 ? Object.keys(data[0]) : [], [data]);

  // Filter data based on current drill-down path
  const filteredData = useMemo(() => {
    let result = data;
    drillPath.forEach((val, idx) => {
      const dim = DRILL_HIERARCHY[idx];
      result = result.filter(item => String(item[dim]) === val);
    });
    return result;
  }, [data, drillPath]);

  const handleDrill = (val: string) => {
    if (drillPath.length < DRILL_HIERARCHY.length) {
      setDrillPath([...drillPath, val]);
    }
  };

  const handleNavigate = (idx: number) => {
    setDrillPath(drillPath.slice(0, idx + 1));
  };

  const handleLevelUp = () => {
    setDrillPath(drillPath.slice(0, -1));
  };

  // --- Grid Math Helpers ---
  const calculateGridDelta = (deltaX: number, deltaY: number, parentWidth: number) => {
     // 12 columns, 11 gaps
     const totalGapWidth = (GRID_SYSTEM.COLS - 1) * GRID_SYSTEM.GAP_PX;
     const colWidth = (parentWidth - totalGapWidth) / GRID_SYSTEM.COLS;

     const stepX = colWidth + GRID_SYSTEM.GAP_PX;
     const stepY = GRID_SYSTEM.ROW_HEIGHT_PX + GRID_SYSTEM.GAP_PX;

     return {
       dCol: Math.round(deltaX / stepX),
       dRow: Math.round(deltaY / stepY)
     };
  };

  // --- Resize Handler ---
  const handleResizeStart = (e: React.MouseEvent) => {
    if (mode !== EditMode.PRO || !onResize) return;
    e.preventDefault();
    e.stopPropagation();
    setIsResizing(true);

    const startX = e.clientX;
    const startY = e.clientY;
    const startW = widget.w;
    const startH = widget.h;

    const parent = containerRef.current?.offsetParent as HTMLElement;
    if (!parent) return;

    const handleMouseMove = (moveEvent: MouseEvent) => {
      const { dCol, dRow } = calculateGridDelta(
        moveEvent.clientX - startX,
        moveEvent.clientY - startY,
        parent.clientWidth
      );

      // Constraint resizing to grid bounds and min size
      const newW = Math.max(2, Math.min(GRID_SYSTEM.COLS - widget.x, startW + dCol));
      const newH = Math.max(1, Math.min(12, startH + dRow));

      if (newW !== widget.w || newH !== widget.h) {
         onResize(widget.id, newW, newH);
      }
    };

    const handleMouseUp = () => {
      setIsResizing(false);
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };

    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  };

  // --- Drag Handler ---
  const handleDragStart = (e: React.MouseEvent) => {
    if (mode !== EditMode.PRO || !onMove) return;
    if ((e.target as HTMLElement).closest('button')) return;

    e.preventDefault();
    setIsDragging(true);

    const startX = e.clientX;
    const startY = e.clientY;
    const startGridX = widget.x;
    const startGridY = widget.y;

    const parent = containerRef.current?.offsetParent as HTMLElement;
    if (!parent) return;

    const handleMouseMove = (moveEvent: MouseEvent) => {
        const { dCol, dRow } = calculateGridDelta(
          moveEvent.clientX - startX,
          moveEvent.clientY - startY,
          parent.clientWidth
        );

        const newX = Math.max(0, Math.min(GRID_SYSTEM.COLS - widget.w, startGridX + dCol));
        const newY = Math.max(0, startGridY + dRow);

        if (newX !== widget.x || newY !== widget.y) {
           onMove(widget.id, newX, newY);
        }
    };

    const handleMouseUp = () => {
        setIsDragging(false);
        document.removeEventListener('mousemove', handleMouseMove);
        document.removeEventListener('mouseup', handleMouseUp);
    };

    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  };

  return (
    <div 
      ref={containerRef}
      className={`glass-panel rounded-3xl flex flex-col transition-all relative group/widget backdrop-blur-md 
        ${isResizing || isDragging ? 'z-50 border-fuchsia-500 shadow-2xl scale-[1.02]' : 'hover:border-fuchsia-500/30'}
        ${mode === EditMode.PRO ? 'cursor-grab active:cursor-grabbing' : ''}
      `}
      style={{ 
        gridColumn: `span ${widget.w}`, 
        gridRow: `span ${widget.h}`,
        ...(widget.x > 0 || widget.y > 0 ? {
            gridColumnStart: widget.x + 1,
            gridRowStart: widget.y + 1
        } : {}),
        userSelect: isResizing || isDragging ? 'none' : 'auto'
      }}
      onMouseDown={handleDragStart}
    >
      {/* Settings Overlay */}
      {showSettings && (
          <div className="absolute inset-0 bg-slate-900/95 z-40 p-6 flex flex-col gap-4 animate-in fade-in rounded-3xl" onMouseDown={(e) => e.stopPropagation()}>
              <div className="flex justify-between items-center border-b border-white/10 pb-4">
                  <span className="font-bold text-white uppercase tracking-wider">Configure Widget</span>
                  <button onClick={() => setShowSettings(false)} className="text-slate-400 hover:text-white"><Icons.Settings /></button>
              </div>

              <div className="space-y-4 overflow-y-auto custom-scrollbar">
                  <div>
                      <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Title</label>
                      <input 
                          type="text" 
                          value={widget.title} 
                          onChange={(e) => onUpdate?.(widget.id, { title: e.target.value })}
                          className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:border-fuchsia-500 outline-none"
                      />
                  </div>

                  <div>
                      <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Dimension (X-Axis)</label>
                      <select 
                          value={widget.dimension || ''} 
                          onChange={(e) => onUpdate?.(widget.id, { dimension: e.target.value })}
                          className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:border-fuchsia-500 outline-none"
                      >
                          <option value="">Auto</option>
                          {dataKeys.map(k => <option key={k} value={k}>{k}</option>)}
                      </select>
                  </div>

                  <div>
                      <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Secondary Dimension (Y-Axis)</label>
                      <select 
                          value={widget.secondaryDimension || ''} 
                          onChange={(e) => onUpdate?.(widget.id, { secondaryDimension: e.target.value })}
                          className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:border-fuchsia-500 outline-none"
                      >
                          <option value="">None</option>
                          {dataKeys.map(k => <option key={k} value={k}>{k}</option>)}
                      </select>
                  </div>

                  <div>
                      <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Metric (Value)</label>
                      <select 
                          value={widget.metric || ''} 
                          onChange={(e) => onUpdate?.(widget.id, { metric: e.target.value })}
                          className="w-full bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:border-fuchsia-500 outline-none"
                      >
                          <option value="">Auto</option>
                          {dataKeys.map(k => <option key={k} value={k}>{k}</option>)}
                      </select>
                  </div>
              </div>
          </div>
      )}

      {widget.type !== VizType.KPI_CARD && (
        <div className="px-6 py-4 border-b border-white/5 flex items-center justify-between bg-white/[0.02] rounded-t-3xl">
          <div className="flex flex-col">
            <span className="text-sm font-black text-white tracking-tight uppercase drop-shadow-sm">{widget.title}</span>
            <Breadcrumbs path={drillPath} onNavigate={handleNavigate} />
          </div>
          <div className="flex items-center gap-2">
            {mode === EditMode.PRO && (
                <button 
                    onClick={(e) => { e.stopPropagation(); setShowSettings(!showSettings); }}
                    className="p-1.5 hover:bg-white/10 rounded-lg text-slate-500 hover:text-white transition-colors"
                >
                    <Icons.Settings />
                </button>
            )}
            <button
               onClick={(e) => { e.stopPropagation(); onAnalyze(widget, filteredData); }}
               className="flex items-center gap-1.5 px-3 py-1.5 bg-white/5 border border-white/10 rounded-lg text-[10px] font-bold text-slate-400 uppercase tracking-wider hover:text-white hover:bg-white/10 hover:border-white/20 transition-all shadow-sm"
            >
              <Icons.Sparkles /> Analyze
            </button>
            {drillPath.length > 0 && (
              <button 
                onClick={(e) => { e.stopPropagation(); handleLevelUp(); }}
                className="p-1.5 hover:bg-white/10 rounded-lg text-slate-500 hover:text-white transition-colors"
                title="Go up one level"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 10l7-7m0 0l7 7m-7-7v18" />
                </svg>
              </button>
            )}
          </div>
        </div>
      )}

      {widget.type === VizType.KPI_CARD && (
         <div className="absolute top-4 right-4 opacity-0 group-hover/widget:opacity-100 transition-opacity z-20 flex gap-2">
            {mode === EditMode.PRO && (
                <button onClick={(e) => { e.stopPropagation(); setShowSettings(!showSettings); }} className="p-2 bg-slate-800 text-slate-300 rounded-full shadow-sm hover:scale-110 transition-transform">
                   <Icons.Settings />
                </button>
            )}
            <button onClick={(e) => { e.stopPropagation(); onAnalyze(widget, filteredData); }} className="p-2 bg-fuchsia-500/20 text-fuchsia-300 rounded-full shadow-sm hover:scale-110 transition-transform">
               <Icons.Sparkles />
            </button>
         </div>
      )}

      <div className="flex-1 p-6 relative overflow-hidden" onMouseDown={(e) => e.stopPropagation()}>
        <ChartRenderer 
          config={widget} 
          data={filteredData} 
          onDrill={handleDrill} 
          currentLevel={currentLevel}
          drillPath={drillPath}
          canDrill={canDrill}
        />
      </div>

      {/* Resize Handle */}
      {mode === EditMode.PRO && (
        <div 
          onMouseDown={handleResizeStart}
          className="absolute bottom-0 right-0 w-6 h-6 cursor-se-resize z-20 flex items-center justify-center opacity-0 group-hover/widget:opacity-100 transition-opacity"
        >
          <svg className="w-4 h-4 text-fuchsia-500 transform rotate-45" fill="none" viewBox="0 0 24 24" stroke="currentColor">
             <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 5v14m7-14v14" />
          </svg>
        </div>
      )}
    </div>
  );
};

import React, { useMemo } from 'react';
import { Icons } from '../constants';
import { VizType, WidgetConfig } from '../types';
import { VizArea } from './VizArea';
import { VizBar } from './VizBar';
import { VizKPI } from './VizKPI';
import { VizScatter } from './VizScatter';
import { VizHeatmap } from './VizHeatmap';
import { VizTreemap } from './VizTreemap';

interface ChartRendererProps {
  config: WidgetConfig;
  data: any[];
  onDrill: (value: string) => void;
  currentLevel: string;
  drillPath: string[];
  canDrill: boolean;
}

/**
 * Renders the appropriate visualization based on the widget configuration.
 * Handles data aggregation, transformation, and distribution to specific Viz components.
 */
export const ChartRenderer: React.FC<ChartRendererProps> = ({ config, data, onDrill, currentLevel, drillPath, canDrill }) => {

  // -- Standard Aggregation (Bar, Line, KPI) --
  // Aggregates data by the current drill level (Dimension) and sums the metric.
  const standardData = useMemo(() => {
    if ([VizType.SCATTER, VizType.HEATMAP, VizType.TREEMAP].includes(config.type)) return [];

    const metric = config.metric || 'sales';
    const agg: Record<string, any> = {};

    data.forEach(item => {
      const key = String(item[currentLevel] || 'Unknown');

      // Initialize the group if it doesn't exist
      if (!agg[key]) {
        agg[key] = { [currentLevel]: key };
        agg[key][metric] = 0;

        // Backward compatibility: ensure standard keys exist for legacy templates
        if (metric !== 'sales') agg[key]['sales'] = 0;
        if (metric !== 'users') agg[key]['users'] = 0;
      }

      // Safely accumulate the metric
      const val = Number(item[metric]);
      if (!isNaN(val)) {
        agg[key][metric] += val;
      }

      // Accumulate defaults if present in source data (legacy support)
      if (metric !== 'sales' && item.sales) agg[key]['sales'] += Number(item.sales) || 0;
      if (metric !== 'users' && item.users) agg[key]['users'] += Number(item.users) || 0;
    });

    // Sort by dimension key for consistent display
    return Object.values(agg).sort((a, b) => String(a[currentLevel]).localeCompare(String(b[currentLevel])));
  }, [data, currentLevel, config.type, config.metric]);

  // -- Scatter Data (Raw) --
  // Maps data directly for X/Y/Z plotting without aggregation
  const scatterData = useMemo(() => {
    if (config.type !== VizType.SCATTER) return [];
    return data.map(d => ({
        ...d,
        [config.dimension || 'sales']: Number(d[config.dimension || 'sales'] || 0),
        [config.secondaryDimension || 'users']: Number(d[config.secondaryDimension || 'users'] || 0),
        [config.metric || 'conversion']: Number(d[config.metric || 'conversion'] || 0),
    }));
  }, [data, config.type, config.dimension, config.secondaryDimension, config.metric]);

  // -- Heatmap Data (Pivoted) --
  // Aggregates data into a matrix form (X-Axis vs Y-Axis) with value Z
  const heatmapData = useMemo(() => {
    if (config.type !== VizType.HEATMAP) return [];
    const xKey = config.dimension || 'category';
    const yKey = config.secondaryDimension || 'region';
    const valKey = config.metric || 'sales';

    const agg: Record<string, any> = {};
    data.forEach(item => {
        const x = String(item[xKey] || 'N/A');
        const y = String(item[yKey] || 'N/A');
        const key = `${x}-${y}`;
        if(!agg[key]) agg[key] = { [xKey]: x, [yKey]: y, [valKey]: 0 };
        agg[key][valKey] += Number(item[valKey] || 0);
    });
    return Object.values(agg);
  }, [data, config.type, config.dimension, config.secondaryDimension, config.metric]);

  // -- Treemap Data (Hierarchical) --
  // Simple grouping by current level for size comparison
  const treemapData = useMemo(() => {
      if (config.type !== VizType.TREEMAP) return [];
      const valKey = config.metric || 'sales';

      const agg: Record<string, number> = {};
      data.forEach(item => {
          const key = String(item[currentLevel] || 'Unknown');
          agg[key] = (agg[key] || 0) + (Number(item[valKey]) || 0);
      });
      return Object.entries(agg).map(([name, size]) => ({ name, size }));
  }, [data, config.type, currentLevel, config.metric]);

  // Render Logic
  switch (config.type) {
    case VizType.TIME_SERIES:
      return <VizArea 
        data={standardData} 
        onDrill={onDrill} 
        currentLevel={currentLevel} 
        drillPath={drillPath} 
        canDrill={canDrill}
        metric={config.metric || 'sales'}
      />;

    case VizType.BAR:
      return <VizBar 
        data={standardData} 
        onDrill={onDrill} 
        currentLevel={currentLevel} 
        drillPath={drillPath} 
        canDrill={canDrill}
        metric={config.metric || 'sales'}
      />;

    case VizType.KPI_CARD:
      const metric = config.metric || 'sales';
      const total = standardData.reduce((acc, curr) => acc + (Number(curr[metric]) || 0), 0);
      // Format large numbers for KPI card
      const formattedTotal = new Intl.NumberFormat('en-US', { 
        notation: "compact", 
        compactDisplay: "short" 
      }).format(total);

      return <VizKPI title={config.title} value={formattedTotal} trend="--" isPositive={true} />;

    case VizType.SCATTER:
        return <VizScatter 
          data={scatterData} 
          xKey={config.dimension || 'sales'}
          yKey={config.secondaryDimension || 'users'}
          zKey={config.metric || 'conversion'}
        />;

    case VizType.HEATMAP:
        return <VizHeatmap 
          data={heatmapData} 
          xKey={config.dimension || 'category'} 
          yKey={config.secondaryDimension || 'region'} 
          valKey={config.metric || 'sales'} 
        />;

    case VizType.TREEMAP:
        return <VizTreemap data={treemapData} />;

    default:
      return (
        <div className="flex flex-col items-center justify-center h-full text-slate-600 gap-2">
          <Icons.Dashboard />
          <span className="text-xs font-semibold uppercase tracking-widest">{config.type} Placeholder</span>
        </div>
      );
  }
};

import React, { useState, useMemo, useEffect, useCallback, useRef } from 'react';
import { Icons } from './constants';
import { EditMode, WidgetConfig, AnalysisResult, GRID_SYSTEM } from './types';
import { inferSemanticModel } from './services/semanticEngine';
import { generateTemplates } from './services/templateService';
import { generateAnalysis } from './services/aiService';
import { WidgetContainer } from './components/WidgetContainer';
import { Sidebar } from './components/Sidebar';
import { MagicBar } from './components/MagicBar';
import { AnalysisPanel } from './components/AnalysisPanel';
import { useDataManager } from './hooks/useDataManager';

// Use global html2canvas and jspdf from import map
declare const html2canvas: any;
declare const jspdf: any;

// --- Main Application ---

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'catalog' | 'model' | 'trust'>('dashboard');
  const [mode, setMode] = useState<EditMode>(EditMode.SAFE);
  const [selectedTemplateId, setSelectedTemplateId] = useState('foh-sales-exec');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Mutable state for widgets to allow AI additions and persistence
  const [dashboardWidgets, setDashboardWidgets] = useState<WidgetConfig[]>([]);

  // Analysis Panel State
  const [isAnalysisOpen, setIsAnalysisOpen] = useState(false);
  const [analyzingWidget, setAnalyzingWidget] = useState<WidgetConfig | null>(null);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const dashboardRef = useRef<HTMLDivElement>(null);

  // Generate Templates (Memoized)
  const templates = useMemo(() => generateTemplates(), []);

  const currentTemplate = useMemo(() => 
    templates.find(t => t.id === selectedTemplateId) || templates[0], 
    [templates, selectedTemplateId]
  );

  // Load widgets from LocalStorage or fallback to template
  useEffect(() => {
    const savedLayout = localStorage.getItem(`omnigen_layout_${selectedTemplateId}`);
    if (savedLayout) {
      try {
        setDashboardWidgets(JSON.parse(savedLayout));
      } catch (e) {
        console.error("Failed to load saved layout", e);
        setDashboardWidgets(currentTemplate.widgets);
      }
    } else {
      setDashboardWidgets(currentTemplate.widgets);
    }
  }, [currentTemplate, selectedTemplateId]);

  // Save widgets to LocalStorage whenever they change
  useEffect(() => {
    if (dashboardWidgets.length > 0) {
      localStorage.setItem(`omnigen_layout_${selectedTemplateId}`, JSON.stringify(dashboardWidgets));
    }
  }, [dashboardWidgets, selectedTemplateId]);

  // Data Logic Hook
  const { 
    data, 
    isStreaming, 
    setIsStreaming, 
    handleFileUpload, 
    exportStandalone 
  } = useDataManager(currentTemplate.name);

  const semanticModel = useMemo(() => inferSemanticModel(data), [data]);

  const handleWidgetGenerated = (newWidget: WidgetConfig) => {
    setDashboardWidgets(prev => {
      // Find first available spot using GRID_SYSTEM constants
      let placed = false;
      let y = 0;
      // Search up to 20 rows down for a spot
      while (!placed && y < 20) {
        for (let x = 0; x <= GRID_SYSTEM.COLS - newWidget.w; x++) {
           const collision = prev.some(w => 
             x < w.x + w.w && x + newWidget.w > w.x &&
             y < w.y + w.h && y + newWidget.h > w.y
           );
           if (!collision) {
             newWidget.x = x;
             newWidget.y = y;
             placed = true;
             break;
           }
        }
        y++;
      }
      return [...prev, newWidget];
    });
  };

  const handleWidgetResize = useCallback((id: string, newW: number, newH: number) => {
    setDashboardWidgets(prev => {
        const widget = prev.find(w => w.id === id);
        if (!widget) return prev;

        // Collision Check for Resize
        const collision = prev.some(w => 
            w.id !== id &&
            widget.x < w.x + w.w && widget.x + newW > w.x &&
            widget.y < w.y + w.h && widget.y + newH > w.y
        );

        if (collision) return prev; // Block resize if it hits another widget

        return prev.map(w => w.id === id ? { ...w, w: newW, h: newH } : w);
    });
  }, []);

  const handleWidgetMove = useCallback((id: string, newX: number, newY: number) => {
    setDashboardWidgets(prev => {
        const widget = prev.find(w => w.id === id);
        if (!widget) return prev;

        // Collision Check for Move
        const hasCollision = prev.some(w => {
            if (w.id === id) return false;
            // Intersection test (AABB)
            return newX < w.x + w.w &&
                   newX + widget.w > w.x &&
                   newY < w.y + w.h &&
                   newY + widget.h > w.y;
        });

        if (hasCollision) return prev; // Block move

        return prev.map(w => w.id === id ? { ...w, x: newX, y: newY } : w);
    });
  }, []);

  const handleWidgetUpdate = useCallback((id: string, updates: Partial<WidgetConfig>) => {
    setDashboardWidgets(prev => prev.map(w => w.id === id ? { ...w, ...updates } : w));
  }, []);

  const handleAnalyze = async (widget: WidgetConfig, currentData: any[]) => {
    setAnalyzingWidget(widget);
    setIsAnalysisOpen(true);
    setAnalysisResult(null);
    setIsAnalyzing(true);

    // Call AI Service
    const result = await generateAnalysis(widget.title, currentData);

    setAnalysisResult(result);
    setIsAnalyzing(false);
  };

  const handleExportPDF = async () => {
    if (!dashboardRef.current) return;
    try {
        const canvas = await html2canvas(dashboardRef.current, { scale: 2, backgroundColor: '#020617' });
        const imgData = canvas.toDataURL('image/png');
        // A4 Landscape roughly
        const pdf = new jspdf.jsPDF({ orientation: 'landscape', unit: 'px', format: [canvas.width, canvas.height] });
        pdf.addImage(imgData, 'PNG', 0, 0, canvas.width, canvas.height);
        pdf.save('dashboard.pdf');
    } catch (e) {
        console.error("PDF Export failed", e);
    }
  };

  const handleExportImage = async () => {
      if (!dashboardRef.current) return;
      try {
          const canvas = await html2canvas(dashboardRef.current, { scale: 2, backgroundColor: '#020617' });
          const link = document.createElement('a');
          link.download = 'dashboard.png';
          link.href = canvas.toDataURL();
          link.click();
      } catch (e) {
          console.error("Image Export failed", e);
      }
  };

  return (
    <div className="flex h-screen overflow-hidden text-slate-200">
      <Sidebar 
        activeTab={activeTab}
        setActiveTab={setActiveTab}
        isSidebarOpen={isSidebarOpen}
        onImport={handleFileUpload}
        onExport={exportStandalone}
      />

      <main className="flex-1 flex flex-col overflow-hidden relative">
        {/* Header */}
        <header className="h-20 border-b border-white/10 px-10 flex items-center justify-between shrink-0 glass-panel">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-colors">
               <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16m-7 6h7" /></svg>
            </button>
            <div>
              <h2 className="text-xl font-black text-white uppercase tracking-tight drop-shadow-lg">{activeTab === 'dashboard' ? currentTemplate.name : activeTab}</h2>
              <div className="flex gap-2 mt-1">
                <span className="text-[10px] font-black text-fuchsia-400 uppercase tracking-widest">{currentTemplate.category}</span>
                <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">• {currentTemplate.archetype}</span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-4">
             {/* Export Dropdown */}
            <div className="relative group">
                <button className="p-2 hover:bg-white/10 rounded-lg transition-colors text-slate-400 hover:text-white">
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                    </svg>
                </button>
                <div className="absolute right-0 top-full mt-2 w-40 glass-panel rounded-xl shadow-xl overflow-hidden hidden group-hover:block z-50">
                    <button onClick={handleExportImage} className="w-full text-left px-4 py-2 text-xs font-bold text-slate-300 hover:bg-white/10 hover:text-white">Save as PNG</button>
                    <button onClick={handleExportPDF} className="w-full text-left px-4 py-2 text-xs font-bold text-slate-300 hover:bg-white/10 hover:text-white">Save as PDF</button>
                </div>
            </div>

            <button 
              onClick={() => setIsStreaming(!isStreaming)} 
              className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${isStreaming ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/30' : 'bg-white/5 text-slate-400 border border-white/10'}`}
            >
              {isStreaming ? "● Simulation" : "Offline"}
            </button>

            <div className="flex items-center bg-black/20 rounded-2xl p-1.5 border border-white/10">
              <button 
                onClick={() => setMode(EditMode.SAFE)} 
                className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${mode === EditMode.SAFE ? 'bg-white/10 text-white shadow-sm border border-white/10' : 'text-slate-500 hover:text-slate-300'}`}
              >
                Safe
              </button>
              <button 
                onClick={() => setMode(EditMode.PRO)} 
                className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${mode === EditMode.PRO ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-500/30' : 'text-slate-500 hover:text-slate-300'}`}
              >
                Pro
              </button>
            </div>
          </div>
        </header>

        {/* View Content */}
        <div className="flex-1 overflow-y-auto p-10 custom-scrollbar relative">

          {activeTab === 'dashboard' && (
            <>
              <div 
                ref={dashboardRef} 
                className="grid max-w-screen-2xl mx-auto pb-32 relative transition-all"
                style={{
                  gridTemplateColumns: `repeat(${GRID_SYSTEM.COLS}, minmax(0, 1fr))`,
                  gap: `${GRID_SYSTEM.GAP_PX}px`,
                  gridAutoRows: `${GRID_SYSTEM.ROW_HEIGHT_PX}px`
                }}
              >
                {dashboardWidgets.map(w => (
                  <WidgetContainer 
                    key={w.id} 
                    widget={w} 
                    mode={mode} 
                    data={data} 
                    onAnalyze={handleAnalyze}
                    onResize={handleWidgetResize}
                    onMove={handleWidgetMove}
                    onUpdate={handleWidgetUpdate}
                  />
                ))}
              </div>
              <MagicBar onWidgetGenerated={handleWidgetGenerated} semanticModel={semanticModel} />
            </>
          )}

          {activeTab === 'catalog' && (
            <div className="max-w-screen-xl mx-auto space-y-8 pb-20">
              <h3 className="text-4xl font-black uppercase tracking-tighter text-white drop-shadow-md">Blueprint Catalog</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {templates.map(t => (
                  <div key={t.id} onClick={() => { setSelectedTemplateId(t.id); setActiveTab('dashboard'); }} className="glass-panel p-8 rounded-[2rem] hover:shadow-2xl hover:shadow-purple-500/10 transition-all cursor-pointer group hover:-translate-y-1 hover:border-purple-500/30">
                    <span className="text-[10px] font-black text-fuchsia-400 uppercase tracking-widest">{t.category}</span>
                    <h4 className="text-2xl font-black mt-2 leading-tight text-white group-hover:text-fuchsia-300 transition-colors">{t.name}</h4>
                    <p className="text-slate-400 text-sm font-medium mt-4 leading-relaxed">{t.description}</p>
                    <div className="mt-6 flex gap-2">
                       <span className="px-3 py-1 bg-white/5 rounded-full text-[9px] font-black uppercase border border-white/10 text-slate-300">{t.difficulty}</span>
                       <span className="px-3 py-1 bg-white/5 rounded-full text-[9px] font-black uppercase border border-white/10 text-slate-300">{t.archetype}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'model' && (
            <div className="max-w-4xl mx-auto glass-panel rounded-[3rem] p-16 shadow-2xl mb-20 relative overflow-hidden">
               <div className="absolute top-0 right-0 p-32 bg-purple-600/20 blur-[100px] rounded-full"></div>
              <h3 className="text-4xl font-black uppercase tracking-tighter mb-12 text-white relative z-10">Semantic Layer V1.0</h3>
