import { GoogleGenAI, Type } from "@google/genai";
import { VizType, WidgetConfig, SemanticModel, AnalysisResult } from '../types';

// Fallback heuristic logic for when API key is missing or offline
const heuristicParse = (prompt: string): WidgetConfig => {
  const lower = prompt.toLowerCase();
  const id = `ai-${Date.now()}`;

  let type = VizType.KPI_CARD;
  let w = 3;
  let h = 1;

  if (lower.includes('scatter') || lower.includes('correlation') || lower.includes('relationship')) {
    type = VizType.SCATTER;
    w = 6;
    h = 4;
  } else if (lower.includes('heat') || lower.includes('matrix') || lower.includes('density')) {
    type = VizType.HEATMAP;
    w = 6;
    h = 4;
  } else if (lower.includes('tree') || lower.includes('hierarchy') || lower.includes('composition')) {
    type = VizType.TREEMAP;
    w = 8;
    h = 4;
  } else if (lower.includes('flow') || lower.includes('journey') || lower.includes('sankey')) {
    type = VizType.SANKEY;
    w = 12;
    h = 4;
  } else if (lower.includes('trend') || lower.includes('growth') || lower.includes('over time')) {
    type = VizType.TIME_SERIES;
    w = 6;
    h = 3;
  } else if (lower.includes('breakdown') || lower.includes('compare') || lower.includes('vs') || lower.includes('distribution')) {
    type = VizType.BAR;
    w = 6;
    h = 3;
  } else if (lower.includes('map') || lower.includes('geo')) {
    type = VizType.GEO_MAP;
    w = 6;
    h = 4;
  } else if (lower.includes('funnel') || lower.includes('conversion') || lower.includes('pipeline')) {
      type = VizType.FUNNEL;
      w = 6;
      h = 3;
  }

  const title = prompt.length > 5 ? prompt.split(' ').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(' ') : 'AI Insight';

  return {
    id,
    type,
    title,
    x: 0,
    y: 0,
    w,
    h,
  };
};

/**
 * Smartly samples and aggregates data for AI analysis to avoid token limit exhaustion.
 * @param data - Raw dataset
 * @returns Aggregated subset of data
 */
const smartSampleData = (data: any[]): any[] => {
  if (data.length <= 50) return data;

  // Identify schema
  const sample = data[0];
  const numericKeys = Object.keys(sample).filter(k => typeof sample[k] === 'number');
  const stringKeys = Object.keys(sample).filter(k => typeof sample[k] === 'string');
  const groupKey = stringKeys.find(k => k.toLowerCase().includes('date') || k.toLowerCase().includes('category') || k.toLowerCase().includes('region')) || stringKeys[0] || 'id';

  // Aggregate
  const grouped: Record<string, any> = {};
  data.forEach(row => {
    const key = row[groupKey];
    if (!grouped[key]) {
      grouped[key] = { ...row };
      numericKeys.forEach(nk => grouped[key][nk] = 0);
    }
    numericKeys.forEach(nk => grouped[key][nk] += (row[nk] || 0));
  });

  let result = Object.values(grouped);

  // If still too large, sort by significant metric and take top 30
  if (result.length > 30 && numericKeys.length > 0) {
      // Pick first metric to sort by
      const sortKey = numericKeys[0];
      result.sort((a, b) => b[sortKey] - a[sortKey]);
      result = result.slice(0, 30);
  }

  return result.slice(0, 30);
};

/**
 * Translates a natural language query into a Widget Configuration.
 * Uses Gemini Flash for low-latency instruction following.
 */
export const parsePrompt = async (prompt: string, semanticModel?: SemanticModel): Promise<WidgetConfig> => {
  // 1. Check for API Key availability
  if (!process.env.API_KEY) {
    console.warn("[OmniGen] No API_KEY found. Using heuristic fallback.");
    return new Promise((resolve) => {
      setTimeout(() => resolve(heuristicParse(prompt)), 800);
    });
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const availableMetrics = semanticModel?.metrics.map(m => m.name).join(', ') || 'Sales, Users, Conversion';
    const availableDimensions = semanticModel?.dimensions.map(d => d.name).join(', ') || 'Date, Region, Category';

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `
        You are an expert data visualization architect.
        User Request: "${prompt}"

        Available Data Fields:
        - Metrics: ${availableMetrics}
        - Dimensions: ${availableDimensions}

        Task: Generate a JSON configuration for a dashboard widget that best visualizes this request.

        Rules:
        - Select the most appropriate 'type' from: ${Object.values(VizType).join(', ')}.
        - Use 'scatter' for correlations, 'heatmap' for density/matrix, 'treemap' for hierarchical composition.
        - 'w' (width) should be between 3 and 12. 
        - 'h' (height) should be between 1 and 4.
        - KPI cards should be small (3x1). Complex charts should be larger (6x3 or 6x4).
        - 'id' should be unique (use a random string suffix).
        - 'x' and 'y' should be 0 (the grid layout handles placement).
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            type: { 
              type: Type.STRING, 
              enum: Object.values(VizType) 
            },
            title: { type: Type.STRING },
            w: { type: Type.INTEGER },
            h: { type: Type.INTEGER },
            x: { type: Type.INTEGER },
            y: { type: Type.INTEGER }
          },
          required: ["id", "type", "title", "w", "h", "x", "y"]
        }
      }
    });

    const text = response.text;
    if (text) {
      const config = JSON.parse(text) as WidgetConfig;
      config.id = config.id || `gen-${Date.now()}`;
      return config;
    }

    throw new Error("Empty response from AI");

  } catch (error) {
    console.error("[OmniGen] AI Generation failed, falling back to heuristics:", error);
    return heuristicParse(prompt);
  }
};

/**
 * Generates an executive analysis of a specific widget's data.
 * Uses Gemini Flash for analysis and Search Grounding for market context.
 */
export const generateAnalysis = async (title: string, data: any[]): Promise<AnalysisResult> => {
  // Fallback for demo/offline
  if (!process.env.API_KEY) {
    return new Promise((resolve) => {
      setTimeout(() => resolve({
        summary: `Analysis of ${title} indicates a stable trend with minor fluctuations. The data suggests consistent performance across the selected timeframe.`,
        drivers: ["Consistent user engagement", "Seasonal baseline effects"],
        recommendations: ["Monitor for upcoming seasonal spikes", "Investigate lower performing segments"],
        sentiment: "neutral",
        marketContext: "Similar industries typically see a 5-10% variance in this period due to macroeconomic factors.",
        sources: [
            { title: "Global Industry Report 2024", uri: "#" },
            { title: "Market Trends Daily", uri: "#" }
        ]
      }), 1500);
    });
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Aggregation Logic for large datasets
    const aggregatedData = smartSampleData(data);
    const dataSample = JSON.stringify(aggregatedData);

    // Parallel execution: Internal Analysis (JSON) + External Context (Search)
    const [internalResponse, externalResponse] = await Promise.all([
        ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `
              Role: Senior Business Analyst.
              Task: Analyze the following dataset for a chart titled "${title}".
              Data (Aggregated Sample): ${dataSample}

              Provide:
              1. An executive summary (max 2 sentences).
              2. Key drivers/factors (max 3 bullet points).
              3. Strategic recommendations (max 2).
              4. Overall sentiment.
            `,
            config: {
              responseMimeType: "application/json",
              responseSchema: {
                type: Type.OBJECT,
                properties: {
                  summary: { type: Type.STRING },
                  drivers: { type: Type.ARRAY, items: { type: Type.STRING } },
                  recommendations: { type: Type.ARRAY, items: { type: Type.STRING } },
                  sentiment: { type: Type.STRING, enum: ["positive", "negative", "neutral"] }
                }
              }
            }
        }),
        ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Briefly summarize the latest market trends, industry benchmarks, or news related to the business topic: "${title}". Focus on high-level business implications. Keep it under 50 words.`,
            config: {
                tools: [{googleSearch: {}}]
            }
        })
    ]);

    const result = JSON.parse(internalResponse.text!) as AnalysisResult;

    // Attach External Context
    if (externalResponse.text) {
        result.marketContext = externalResponse.text;
    }

    // Attach Grounding Sources
    const chunks = externalResponse.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) {
        result.sources = chunks
            .map((c: any) => c.web ? { title: c.web.title, uri: c.web.uri } : null)
            .filter((c: any) => c !== null);
    }

    return result;

  } catch (error) {
    console.error("Analysis failed", error);
    return {
       summary: "Could not generate analysis at this time.",
       drivers: [],
       recommendations: [],
       sentiment: "neutral"
    };
  }
};

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Icons } from '../constants';
import { parsePrompt } from '../services/aiService';
import { WidgetConfig, SemanticModel, VizType } from '../types';

interface MagicBarProps {
  onWidgetGenerated: (widget: WidgetConfig) => void;
  semanticModel?: SemanticModel;
}

/**
 * A natural language command interface for generating dashboard widgets.
 * Features:
 * - Autocomplete suggestions based on available metrics/dimensions.
 * - AI-powered prompt parsing to infer visualization type and configuration.
 */
export const MagicBar: React.FC<MagicBarProps> = ({ onWidgetGenerated, semanticModel }) => {
  const [query, setQuery] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setIsGenerating(true);
    setShowSuggestions(false);
    try {
      const widget = await parsePrompt(query, semanticModel);
      onWidgetGenerated(widget);
      setQuery('');
    } catch (error) {
      console.error("AI Generation failed", error);
    } finally {
      setIsGenerating(false);
    }
  };

  // Intelligent Suggestions based on Semantic Model
  const suggestions = useMemo(() => {
    if (!query.trim()) return [];
    const lower = query.toLowerCase();
    const list: { label: string; action: string; type: string }[] = [];

    // 1. Check Visualization Types
    Object.values(VizType).forEach(t => {
      if (t.toLowerCase().includes(lower)) {
        list.push({ label: `Create ${t}`, action: `Create a ${t} showing `, type: 'Chart' });
      }
    });

    if (semanticModel) {
      // 2. Check Metrics
      semanticModel.metrics.forEach(m => {
        if (m.name.toLowerCase().includes(lower)) {
          list.push({ label: `Trend: ${m.name}`, action: `Show trend of ${m.name} over time`, type: 'Metric' });
          list.push({ label: `Breakdown: ${m.name}`, action: `Show ${m.name} broken down by `, type: 'Metric' });
        }
      });

      // 3. Check Dimensions
      semanticModel.dimensions.forEach(d => {
        if (d.name.toLowerCase().includes(lower)) {
          list.push({ label: `Group by ${d.name}`, action: `Show sales grouped by ${d.name}`, type: 'Dimension' });
        }
      });

      // 4. Check Entities
       semanticModel.entities.forEach(e => {
        if (e.name.toLowerCase().includes(lower)) {
          list.push({ label: `Analyze ${e.name}`, action: `Analyze ${e.name} performance`, type: 'Entity' });
        }
      });
    }

    return list.slice(0, 6);
  }, [query, semanticModel]);

  return (
    <div className="fixed bottom-8 left-1/2 transform -translate-x-1/2 w-full max-w-2xl px-4 z-50">
      <form onSubmit={handleSubmit} className="relative group">
        <div className={`absolute -inset-0.5 bg-gradient-to-r from-fuchsia-600 to-purple-600 rounded-full opacity-75 blur transition duration-500 ${isGenerating ? 'animate-pulse' : 'group-hover:opacity-100'}`}></div>
        <div className="relative flex items-center bg-slate-900/90 backdrop-blur-xl rounded-full p-2 pl-4 shadow-2xl border border-white/20">
          <div className={`text-fuchsia-400 mr-3 ${isGenerating ? 'animate-spin' : ''}`}>
             <Icons.Sparkles />
          </div>
          <input 
            ref={inputRef}
            type="text" 
            value={query}
            onChange={(e) => {
                setQuery(e.target.value);
                setShowSuggestions(true);
            }}
            onFocus={() => setShowSuggestions(true)}
            onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
            placeholder={isGenerating ? "Designing your widget..." : "Ask OmniGen... (e.g. 'Trend of sales over time')"}
            className="flex-1 bg-transparent border-none outline-none text-slate-100 placeholder-slate-500 font-medium text-sm"
            disabled={isGenerating}
          />
          <button 
            type="submit"
            disabled={!query.trim() || isGenerating}
            className={`p-2 rounded-full transition-all duration-300 ${query.trim() ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-500/50 scale-100' : 'bg-slate-800 text-slate-600 scale-90'}`}
          >
            <svg className="w-5 h-5 transform rotate-90" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
            </svg>
          </button>
        </div>

        {/* Search Suggestions Dropdown */}
        {showSuggestions && query.length > 0 && suggestions.length > 0 && (
           <div className="absolute bottom-full left-6 right-6 mb-2 bg-slate-900/95 backdrop-blur-xl border border-white/10 rounded-2xl shadow-xl overflow-hidden animate-in slide-in-from-bottom-2">
              <div className="p-2">
                 <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest px-3 py-2">Suggested Actions</div>
                 {suggestions.map((s, idx) => (
                    <button
                       key={idx}
                       type="button"
                       onClick={() => {
                           setQuery(s.action);
                           inputRef.current?.focus();
                       }}
                       className="w-full text-left px-3 py-2.5 text-sm text-slate-300 hover:bg-white/10 hover:text-white rounded-lg transition-colors flex items-center justify-between group/item"
                    >
                       <span className="font-medium">{s.label}</span>
                       <span className={`text-[9px] font-black uppercase tracking-wider px-2 py-0.5 rounded-full border opacity-50 group-hover/item:opacity-100 transition-opacity
                         ${s.type === 'Chart' ? 'bg-purple-500/10 border-purple-500/20 text-purple-400' : 
                           s.type === 'Metric' ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400' : 
                           'bg-blue-500/10 border-blue-500/20 text-blue-400'}`}
                       >
                         {s.type}
                       </span>
                    </button>
                 ))}
              </div>
           </div>
        )}
      </form>

      {/* Default Prompt Pills */}
      {!query && !isGenerating && (
         <div className="absolute -top-12 left-1/2 transform -translate-x-1/2 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity duration-300 delay-150 pointer-events-none">
            <div className="px-3 py-1.5 bg-slate-900/90 backdrop-blur rounded-xl text-[10px] font-bold text-slate-400 shadow-lg border border-white/10">"Show Sales Trend"</div>
            <div className="px-3 py-1.5 bg-slate-900/90 backdrop-blur rounded-xl text-[10px] font-bold text-slate-400 shadow-lg border border-white/10">"Regional Breakdown"</div>
         </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect, useCallback, useRef } from 'react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';
import { Icons } from './constants';
import { EditMode, WidgetConfig, AnalysisResult, GRID_SYSTEM } from './types';
import { inferSemanticModel } from './services/semanticEngine';
import { generateTemplates } from './services/templateService';
import { generateAnalysis } from './services/aiService';
import { WidgetContainer } from './components/WidgetContainer';
import { Sidebar } from './components/Sidebar';
import { MagicBar } from './components/MagicBar';
import { AnalysisPanel } from './components/AnalysisPanel';
import { useDataManager } from './hooks/useDataManager';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'catalog' | 'model' | 'trust'>('dashboard');
  const [mode, setMode] = useState<EditMode>(EditMode.SAFE);
  const [selectedTemplateId, setSelectedTemplateId] = useState('foh-sales-exec');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const [dashboardWidgets, setDashboardWidgets] = useState<WidgetConfig[]>([]);

  const [isAnalysisOpen, setIsAnalysisOpen] = useState(false);
  const [analyzingWidget, setAnalyzingWidget] = useState<WidgetConfig | null>(null);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const dashboardRef = useRef<HTMLDivElement>(null);

  const templates = useMemo(() => generateTemplates(), []);

  const currentTemplate = useMemo(() => 
    templates.find(t => t.id === selectedTemplateId) || templates[0], 
    [templates, selectedTemplateId]
  );

  useEffect(() => {
    const savedLayout = localStorage.getItem(`omnigen_layout_${selectedTemplateId}`);
    if (savedLayout) {
      try {
        setDashboardWidgets(JSON.parse(savedLayout));
      } catch (e) {
        console.error("Failed to load saved layout", e);
        setDashboardWidgets(currentTemplate.widgets);
      }
    } else {
      setDashboardWidgets(currentTemplate.widgets);
    }
  }, [currentTemplate, selectedTemplateId]);

  useEffect(() => {
    if (dashboardWidgets.length > 0) {
      localStorage.setItem(`omnigen_layout_${selectedTemplateId}`, JSON.stringify(dashboardWidgets));
    }
  }, [dashboardWidgets, selectedTemplateId]);

  const { 
    data, 
    isStreaming, 
    setIsStreaming, 
    handleFileUpload, 
    exportStandalone 
  } = useDataManager(currentTemplate.name);

  const semanticModel = useMemo(() => inferSemanticModel(data), [data]);

  const handleWidgetGenerated = (newWidget: WidgetConfig) => {
    setDashboardWidgets(prev => {
      let placed = false;
      let y = 0;
      while (!placed && y < 50) {
        for (let x = 0; x <= GRID_SYSTEM.COLS - newWidget.w; x++) {
           const collision = prev.some(w => 
             x < w.x + w.w && x + newWidget.w > w.x &&
             y < w.y + w.h && y + newWidget.h > w.y
           );
           if (!collision) {
             newWidget.x = x;
             newWidget.y = y;
             placed = true;
             break;
           }
        }
        y++;
      }
      return [...prev, newWidget];
    });
  };

  const handleWidgetResize = useCallback((id: string, newW: number, newH: number) => {
    setDashboardWidgets(prev => {
        const widget = prev.find(w => w.id === id);
        if (!widget) return prev;

        const collision = prev.some(w => 
            w.id !== id &&
            widget.x < w.x + w.w && widget.x + newW > w.x &&
            widget.y < w.y + w.h && widget.y + newH > w.y
        );

        if (collision) return prev; 
        return prev.map(w => w.id === id ? { ...w, w: newW, h: newH } : w);
    });
  }, []);

  const handleWidgetMove = useCallback((id: string, newX: number, newY: number) => {
    setDashboardWidgets(prev => {
        const widget = prev.find(w => w.id === id);
        if (!widget) return prev;

        const hasCollision = prev.some(w => {
            if (w.id === id) return false;
            return newX < w.x + w.w &&
                   newX + widget.w > w.x &&
                   newY < w.y + w.h &&
                   newY + widget.h > w.y;
        });

        if (hasCollision) return prev; 

        return prev.map(w => w.id === id ? { ...w, x: newX, y: newY } : w);
    });
  }, []);

  const handleWidgetUpdate = useCallback((id: string, updates: Partial<WidgetConfig>) => {
    setDashboardWidgets(prev => prev.map(w => w.id === id ? { ...w, ...updates } : w));
  }, []);

  const handleAnalyze = async (widget: WidgetConfig, currentData: any[]) => {
    setAnalyzingWidget(widget);
    setIsAnalysisOpen(true);
    setAnalysisResult(null);
    setIsAnalyzing(true);
    const result = await generateAnalysis(widget.title, currentData);
    setAnalysisResult(result);
    setIsAnalyzing(false);
  };

  const handleExportPDF = async () => {
    if (!dashboardRef.current) return;
    try {
        const canvas = await html2canvas(dashboardRef.current, { scale: 2, backgroundColor: '#020617' });
        const imgData = canvas.toDataURL('image/png');
        const pdf = new jsPDF({ orientation: 'landscape', unit: 'px', format: [canvas.width, canvas.height] });
        pdf.addImage(imgData, 'PNG', 0, 0, canvas.width, canvas.height);
        pdf.save(`${currentTemplate.name}_Dashboard.pdf`);
    } catch (e) {
        console.error("PDF Export failed", e);
    }
  };

  const handleExportImage = async () => {
      if (!dashboardRef.current) return;
      try {
          const canvas = await html2canvas(dashboardRef.current, { scale: 2, backgroundColor: '#020617' });
          const link = document.createElement('a');
          link.download = `${currentTemplate.name}_Dashboard.png`;
          link.href = canvas.toDataURL();
          link.click();
      } catch (e) {
          console.error("Image Export failed", e);
      }
  };

  return (
    <div className="flex h-screen overflow-hidden text-slate-200">
      <Sidebar 
        activeTab={activeTab}
        setActiveTab={setActiveTab}
        isSidebarOpen={isSidebarOpen}
        onImport={handleFileUpload}
        onExport={exportStandalone}
      />

      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-20 border-b border-white/10 px-10 flex items-center justify-between shrink-0 glass-panel z-30">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-colors">
               <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16m-7 6h7" /></svg>
            </button>
            <div>
              <h2 className="text-xl font-black text-white uppercase tracking-tight drop-shadow-lg">{activeTab === 'dashboard' ? currentTemplate.name : activeTab}</h2>
              <div className="flex gap-2 mt-1">
                <span className="text-[10px] font-black text-fuchsia-400 uppercase tracking-widest">{currentTemplate.category}</span>
                <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">• {currentTemplate.archetype}</span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <div className="relative group">
                <button className="p-2 hover:bg-white/10 rounded-lg transition-colors text-slate-400 hover:text-white flex items-center gap-2">
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                    </svg>
                    <span className="text-[10px] font-black uppercase tracking-widest hidden lg:inline">Export</span>
                </button>
                <div className="absolute right-0 top-full mt-2 w-48 glass-panel rounded-2xl shadow-2xl overflow-hidden hidden group-hover:block z-50 animate-in fade-in slide-in-from-top-2 duration-200">
                    <button onClick={handleExportImage} className="w-full text-left px-5 py-3 text-xs font-bold text-slate-300 hover:bg-white/10 hover:text-white border-b border-white/5">Save as PNG Image</button>
                    <button onClick={handleExportPDF} className="w-full text-left px-5 py-3 text-xs font-bold text-slate-300 hover:bg-white/10 hover:text-white">Save as PDF Document</button>
                </div>
            </div>

            <button 
              onClick={() => setIsStreaming(!isStreaming)} 
              className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${isStreaming ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/30' : 'bg-white/5 text-slate-400 border border-white/10'}`}
            >
              {isStreaming ? "● Simulation" : "Offline"}
            </button>

            <div className="flex items-center bg-black/20 rounded-2xl p-1.5 border border-white/10">
              <button 
                onClick={() => setMode(EditMode.SAFE)} 
                className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${mode === EditMode.SAFE ? 'bg-white/10 text-white shadow-sm border border-white/10' : 'text-slate-500 hover:text-slate-300'}`}
              >
                Safe
              </button>
              <button 
                onClick={() => setMode(EditMode.PRO)} 
                className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${mode === EditMode.PRO ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-500/30' : 'text-slate-500 hover:text-slate-300'}`}
              >
                Pro
              </button>
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10 custom-scrollbar relative">
          {activeTab === 'dashboard' && (
            <>
              <div 
                ref={dashboardRef} 
                className="grid max-w-screen-2xl mx-auto pb-48 relative transition-all"
                style={{
                  gridTemplateColumns: `repeat(${GRID_SYSTEM.COLS}, minmax(0, 1fr))`,
                  gap: `${GRID_SYSTEM.GAP_PX}px`,
                  gridAutoRows: `${GRID_SYSTEM.ROW_HEIGHT_PX}px`
                }}
              >
                {dashboardWidgets.map(w => (
                  <WidgetContainer 
                    key={w.id} 
                    widget={w} 
                    mode={mode} 
                    data={data} 
                    onAnalyze={handleAnalyze}
                    onResize={handleWidgetResize}
                    onMove={handleWidgetMove}
                    onUpdate={handleWidgetUpdate}
                  />
                ))}
              </div>
              <MagicBar onWidgetGenerated={handleWidgetGenerated} semanticModel={semanticModel} />
            </>
          )}

          {activeTab === 'catalog' && (
            <div className="max-w-screen-xl mx-auto space-y-8 pb-20">
              <h3 className="text-4xl font-black uppercase tracking-tighter text-white drop-shadow-md">Blueprint Catalog</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {templates.map(t => (
                  <div key={t.id} onClick={() => { setSelectedTemplateId(t.id); setActiveTab('dashboard'); }} className="glass-panel p-8 rounded-[2rem] hover:shadow-2xl hover:shadow-purple-500/10 transition-all cursor-pointer group hover:-translate-y-1 hover:border-purple-500/30">
                    <span className="text-[10px] font-black text-fuchsia-400 uppercase tracking-widest">{t.category}</span>
                    <h4 className="text-2xl font-black mt-2 leading-tight text-white group-hover:text-fuchsia-300 transition-colors">{t.name}</h4>
                    <p className="text-slate-400 text-sm font-medium mt-4 leading-relaxed">{t.description}</p>
                    <div className="mt-6 flex gap-2">
                       <span className="px-3 py-1 bg-white/5 rounded-full text-[9px] font-black uppercase border border-white/10 text-slate-300">{t.difficulty}</span>
                       <span className="px-3 py-1 bg-white/5 rounded-full text-[9px] font-black uppercase border border-white/10 text-slate-300">{t.archetype}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'model' && (
            <div className="max-w-4xl mx-auto glass-panel rounded-[3rem] p-16 shadow-2xl mb-20 relative overflow-hidden">
               <div className="absolute top-0 right-0 p-32 bg-purple-600/20 blur-[100px] rounded-full"></div>
              <h3 className="text-4xl font-black uppercase tracking-tighter mb-12 text-white relative z-10">Semantic Layer V1.0</h3>
              <div className="space-y-12 relative z-10">
                <section>
                  <h4 className="text-xs font-black text-slate-500 uppercase tracking-widest mb-6">Extracted Entities</h4>
                  <div className="grid gap-4">
                    {semanticModel.entities.map(e => (
                      <div key={e.name} className="p-6 bg-white/5 rounded-2xl border border-white/10 hover:border-purple-500/30 transition-colors">
                        <span className="font-black text-fuchsia-300">{e.name}</span>
                        <p className="text-sm text-slate-400 mt-2">{e.description}</p>
                      </div>
                    ))}
                  </div>
                </section>
                <section>
                   <h4 className="text-xs font-black text-slate-500 uppercase tracking-widest mb-6">Active Metrics</h4>
                   <div className="grid grid-cols-2 gap-4">
                     {semanticModel.metrics.map(m => (
                       <div key={m.name} className="p-6 border border-white/10 bg-white/5 rounded-2xl">
                         <span className="font-black text-cyan-300">{m.name}</span>
                         <span className="block text-[10px] text-slate-500 font-bold mt-1">{m.aggregation} / {m.grain}</span>
                       </div>
                     ))}
                   </div>
                </section>
                <pre className="bg-black/50 text-emerald-400 p-8 rounded-3xl text-[10px] overflow-x-auto shadow-inner border border-white/5">
                  {JSON.stringify(semanticModel, null, 2)}
                </pre>
              </div>
            </div>
          )}

          {activeTab === 'trust' && (
            <div className="max-w-4xl mx-auto pb-20">
              <div className="glass-panel rounded-[3.5rem] p-20 text-white shadow-2xl relative overflow-hidden border border-white/10">
                <div className="absolute top-0 right-0 p-20 opacity-10 text-fuchsia-500"><Icons.Shield /></div>
                <h3 className="text-5xl font-black uppercase tracking-tighter mb-8">Trust Perimeter</h3>
                <p className="text-slate-400 text-xl font-medium leading-relaxed max-w-xl">Our defense-in-depth approach ensures your BOH financial data and FOH customer data are isolated from prompt injection and exfiltration.</p>
                <div className="mt-12 grid grid-cols-2 gap-8">
                  <div className="p-8 bg-white/5 rounded-3xl border border-white/10">
                    <h5 className="font-black text-rose-400 uppercase tracking-widest mb-4">Prompt Injection</h5>
                    <p className="text-sm text-slate-400">Strict schema validation ensures document content is never interpreted as executable logic.</p>
                  </div>
                  <div className="p-8 bg-white/5 rounded-3xl border border-white/10">
                    <h5 className="font-black text-cyan-400 uppercase tracking-widest mb-4">XSS Defense</h5>
                    <p className="text-sm text-slate-400">Sanitizing all custom measures through a restricted expression language sandbox.</p>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>

        <AnalysisPanel 
          isOpen={isAnalysisOpen} 
          onClose={() => setIsAnalysisOpen(false)} 
          widget={analyzingWidget}
          analysis={analysisResult}
          isLoading={isAnalyzing}
        />
      </main>
    </div>
  );
};

