);

interface WidgetContainerProps {
  widget: WidgetConfig;
  mode: EditMode;
  data: any[];
  onAnalyze: (widget: WidgetConfig, currentData: any[]) => void;
  onResize?: (id: string, w: number, h: number) => void;
  onMove?: (id: string, x: number, y: number) => void;
  onUpdate?: (id: string, updates: Partial<WidgetConfig>) => void;
}

export const WidgetContainer: React.FC<WidgetContainerProps> = ({ widget, mode, data, onAnalyze, onResize, onMove, onUpdate }) => {
  const [drillPath, setDrillPath] = useState<string[]>([]);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isResizing, setIsResizing] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const [showSettings, setShowSettings] = useState(false);

  const currentLevelIndex = Math.min(drillPath.length, DRILL_HIERARCHY.length - 1);
  const currentLevel = DRILL_HIERARCHY[currentLevelIndex];
  const canDrill = drillPath.length < DRILL_HIERARCHY.length;

  const dataKeys = useMemo(() => data.length > 0 ? Object.keys(data[0]) : [], [data]);

  const filteredData = useMemo(() => {
    let result = data;
    drillPath.forEach((val, idx) => {
      const dim = DRILL_HIERARCHY[idx];
      result = result.filter(item => String(item[dim]) === val);
    });
    return result;
  }, [data, drillPath]);

  const handleDrill = (val: string) => {
    if (drillPath.length < DRILL_HIERARCHY.length) {
      setDrillPath([...drillPath, val]);
    }
  };

  const handleNavigate = (idx: number) => {
    setDrillPath(drillPath.slice(0, idx + 1));
  };

  const handleLevelUp = () => {
    setDrillPath(drillPath.slice(0, -1));
  };

  const calculateGridDelta = (deltaX: number, deltaY: number, parentWidth: number) => {
     const totalGapWidth = (GRID_SYSTEM.COLS - 1) * GRID_SYSTEM.GAP_PX;
     const colWidth = (parentWidth - totalGapWidth) / GRID_SYSTEM.COLS;
     const stepX = colWidth + GRID_SYSTEM.GAP_PX;
     const stepY = GRID_SYSTEM.ROW_HEIGHT_PX + GRID_SYSTEM.GAP_PX;
     return { dCol: Math.round(deltaX / stepX), dRow: Math.round(deltaY / stepY) };
  };

  const handleResizeStart = (e: React.MouseEvent) => {
    if (mode !== EditMode.PRO || !onResize) return;
    e.preventDefault(); e.stopPropagation();
    setIsResizing(true);
    const startX = e.clientX, startY = e.clientY, startW = widget.w, startH = widget.h;
    const parent = containerRef.current?.offsetParent as HTMLElement;
    if (!parent) return;
    const handleMouseMove = (moveEvent: MouseEvent) => {
      const { dCol, dRow } = calculateGridDelta(moveEvent.clientX - startX, moveEvent.clientY - startY, parent.clientWidth);
      const newW = Math.max(2, Math.min(GRID_SYSTEM.COLS - widget.x, startW + dCol));
      const newH = Math.max(1, Math.min(20, startH + dRow));
      if (newW !== widget.w || newH !== widget.h) onResize(widget.id, newW, newH);
    };
    const handleMouseUp = () => {
      setIsResizing(false);
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };
    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  };

  const handleDragStart = (e: React.MouseEvent) => {
    if (mode !== EditMode.PRO || !onMove) return;
    if ((e.target as HTMLElement).closest('button')) return;
    e.preventDefault();
    setIsDragging(true);
    const startX = e.clientX, startY = e.clientY, startGridX = widget.x, startGridY = widget.y;
    const parent = containerRef.current?.offsetParent as HTMLElement;
    if (!parent) return;
    const handleMouseMove = (moveEvent: MouseEvent) => {
        const { dCol, dRow } = calculateGridDelta(moveEvent.clientX - startX, moveEvent.clientY - startY, parent.clientWidth);
        const newX = Math.max(0, Math.min(GRID_SYSTEM.COLS - widget.w, startGridX + dCol));
        const newY = Math.max(0, startGridY + dRow);
        if (newX !== widget.x || newY !== widget.y) onMove(widget.id, newX, newY);
    };
    const handleMouseUp = () => {
        setIsDragging(false);
        document.removeEventListener('mousemove', handleMouseMove);
        document.removeEventListener('mouseup', handleMouseUp);
    };
    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  };

  // Helper labels for specific chart configurations
  const getDimensionLabel = () => {
    if (widget.type === VizType.SCATTER) return 'X-Axis Key';
    if (widget.type === VizType.HEATMAP) return 'Rows Key';
    if (widget.type === VizType.TREEMAP) return 'Hierarchy Key';
    return 'Dimension (X-Axis)';
  };

  const getSecondaryDimensionLabel = () => {
    if (widget.type === VizType.SCATTER) return 'Y-Axis Key';
    if (widget.type === VizType.HEATMAP) return 'Columns Key';
    return 'Secondary Dimension';
  };

  const getMetricLabel = () => {
    if (widget.type === VizType.SCATTER) return 'Dot Size Metric';
    if (widget.type === VizType.HEATMAP) return 'Cell Value Metric';
    if (widget.type === VizType.TREEMAP) return 'Area Size Metric';
    return 'Metric (Value)';
  };

  return (
    <div 
      ref={containerRef}
      className={`glass-panel rounded-3xl flex flex-col transition-all relative group/widget backdrop-blur-md 
        ${isResizing || isDragging ? 'z-50 border-fuchsia-500 shadow-2xl scale-[1.01]' : 'hover:border-fuchsia-500/30'}
        ${mode === EditMode.PRO ? 'cursor-grab active:cursor-grabbing' : ''}
      `}
      style={{ 
        gridColumn: `span ${widget.w}`, 
        gridRow: `span ${widget.h}`,
        gridColumnStart: widget.x + 1,
        gridRowStart: widget.y + 1,
        userSelect: isResizing || isDragging ? 'none' : 'auto'
      }}
      onMouseDown={handleDragStart}
    >
      {showSettings && (
          <div className="absolute inset-0 bg-slate-900/98 z-40 p-6 flex flex-col gap-4 animate-in fade-in zoom-in-95 duration-200 rounded-3xl shadow-2xl border border-fuchsia-500/20" onMouseDown={(e) => e.stopPropagation()}>
              <div className="flex justify-between items-center border-b border-white/10 pb-4">
                  <span className="font-black text-white uppercase tracking-wider text-sm">Widget Architect</span>
                  <button onClick={() => setShowSettings(false)} className="text-slate-400 hover:text-white transition-colors p-1"><Icons.Settings /></button>
              </div>

              <div className="space-y-4 overflow-y-auto custom-scrollbar pr-2">
                  <div>
                      <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1.5">Visual Title</label>
                      <input 
                          type="text" 
                          value={widget.title} 
                          onChange={(e) => onUpdate?.(widget.id, { title: e.target.value })}
                          className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2.5 text-sm text-white focus:border-fuchsia-500/50 outline-none transition-all"
                      />
                  </div>

                  <div>
                      <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1.5">{getDimensionLabel()}</label>
                      <select 
                          value={widget.dimension || ''} 
                          onChange={(e) => onUpdate?.(widget.id, { dimension: e.target.value })}
                          className="w-full bg-slate-800 border border-white/10 rounded-xl px-4 py-2.5 text-sm text-white focus:border-fuchsia-500/50 outline-none transition-all"
                      >
                          <option value="">(Auto Selection)</option>
                          {dataKeys.map(k => <option key={k} value={k}>{k}</option>)}
                      </select>
                  </div>

                  {(widget.type === VizType.SCATTER || widget.type === VizType.HEATMAP || widget.type === VizType.STACKED_BAR) && (
                    <div>
                        <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1.5">{getSecondaryDimensionLabel()}</label>
                        <select 
                            value={widget.secondaryDimension || ''} 
                            onChange={(e) => onUpdate?.(widget.id, { secondaryDimension: e.target.value })}
                            className="w-full bg-slate-800 border border-white/10 rounded-xl px-4 py-2.5 text-sm text-white focus:border-fuchsia-500/50 outline-none transition-all"
                        >
                            <option value="">(None)</option>
                            {dataKeys.map(k => <option key={k} value={k}>{k}</option>)}
                        </select>
                    </div>
                  )}

                  <div>
                      <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1.5">{getMetricLabel()}</label>
                      <select 
                          value={widget.metric || ''} 
                          onChange={(e) => onUpdate?.(widget.id, { metric: e.target.value })}
                          className="w-full bg-slate-800 border border-white/10 rounded-xl px-4 py-2.5 text-sm text-white focus:border-fuchsia-500/50 outline-none transition-all"
                      >
                          <option value="">(Auto Selection)</option>
                          {dataKeys.map(k => <option key={k} value={k}>{k}</option>)}
                      </select>
                  </div>
              </div>
          </div>
      )}

      {widget.type !== VizType.KPI_CARD && (
        <div className="px-6 py-4 border-b border-white/5 flex items-center justify-between bg-white/[0.02] rounded-t-3xl">
          <div className="flex flex-col">
            <span className="text-sm font-black text-white tracking-tight uppercase drop-shadow-sm">{widget.title}</span>
            <Breadcrumbs path={drillPath} onNavigate={handleNavigate} />
          </div>
          <div className="flex items-center gap-2">
            {mode === EditMode.PRO && (
                <button 
                    onClick={(e) => { e.stopPropagation(); setShowSettings(!showSettings); }}
                    className="p-1.5 hover:bg-white/10 rounded-lg text-slate-500 hover:text-white transition-colors"
                >
                    <Icons.Settings />
                </button>
            )}
            <button
               onClick={(e) => { e.stopPropagation(); onAnalyze(widget, filteredData); }}
               className="flex items-center gap-1.5 px-3 py-1.5 bg-white/5 border border-white/10 rounded-lg text-[10px] font-bold text-slate-400 uppercase tracking-wider hover:text-white hover:bg-white/10 hover:border-white/20 transition-all shadow-sm"
            >
              <Icons.Sparkles /> Analyze
            </button>
            {drillPath.length > 0 && (
              <button 
                onClick={(e) => { e.stopPropagation(); handleLevelUp(); }}
                className="p-1.5 hover:bg-white/10 rounded-lg text-slate-500 hover:text-white transition-colors"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 10l7-7m0 0l7 7m-7-7v18" />
                </svg>
              </button>
            )}
          </div>
        </div>
      )}

      {widget.type === VizType.KPI_CARD && (
         <div className="absolute top-4 right-4 opacity-0 group-hover/widget:opacity-100 transition-opacity z-20 flex gap-2">
            {mode === EditMode.PRO && (
                <button onClick={(e) => { e.stopPropagation(); setShowSettings(!showSettings); }} className="p-2 bg-slate-800 text-slate-300 rounded-full shadow-sm hover:scale-110 transition-transform">
                   <Icons.Settings />
                </button>
            )}
            <button onClick={(e) => { e.stopPropagation(); onAnalyze(widget, filteredData); }} className="p-2 bg-fuchsia-500/20 text-fuchsia-300 rounded-full shadow-sm hover:scale-110 transition-transform">
               <Icons.Sparkles />
            </button>
         </div>
      )}

      <div className="flex-1 p-6 relative overflow-hidden" onMouseDown={(e) => e.stopPropagation()}>
        <ChartRenderer 
          config={widget} 
          data={filteredData} 
          onDrill={handleDrill} 
          currentLevel={currentLevel} 
          drillPath={drillPath} 
          canDrill={canDrill}
        />
      </div>

      {mode === EditMode.PRO && (
        <div 
          onMouseDown={handleResizeStart}
          className="absolute bottom-0 right-0 w-8 h-8 cursor-se-resize z-20 flex items-center justify-center opacity-0 group-hover/widget:opacity-100 transition-opacity"
        >
          <svg className="w-5 h-5 text-fuchsia-500/50 hover:text-fuchsia-500 transition-colors transform rotate-45" fill="none" viewBox="0 0 24 24" stroke="currentColor">
             <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 5v14m7-14v14" />
          </svg>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect, useCallback, useRef } from 'react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';
import { Icons } from './constants';
import { EditMode, WidgetConfig, AnalysisResult, GRID_SYSTEM, VizType } from './types';
import { inferSemanticModel } from './services/semanticEngine';
import { generateTemplates } from './services/templateService';
import { generateAnalysis } from './services/aiService';
import { WidgetContainer } from './components/WidgetContainer';
import { Sidebar } from './components/Sidebar';
import { MagicBar } from './components/MagicBar';
import { AnalysisPanel } from './components/AnalysisPanel';
import { useDataManager } from './hooks/useDataManager';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'catalog' | 'model' | 'trust'>('dashboard');
  const [mode, setMode] = useState<EditMode>(EditMode.SAFE);
  const [selectedTemplateId, setSelectedTemplateId] = useState('foh-sales-exec');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false); // Collapsed by default

  const [dashboardWidgets, setDashboardWidgets] = useState<WidgetConfig[]>([]);
  const [isAnalysisOpen, setIsAnalysisOpen] = useState(false);
  const [analyzingWidget, setAnalyzingWidget] = useState<WidgetConfig | null>(null);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const dashboardRef = useRef<HTMLDivElement>(null);

  const templates = useMemo(() => generateTemplates(), []);
  const currentTemplate = useMemo(() => 
    templates.find(t => t.id === selectedTemplateId) || templates[0], 
    [templates, selectedTemplateId]
  );

  const { data, isStreaming, setIsStreaming, handleFileUpload, exportStandalone } = useDataManager(currentTemplate.name);
  const semanticModel = useMemo(() => inferSemanticModel(data), [data]);

  // Logic to place widget automatically in the "best" spot
  const handleWidgetGenerated = (newWidget: WidgetConfig) => {
    setDashboardWidgets(prev => {
      let placed = false;
      let y = 0;
      while (!placed && y < 50) {
        for (let x = 0; x <= GRID_SYSTEM.COLS - newWidget.w; x++) {
           const collision = prev.some(w => 
             x < w.x + w.w && x + newWidget.w > w.x &&
             y < w.y + w.h && y + newWidget.h > w.y
           );
           if (!collision) {
             newWidget.x = x;
             newWidget.y = y;
             placed = true;
             break;
           }
        }
        y++;
      }
      return [...prev, newWidget];
    });
  };

  const handleWidgetResize = useCallback((id: string, newW: number, newH: number) => {
    setDashboardWidgets(prev => prev.map(w => w.id === id ? { ...w, w: newW, h: newH } : w));
  }, []);

  const handleWidgetMove = useCallback((id: string, newX: number, newY: number) => {
    setDashboardWidgets(prev => prev.map(w => w.id === id ? { ...w, x: newX, y: newY } : w));
  }, []);

  const handleWidgetUpdate = useCallback((id: string, updates: Partial<WidgetConfig>) => {
    setDashboardWidgets(prev => prev.map(w => w.id === id ? { ...w, ...updates } : w));
  }, []);

  const handleAnalyze = async (widget: WidgetConfig, currentData: any[]) => {
    setAnalyzingWidget(widget);
    setIsAnalysisOpen(true);
    setAnalysisResult(null);
    setIsAnalyzing(true);
    const result = await generateAnalysis(widget.title, currentData);
    setAnalysisResult(result);
    setIsAnalyzing(false);
  };

  return (
    <div className="flex h-screen overflow-hidden text-slate-200 bg-cyber">
      <Sidebar 
        activeTab={activeTab}
        setActiveTab={setActiveTab}
        isSidebarOpen={isSidebarOpen}
        onImport={handleFileUpload}
        onExport={exportStandalone}
        toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)}
      />

      <main className="flex-1 flex flex-col overflow-hidden relative">
        {/* Simplified Header */}
        <header className="h-16 px-8 flex items-center justify-between shrink-0 glass-panel border-b border-white/5 z-40">
          <div className="flex items-center gap-6">
            <h2 className="text-lg font-black text-white uppercase tracking-tighter opacity-80">{activeTab}</h2>
            <div className="h-4 w-px bg-white/10 hidden md:block" />
            <div className="flex items-center gap-2">
              <div className={`w-2 h-2 rounded-full ${isStreaming ? 'bg-emerald-500 animate-pulse' : 'bg-slate-600'}`} />
              <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">{isStreaming ? "Live Intelligence" : "Static Engine"}</span>
            </div>
          </div>

          <div className="flex items-center gap-3">
             <button 
                onClick={() => setMode(mode === EditMode.SAFE ? EditMode.PRO : EditMode.SAFE)}
                className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${mode === EditMode.PRO ? 'bg-fuchsia-600 text-white' : 'bg-white/5 text-slate-400 border border-white/10'}`}
             >
                {mode === EditMode.PRO ? "Done Editing" : "Customize"}
             </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto custom-scrollbar relative p-6 lg:p-10">
          {activeTab === 'dashboard' && (
            <div className="max-w-screen-2xl mx-auto flex flex-col items-center">

              {/* Central Magic Bar - The Main Entry Point */}
              <div className="w-full max-w-3xl mb-12">
                <MagicBar 
                  onWidgetGenerated={handleWidgetGenerated} 
                  semanticModel={semanticModel} 
                  compact={dashboardWidgets.length > 0}
