              </div>

              {/* Empty State / Guided Actions */}
              {dashboardWidgets.length === 0 && (
                <div className="text-center py-20 animate-in fade-in zoom-in duration-700">
                   <div className="mb-6 inline-flex p-4 rounded-full bg-fuchsia-500/10 text-fuchsia-400 border border-fuchsia-500/20">
