                   <p className="text-slate-400 font-medium mb-12 max-w-lg mx-auto leading-relaxed">Ask me anything about your data, or choose a starting point below to generate your first insights instantly.</p>

                   <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 max-w-2xl mx-auto">
                      <button 
                        onClick={() => handleWidgetGenerated({ id: 'init-1', type: VizType.KPI_CARD, title: 'Total Revenue', x: 0, y: 0, w: 3, h: 1 })}
                        className="p-6 bg-white/5 border border-white/10 rounded-3xl hover:bg-white/10 hover:border-fuchsia-500/30 transition-all text-left group"
                      >
                         <div className="text-fuchsia-400 mb-2 group-hover:scale-110 transition-transform"><Icons.Dashboard /></div>
                         <div className="text-sm font-black text-white uppercase tracking-wider">Revenue Overview</div>
