const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'catalog' | 'model' | 'trust'>('dashboard');
  const [mode, setMode] = useState<EditMode>(EditMode.SAFE);
  const [selectedTemplateId, setSelectedTemplateId] = useState('foh-sales-exec');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const [dashboardWidgets, setDashboardWidgets] = useState<WidgetConfig[]>([]);
  const [isAnalysisOpen, setIsAnalysisOpen] = useState(false);
  const [analyzingWidget, setAnalyzingWidget] = useState<WidgetConfig | null>(null);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isExportModalOpen, setIsExportModalOpen] = useState(false);

  const dashboardRef = useRef<HTMLDivElement>(null);

  const templates = useMemo(() => generateTemplates(), []);
  const currentTemplate = useMemo(() => 
    templates.find(t => t.id === selectedTemplateId) || templates[0], 
    [templates, selectedTemplateId]
  );

  const { data, isStreaming, setIsStreaming, handleFileUpload } = useDataManager(currentTemplate.name);
  const semanticModel = useMemo(() => inferSemanticModel(data), [data]);

  // Sync with Template or LocalStorage
  useEffect(() => {
    const savedLayout = localStorage.getItem(`flashfusion_layout_${selectedTemplateId}`);
    if (savedLayout) {
      try {
        setDashboardWidgets(JSON.parse(savedLayout));
      } catch (e) {
        setDashboardWidgets(currentTemplate.widgets);
      }
    } else {
      setDashboardWidgets(currentTemplate.widgets);
    }
  }, [currentTemplate, selectedTemplateId]);

  // Persist Layout Changes
  useEffect(() => {
    if (dashboardWidgets.length > 0) {
      localStorage.setItem(`flashfusion_layout_${selectedTemplateId}`, JSON.stringify(dashboardWidgets));
    }
  }, [dashboardWidgets, selectedTemplateId]);

  const checkCollision = (id: string, x: number, y: number, w: number, h: number, widgets: WidgetConfig[]): boolean => {
    return widgets.some(other => {
      if (other.id === id) return false;
      return (
        x < other.x + other.w &&
        x + w > other.x &&
        y < other.y + other.h &&
        y + h > other.y
      );
    });
  };

  const handleWidgetGenerated = (newWidget: WidgetConfig) => {
    setDashboardWidgets(prev => {
      let placed = false;
      let y = 0;
      const widgetToPlace = { ...newWidget };
      // Simple vertical search for first available slot
      while (!placed && y < 50) {
        for (let x = 0; x <= GRID_SYSTEM.COLS - widgetToPlace.w; x++) {
           if (!checkCollision(widgetToPlace.id, x, y, widgetToPlace.w, widgetToPlace.h, prev)) {
             widgetToPlace.x = x;
             widgetToPlace.y = y;
             placed = true;
             break;
           }
        }
        y++;
      }
      return [...prev, widgetToPlace];
    });
  };

  const handleWidgetResize = useCallback((id: string, newW: number, newH: number) => {
    setDashboardWidgets(prev => {
      const target = prev.find(w => w.id === id);
      if (!target) return prev;
      if (target.x + newW > GRID_SYSTEM.COLS) return prev;
      if (checkCollision(id, target.x, target.y, newW, newH, prev)) return prev;
      return prev.map(w => w.id === id ? { ...w, w: newW, h: newH } : w);
    });
  }, []);

  const handleWidgetMove = useCallback((id: string, newX: number, newY: number) => {
    setDashboardWidgets(prev => {
      const target = prev.find(w => w.id === id);
      if (!target) return prev;
      if (newX < 0 || newX + target.w > GRID_SYSTEM.COLS || newY < 0) return prev;
      if (checkCollision(id, newX, newY, target.w, target.h, prev)) return prev;
      return prev.map(w => w.id === id ? { ...w, x: newX, y: newY } : w);
    });
  }, []);

  const handleWidgetUpdate = useCallback((id: string, updates: Partial<WidgetConfig>) => {
    setDashboardWidgets(prev => prev.map(w => w.id === id ? { ...w, ...updates } : w));
  }, []);

  const handleAnalyze = async (widget: WidgetConfig, currentData: any[]) => {
    setAnalyzingWidget(widget);
    setIsAnalysisOpen(true);
    setAnalysisResult(null);
    setIsAnalyzing(true);
    const result = await generateAnalysis(widget.title, currentData);
    setAnalysisResult(result);
    setIsAnalyzing(false);
  };

  // -- Export Logic --
  const processExport = async (config: ExportConfig) => {
    if (!dashboardRef.current) return;
    setIsExportModalOpen(false);

    // Scale factor
    const scale = config.resolution === 'Print' ? 4 : 2;

    const canvas = await html2canvas(dashboardRef.current, {
      backgroundColor: '#020617',
      scale: scale,
      useCORS: true,
      logging: false,
    });

    const filename = `${currentTemplate.name.replace(/\s+/g, '_')}_${config.resolution}`;

    if (config.format === 'PDF') {
      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('l', 'px', [canvas.width, canvas.height]);
      pdf.addImage(imgData, 'PNG', 0, 0, canvas.width, canvas.height);

      if (config.includeTitle) {
          pdf.setFontSize(24 * scale);
          pdf.setTextColor(255, 255, 255);
          pdf.text(currentTemplate.name, 40 * scale, 40 * scale);
      }
      if (config.includeDate) {
          pdf.setFontSize(14 * scale);
          pdf.setTextColor(150, 150, 150);
          pdf.text(`Generated: ${new Date().toLocaleDateString()}`, 40 * scale, 60 * scale);
      }

      pdf.save(`${filename}.pdf`);
    } else {
      // Image Export (PNG/JPG)
      let finalCanvas = canvas;

      // If metadata requested for image, create composite canvas
      if (config.includeTitle || config.includeDate) {
         const padding = 40 * scale;
         const headerHeight = ((config.includeTitle ? 40 : 0) + (config.includeDate ? 30 : 0)) * scale + padding;

         const composite = document.createElement('canvas');
         composite.width = canvas.width;
         composite.height = canvas.height + headerHeight;
         const ctx = composite.getContext('2d');

         if (ctx) {
            // Fill Background
            ctx.fillStyle = '#020617';
            ctx.fillRect(0, 0, composite.width, composite.height);

            // Draw Original
            ctx.drawImage(canvas, 0, headerHeight);

            // Draw Metadata
            ctx.textBaseline = 'top';
            let currentY = padding / 2;

            if (config.includeTitle) {
               ctx.font = `900 ${32 * scale}px Inter, sans-serif`;
               ctx.fillStyle = '#ffffff';
               ctx.fillText(currentTemplate.name, padding, currentY);
               currentY += 40 * scale;
            }

            if (config.includeDate) {
               ctx.font = `500 ${16 * scale}px Inter, sans-serif`;
               ctx.fillStyle = '#94a3b8';
               ctx.fillText(`Snapshot: ${new Date().toLocaleDateString()}`, padding, currentY);
            }

            finalCanvas = composite;
         }
      }

      const mime = config.format === 'PNG' ? 'image/png' : 'image/jpeg';
      const ext = config.format === 'PNG' ? 'png' : 'jpg';

      const link = document.createElement('a');
      link.download = `${filename}.${ext}`;
      link.href = finalCanvas.toDataURL(mime, 0.9);
      link.click();
    }
  };

  const handleQuickExport = (format: 'PNG' | 'PDF') => {
    processExport({
        format,
        includeTitle: true,
        includeDate: true,
        resolution: 'Screen'
    });
  };

  return (
    <div className="flex h-screen overflow-hidden text-slate-200 bg-cyber selection:bg-fuchsia-500/30">
      <ExportModal isOpen={isExportModalOpen} onClose={() => setIsExportModalOpen(false)} onConfirm={processExport} />

      <Sidebar 
        activeTab={activeTab}
        setActiveTab={setActiveTab}
        isSidebarOpen={isSidebarOpen}
        onImport={handleFileUpload}
        onExport={() => setIsExportModalOpen(true)}
        toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)}
      />

      <main className="flex-1 flex flex-col overflow-hidden relative">
        {/* Global Control Header */}
        <header className="h-20 px-8 flex items-center justify-between shrink-0 glass-panel border-b border-white/5 z-40">
          <div className="flex items-center gap-6">
             <div className="flex flex-col">
               <h1 className="text-2xl font-black text-transparent bg-clip-text bg-gradient-to-r from-white to-slate-400 uppercase tracking-tighter leading-none">FlashFusion</h1>
               <div className="flex items-center gap-2 mt-1">
                 <span className="text-[10px] font-bold text-fuchsia-500 uppercase tracking-widest">by IntInc</span>
                 <div className="w-1 h-1 rounded-full bg-slate-600"></div>
                 <span className="text-[10px] font-medium text-slate-500 uppercase tracking-widest">{currentTemplate.name}</span>
               </div>
             </div>
          </div>

          <div className="flex items-center gap-4">
             <div className="flex items-center gap-2 px-4 py-2 bg-white/5 rounded-full border border-white/5">
                <div className={`w-2 h-2 rounded-full ${isStreaming ? 'bg-emerald-500 animate-pulse shadow-[0_0_8px_#10b981]' : 'bg-slate-600'}`} />
                <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                  {isStreaming ? "Simulating Intelligence" : "Static Engine"}
                </span>
             </div>

             {/* Quick Export Buttons */}
             <div className="flex items-center bg-white/5 rounded-full p-1 border border-white/10 shadow-inner">
                <button 
                  onClick={() => handleQuickExport('PNG')}
                  className="px-4 py-1.5 text-[10px] font-black uppercase tracking-tighter text-slate-400 hover:text-white transition-all hover:bg-white/5 rounded-full"
                >
                  PNG
                </button>
                <button 
                  onClick={() => handleQuickExport('PDF')}
                  className="px-4 py-1.5 text-[10px] font-black uppercase tracking-tighter text-slate-400 hover:text-white transition-all hover:bg-white/5 rounded-full"
                >
                  PDF
                </button>
             </div>

             <button 
                onClick={() => setMode(mode === EditMode.SAFE ? EditMode.PRO : EditMode.SAFE)}
                className={`flex items-center gap-2 px-6 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all shadow-lg ${
                  mode === EditMode.PRO 
                    ? 'bg-fuchsia-600 text-white shadow-fuchsia-600/30 hover:bg-fuchsia-500' 
                    : 'bg-white/5 text-slate-400 border border-white/10 hover:border-white/20 hover:text-white'
                }`}
             >
                <Icons.Settings />
                {mode === EditMode.PRO ? "Save Layout" : "Edit Layout"}
             </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto custom-scrollbar relative p-6 lg:p-12">
          {activeTab === 'dashboard' && (
            <div className="max-w-screen-2xl mx-auto flex flex-col items-center">

              {/* Studio-Grade AI Input */}
              <div className="w-full max-w-4xl mb-16 relative z-30">
                <MagicBar 
                  onWidgetGenerated={handleWidgetGenerated} 
                  semanticModel={semanticModel} 
                  compact={dashboardWidgets.length > 0}
                />
              </div>

              {/* Zero-State Onboarding */}
              {dashboardWidgets.length === 0 && (
                <div className="text-center py-20 animate-in fade-in zoom-in duration-1000">
                   <div className="mb-8 inline-flex p-6 rounded-[2rem] bg-gradient-to-br from-fuchsia-600/20 to-indigo-600/20 text-fuchsia-400 border border-fuchsia-500/20 shadow-2xl shadow-fuchsia-500/10">
                      <Icons.Sparkles />
                   </div>
                   <h1 className="text-6xl font-black text-white tracking-tighter mb-6 drop-shadow-2xl">FlashFusion</h1>
                   <p className="text-slate-400 font-medium mb-12 max-w-xl mx-auto leading-relaxed text-lg">
                     The conversational intelligence studio. <br/> Describe your data story, and we'll build the dashboard.
                   </p>
                   <div className="flex justify-center gap-4">
                      <button onClick={() => setDashboardWidgets(currentTemplate.widgets)} className="px-8 py-4 bg-white text-slate-950 rounded-2xl font-black uppercase tracking-tighter hover:bg-slate-200 transition-all shadow-xl hover:scale-105">Load Blueprint</button>
                      <button onClick={() => setIsStreaming(true)} className="px-8 py-4 bg-white/5 border border-white/10 text-white rounded-2xl font-black uppercase tracking-tighter hover:bg-white/10 transition-all hover:scale-105">Watch Simulation</button>
                   </div>
                </div>
              )}

              {/* High-Fidelity Responsive Grid */}
              <div 
                ref={dashboardRef} 
                className="grid w-full pb-64 relative transition-all duration-500"
                style={{
                  gridTemplateColumns: `repeat(${GRID_SYSTEM.COLS}, minmax(0, 1fr))`,
                  gap: `${GRID_SYSTEM.GAP_PX}px`,
                  gridAutoRows: `${GRID_SYSTEM.ROW_HEIGHT_PX}px`
                }}
              >
                {dashboardWidgets.map(w => (
                  <WidgetContainer 
                    key={w.id} 
                    widget={w} 
                    mode={mode} 
                    data={data} 
                    onAnalyze={handleAnalyze}
                    onResize={handleWidgetResize}
                    onMove={handleWidgetMove}
                    onUpdate={handleWidgetUpdate}
                  />
                ))}
              </div>
            </div>
          )}

          {activeTab === 'catalog' && (
             <div className="max-w-screen-xl mx-auto">
               <div className="flex items-end justify-between mb-12">
                 <div>
                   <h1 className="text-4xl font-black text-white uppercase tracking-tighter">Blueprint Catalog</h1>
                   <p className="text-slate-500 font-bold mt-2 tracking-wide uppercase text-[10px]">Curated by FlashFusion Strategy</p>
                 </div>
               </div>
               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                 {templates.map(t => (
                   <button 
                    key={t.id} 
                    onClick={() => { setSelectedTemplateId(t.id); setActiveTab('dashboard'); }}
                    className="glass-panel p-8 rounded-[2.5rem] border border-white/5 hover:border-fuchsia-500/30 text-left transition-all group relative overflow-hidden"
                   >
                     <div className="absolute top-0 right-0 w-32 h-32 bg-fuchsia-600/5 blur-3xl group-hover:bg-fuchsia-600/10 transition-all" />
                     <span className="text-[10px] font-black text-fuchsia-400 uppercase tracking-widest">{t.category}</span>
