               <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Format</label>
               <div className="flex gap-2">
                  {(['PNG', 'JPG', 'PDF'] as const).map(f => (
                    <button 
                      key={f}
                      onClick={() => setConfig({ ...config, format: f })}
                      className={`flex-1 py-2 rounded-xl text-xs font-bold transition-all ${config.format === f ? 'bg-fuchsia-600 text-white' : 'bg-white/5 text-slate-400 hover:bg-white/10'}`}
