                          className={`flex-1 py-2 rounded-lg text-[10px] font-bold uppercase tracking-wide transition-all ${config.paperSize === s ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}
