                    <button 
                      key={r}
                      onClick={() => setConfig({ ...config, resolution: r })}
                      className={`flex-1 py-2 rounded-xl text-xs font-bold transition-all ${config.resolution === r ? 'bg-indigo-600 text-white' : 'bg-white/5 text-slate-400 hover:bg-white/10'}`}
                    >
                      {r} (x{r === 'Screen' ? '2' : '4'})
