  includeTitle: boolean;
  includeDate: boolean;
  dpi: number;
  quality: number;
  orientation: 'landscape' | 'portrait';
  paperSize: 'a4' | 'letter' | 'legal';
}
const ExportModal: React.FC<ExportModalProps> = ({ isOpen, onClose, onConfirm }) => {
