                      key={d}
                      onClick={() => setConfig({ ...config, dpi: d })}
                      className={`flex-1 py-2 rounded-xl text-xs font-bold transition-all ${config.dpi === d ? 'bg-indigo-600 text-white' : 'bg-white/5 text-slate-400 hover:bg-white/10'}`}
                    >
                      {d} {d === 72 ? '(Screen)' : d === 150 ? '(Web)' : '(Print)'}
                    </button>
                  ))}
               </div>
            </div>

            {(config.format === 'JPG' || config.format === 'PDF') && (
              <div className="space-y-2 animate-in fade-in slide-in-from-top-1 duration-200">
                 <div className="flex justify-between items-center">
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Quality / Compression</label>
                    <span className="text-xs font-bold text-fuchsia-400">{Math.round(config.quality * 100)}%</span>
                 </div>
                 <input 
                    type="range" 
                    min="10" 
                    max="100" 
                    value={config.quality * 100} 
                    onChange={(e) => setConfig({ ...config, quality: Number(e.target.value) / 100 })}
                    className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-fuchsia-600"
                 />
              </div>
            )}
         </div>

         <div className="flex gap-3 pt-4 border-t border-white/5">
            <button onClick={onClose} className="flex-1 py-3 text-xs font-black uppercase tracking-widest text-slate-400 hover:text-white transition-colors">Cancel</button>
            <button onClick={() => onConfirm(config)} className="flex-1 py-3 bg-white text-slate-900 rounded-xl text-xs font-black uppercase tracking-widest hover:bg-slate-200 transition-colors">Download</button>
         </div>
      </div>
    </div>
  );
};


const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'catalog' | 'model' | 'trust'>('dashboard');
  const [mode, setMode] = useState<EditMode>(EditMode.SAFE);
  const [selectedTemplateId, setSelectedTemplateId] = useState('foh-sales-exec');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const [dashboardWidgets, setDashboardWidgets] = useState<WidgetConfig[]>([]);
  const [isAnalysisOpen, setIsAnalysisOpen] = useState(false);
  const [analyzingWidget, setAnalyzingWidget] = useState<WidgetConfig | null>(null);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isExportModalOpen, setIsExportModalOpen] = useState(false);

  const dashboardRef = useRef<HTMLDivElement>(null);

  const templates = useMemo(() => generateTemplates(), []);
  const currentTemplate = useMemo(() => 
    templates.find(t => t.id === selectedTemplateId) || templates[0], 
    [templates, selectedTemplateId]
  );

  const { data, isStreaming, setIsStreaming, handleFileUpload } = useDataManager(currentTemplate.name);
  const semanticModel = useMemo(() => inferSemanticModel(data), [data]);

  // Sync with Template or LocalStorage
  useEffect(() => {
    const savedLayout = localStorage.getItem(`flashfusion_layout_${selectedTemplateId}`);
    if (savedLayout) {
      try {
        setDashboardWidgets(JSON.parse(savedLayout));
      } catch (e) {
        setDashboardWidgets(currentTemplate.widgets);
      }
    } else {
      setDashboardWidgets(currentTemplate.widgets);
    }
  }, [currentTemplate, selectedTemplateId]);

  // Persist Layout Changes
  useEffect(() => {
    if (dashboardWidgets.length > 0) {
      localStorage.setItem(`flashfusion_layout_${selectedTemplateId}`, JSON.stringify(dashboardWidgets));
    }
  }, [dashboardWidgets, selectedTemplateId]);

  const checkCollision = (id: string, x: number, y: number, w: number, h: number, widgets: WidgetConfig[]): boolean => {
    return widgets.some(other => {
      if (other.id === id) return false;
      return (
        x < other.x + other.w &&
        x + w > other.x &&
        y < other.y + other.h &&
        y + h > other.y
      );
    });
  };

  const handleWidgetGenerated = (newWidget: WidgetConfig) => {
    setDashboardWidgets(prev => {
      let placed = false;
      let y = 0;
      const widgetToPlace = { ...newWidget };
      // Simple vertical search for first available slot
      while (!placed && y < 50) {
        for (let x = 0; x <= GRID_SYSTEM.COLS - widgetToPlace.w; x++) {
           if (!checkCollision(widgetToPlace.id, x, y, widgetToPlace.w, widgetToPlace.h, prev)) {
             widgetToPlace.x = x;
             widgetToPlace.y = y;
             placed = true;
             break;
           }
        }
        y++;
      }
      return [...prev, widgetToPlace];
    });
  };

  const handleWidgetResize = useCallback((id: string, newW: number, newH: number) => {
    setDashboardWidgets(prev => {
      const target = prev.find(w => w.id === id);
      if (!target) return prev;
      if (target.x + newW > GRID_SYSTEM.COLS) return prev;
      if (checkCollision(id, target.x, target.y, newW, newH, prev)) return prev;
      return prev.map(w => w.id === id ? { ...w, w: newW, h: newH } : w);
    });
  }, []);

  const handleWidgetMove = useCallback((id: string, newX: number, newY: number) => {
    setDashboardWidgets(prev => {
      const target = prev.find(w => w.id === id);
      if (!target) return prev;
      if (newX < 0 || newX + target.w > GRID_SYSTEM.COLS || newY < 0) return prev;
      if (checkCollision(id, newX, newY, target.w, target.h, prev)) return prev;
      return prev.map(w => w.id === id ? { ...w, x: newX, y: newY } : w);
    });
  }, []);

  const handleWidgetUpdate = useCallback((id: string, updates: Partial<WidgetConfig>) => {
    setDashboardWidgets(prev => prev.map(w => w.id === id ? { ...w, ...updates } : w));
  }, []);

  const handleAnalyze = async (widget: WidgetConfig, currentData: any[]) => {
    setAnalyzingWidget(widget);
    setIsAnalysisOpen(true);
    setAnalysisResult(null);
    setIsAnalyzing(true);
    const result = await generateAnalysis(widget.title, currentData);
    setAnalysisResult(result);
    setIsAnalyzing(false);
  };

  // -- Export Logic --
  const processExport = async (config: ExportConfig) => {
    if (!dashboardRef.current) return;
    setIsExportModalOpen(false);

    // Calculate Scale from DPI (Base 96)
    const scale = config.dpi / 96;

    const canvas = await html2canvas(dashboardRef.current, {
      backgroundColor: '#020617',
      scale: scale,
      useCORS: true,
      logging: false,
    });

    const filename = `${currentTemplate.name.replace(/\s+/g, '_')}_${config.dpi}dpi`;

    if (config.format === 'PDF') {
      const doc = new jsPDF({
        orientation: config.orientation,
        unit: 'mm',
        format: config.paperSize
      });

      const pageWidth = doc.internal.pageSize.getWidth();
      const pageHeight = doc.internal.pageSize.getHeight();
      const margin = 10; // mm

      // Use JPEG if quality < 1 for better compression
      const isCompressed = config.quality < 1.0;
      const imgData = canvas.toDataURL(isCompressed ? 'image/jpeg' : 'image/png', config.quality);
      const imgProps = doc.getImageProperties(imgData);

      // Calculate constraints
      const availWidth = pageWidth - (margin * 2);
      const availHeight = pageHeight - (margin * 2) - 15; // Extra space for header

      const ratio = Math.min(availWidth / imgProps.width, availHeight / imgProps.height);
      const finalW = imgProps.width * ratio;
      const finalH = imgProps.height * ratio;

      const x = (pageWidth - finalW) / 2;
      const y = margin + 15; // Push down below header

      // Render Header
      if (config.includeTitle || config.includeDate) {
         doc.setFont('helvetica', 'bold');
         doc.setFontSize(11);
         doc.setTextColor(50, 50, 60);

         if (config.includeTitle) {
            doc.text(currentTemplate.name.toUpperCase(), margin, margin + 5);
         }

         if (config.includeDate) {
            doc.setFont('helvetica', 'normal');
            doc.setFontSize(9);
            doc.setTextColor(100, 100, 100);
            const dateStr = new Date().toLocaleDateString();
            const dateWidth = doc.getTextWidth(dateStr);
            doc.text(dateStr, pageWidth - margin - dateWidth, margin + 5);
         }

         // Add separator line
         doc.setDrawColor(200, 200, 200);
         doc.line(margin, margin + 8, pageWidth - margin, margin + 8);
      }

      doc.addImage(imgData, isCompressed ? 'JPEG' : 'PNG', x, y, finalW, finalH, undefined, isCompressed ? 'FAST' : 'NONE');
      doc.save(`${filename}.pdf`);

    } else {
      // Image Export (PNG/JPG)
      let finalCanvas = canvas;

      // If metadata requested for image, create composite canvas
      if (config.includeTitle || config.includeDate) {
         const padding = 40 * scale;
         const headerHeight = ((config.includeTitle ? 40 : 0) + (config.includeDate ? 30 : 0)) * scale + padding;

         const composite = document.createElement('canvas');
         composite.width = canvas.width;
         composite.height = canvas.height + headerHeight;
         const ctx = composite.getContext('2d');

         if (ctx) {
            // Fill Background
            ctx.fillStyle = '#020617';
            ctx.fillRect(0, 0, composite.width, composite.height);

            // Draw Original
            ctx.drawImage(canvas, 0, headerHeight);

            // Draw Metadata
            ctx.textBaseline = 'top';
            let currentY = padding / 2;

            if (config.includeTitle) {
               ctx.font = `900 ${32 * scale}px Inter, sans-serif`;
               ctx.fillStyle = '#ffffff';
               ctx.fillText(currentTemplate.name, padding, currentY);
               currentY += 40 * scale;
            }

            if (config.includeDate) {
               ctx.font = `500 ${16 * scale}px Inter, sans-serif`;
               ctx.fillStyle = '#94a3b8';
               ctx.fillText(`Snapshot: ${new Date().toLocaleDateString()}`, padding, currentY);
            }

            finalCanvas = composite;
         }
      }

      const mime = config.format === 'PNG' ? 'image/png' : 'image/jpeg';
      const ext = config.format === 'PNG' ? 'png' : 'jpg';

      const link = document.createElement('a');
      link.download = `${filename}.${ext}`;
      // Note: toDataURL quality argument is ignored for image/png
      link.href = finalCanvas.toDataURL(mime, config.quality);
      link.click();
    }
  };

  const handleQuickExport = (format: 'PNG' | 'PDF') => {
    processExport({
        format,
        includeTitle: true,
        includeDate: true,
        dpi: 72,
        quality: 1.0,
        orientation: 'landscape',
        paperSize: 'a4'
    });
  };

  return (
    <div className="flex h-screen overflow-hidden text-slate-200 bg-cyber selection:bg-fuchsia-500/30">
      <ExportModal isOpen={isExportModalOpen} onClose={() => setIsExportModalOpen(false)} onConfirm={processExport} />

      <Sidebar 
        activeTab={activeTab}
        setActiveTab={setActiveTab}
        isSidebarOpen={isSidebarOpen}
        onImport={handleFileUpload}
        onExport={() => setIsExportModalOpen(true)}
        toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)}
      />

      <main className="flex-1 flex flex-col overflow-hidden relative">
        {/* Global Control Header */}
        <header className="h-20 px-8 flex items-center justify-between shrink-0 glass-panel border-b border-white/5 z-40">
          <div className="flex items-center gap-6">
             <div className="flex flex-col">
               <h1 className="text-2xl font-black text-transparent bg-clip-text bg-gradient-to-r from-white to-slate-400 uppercase tracking-tighter leading-none">FlashFusion</h1>
               <div className="flex items-center gap-2 mt-1">
                 <span className="text-[10px] font-bold text-fuchsia-500 uppercase tracking-widest">by IntInc</span>
                 <div className="w-1 h-1 rounded-full bg-slate-600"></div>
                 <span className="text-[10px] font-medium text-slate-500 uppercase tracking-widest">{currentTemplate.name}</span>
               </div>
             </div>
          </div>

          <div className="flex items-center gap-4">
             <div className="flex items-center gap-2 px-4 py-2 bg-white/5 rounded-full border border-white/5">
                <div className={`w-2 h-2 rounded-full ${isStreaming ? 'bg-emerald-500 animate-pulse shadow-[0_0_8px_#10b981]' : 'bg-slate-600'}`} />
                <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                  {isStreaming ? "Simulating Intelligence" : "Static Engine"}
                </span>
             </div>

             {/* Quick Export Buttons */}
             <div className="flex items-center bg-white/5 rounded-full p-1 border border-white/10 shadow-inner">
                <button 
                  onClick={() => handleQuickExport('PNG')}
                  className="px-4 py-1.5 text-[10px] font-black uppercase tracking-tighter text-slate-400 hover:text-white transition-all hover:bg-white/5 rounded-full"
                >
                  PNG
                </button>
                <button 
                  onClick={() => handleQuickExport('PDF')}
                  className="px-4 py-1.5 text-[10px] font-black uppercase tracking-tighter text-slate-400 hover:text-white transition-all hover:bg-white/5 rounded-full"
                >
                  PDF
                </button>
             </div>

             <button 
                onClick={() => setMode(mode === EditMode.SAFE ? EditMode.PRO : EditMode.SAFE)}
                className={`flex items-center gap-2 px-6 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all shadow-lg ${
                  mode === EditMode.PRO 
                    ? 'bg-fuchsia-600 text-white shadow-fuchsia-600/30 hover:bg-fuchsia-500' 
                    : 'bg-white/5 text-slate-400 border border-white/10 hover:border-white/20 hover:text-white'
                }`}
             >
                <Icons.Settings />
                {mode === EditMode.PRO ? "Save Layout" : "Edit Layout"}
             </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto custom-scrollbar relative p-6 lg:p-12">
          {activeTab === 'dashboard' && (
            <div className="max-w-screen-2xl mx-auto flex flex-col items-center">

              {/* Studio-Grade AI Input */}
              <div className="w-full max-w-4xl mb-16 relative z-30">
                <MagicBar 
                  onWidgetGenerated={handleWidgetGenerated} 
                  semanticModel={semanticModel} 
                  compact={dashboardWidgets.length > 0}
                />
              </div>

              {/* Zero-State Onboarding */}
              {dashboardWidgets.length === 0 && (
                <div className="text-center py-20 animate-in fade-in zoom-in duration-1000">
                   <div className="mb-8 inline-flex p-6 rounded-[2rem] bg-gradient-to-br from-fuchsia-600/20 to-indigo-600/20 text-fuchsia-400 border border-fuchsia-500/20 shadow-2xl shadow-fuchsia-500/10">
                      <Icons.Sparkles />
                   </div>
                   <h1 className="text-6xl font-black text-white tracking-tighter mb-6 drop-shadow-2xl">FlashFusion</h1>
                   <p className="text-slate-400 font-medium mb-12 max-w-xl mx-auto leading-relaxed text-lg">
                     The conversational intelligence studio. <br/> Describe your data story, and we'll build the dashboard.
                   </p>
                   <div className="flex justify-center gap-4">
                      <button onClick={() => setDashboardWidgets(currentTemplate.widgets)} className="px-8 py-4 bg-white text-slate-950 rounded-2xl font-black uppercase tracking-tighter hover:bg-slate-200 transition-all shadow-xl hover:scale-105">Load Blueprint</button>
                      <button onClick={() => setIsStreaming(true)} className="px-8 py-4 bg-white/5 border border-white/10 text-white rounded-2xl font-black uppercase tracking-tighter hover:bg-white/10 transition-all hover:scale-105">Watch Simulation</button>
                   </div>
                </div>
              )}

              {/* High-Fidelity Responsive Grid */}
              <div 
                ref={dashboardRef} 
                className="grid w-full pb-64 relative transition-all duration-500"
                style={{
                  gridTemplateColumns: `repeat(${GRID_SYSTEM.COLS}, minmax(0, 1fr))`,
                  gap: `${GRID_SYSTEM.GAP_PX}px`,
                  gridAutoRows: `${GRID_SYSTEM.ROW_HEIGHT_PX}px`
                }}
              >
                {dashboardWidgets.map(w => (
                  <WidgetContainer 
                    key={w.id} 
                    widget={w} 
                    mode={mode} 
                    data={data} 
                    onAnalyze={handleAnalyze}
                    onResize={handleWidgetResize}
                    onMove={handleWidgetMove}
                    onUpdate={handleWidgetUpdate}
                  />
                ))}
              </div>
            </div>
          )}

          {activeTab === 'catalog' && (
             <div className="max-w-screen-xl mx-auto">
               <div className="flex items-end justify-between mb-12">
                 <div>
                   <h1 className="text-4xl font-black text-white uppercase tracking-tighter">Blueprint Catalog</h1>
                   <p className="text-slate-500 font-bold mt-2 tracking-wide uppercase text-[10px]">Curated by FlashFusion Strategy</p>
                 </div>
               </div>
               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                 {templates.map(t => (
                   <button 
                    key={t.id} 
                    onClick={() => { setSelectedTemplateId(t.id); setActiveTab('dashboard'); }}
                    className="glass-panel p-8 rounded-[2.5rem] border border-white/5 hover:border-fuchsia-500/30 text-left transition-all group relative overflow-hidden"
                   >
                     <div className="absolute top-0 right-0 w-32 h-32 bg-fuchsia-600/5 blur-3xl group-hover:bg-fuchsia-600/10 transition-all" />
                     <span className="text-[10px] font-black text-fuchsia-400 uppercase tracking-widest">{t.category}</span>
                     <h3 className="text-2xl font-black text-white mt-2 group-hover:text-fuchsia-300 transition-colors">{t.name}</h3>
                     <p className="text-slate-400 text-sm mt-4 leading-relaxed line-clamp-2">{t.description}</p>
                     <div className="mt-8 flex items-center justify-between">
                        <span className="px-3 py-1 bg-white/5 border border-white/10 rounded-full text-[9px] font-black uppercase text-slate-500">{t.difficulty}</span>
                        <div className="text-fuchsia-500 opacity-0 group-hover:opacity-100 transition-all translate-x-4 group-hover:translate-x-0">
                          <Icons.Sparkles />
                        </div>
                     </div>
                   </button>
                 ))}
               </div>
             </div>
          )}
        </div>

        <AnalysisPanel 
          isOpen={isAnalysisOpen} 
          onClose={() => setIsAnalysisOpen(false)} 
          widget={analyzingWidget}
          analysis={analysisResult}
          isLoading={isAnalyzing}
        />
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';

export interface ExportConfig {
  format: 'PNG' | 'JPG' | 'PDF';
  includeTitle: boolean;
  includeDate: boolean;
  dpi: number;
  quality: number;
  orientation: 'landscape' | 'portrait';
  paperSize: 'a4' | 'letter' | 'legal';
}

interface ExportModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (config: ExportConfig) => void;
}

export const ExportModal: React.FC<ExportModalProps> = ({ isOpen, onClose, onConfirm }) => {
  const [config, setConfig] = useState<ExportConfig>({ 
    format: 'PNG', 
    includeTitle: true, 
    includeDate: true,
    dpi: 144,
    quality: 0.9,
    orientation: 'landscape',
    paperSize: 'a4'
  });

  const [useCustomDpi, setUseCustomDpi] = useState(false);

  if (!isOpen) return null;

  const handleDpiSelect = (val: number | 'custom') => {
    if (val === 'custom') {
      setUseCustomDpi(true);
    } else {
      setUseCustomDpi(false);
      setConfig({ ...config, dpi: val });
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-950/80 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="w-[32rem] bg-slate-900 border border-white/10 rounded-[2rem] p-8 shadow-2xl">
         <h3 className="text-xl font-black text-white uppercase tracking-tighter mb-6">Export Snapshot</h3>

         <div className="space-y-6 mb-8 max-h-[60vh] overflow-y-auto custom-scrollbar pr-2">
            {/* Format Selection */}
            <div className="space-y-2">
               <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Format</label>
               <div className="flex gap-2">
                  {(['PNG', 'JPG', 'PDF'] as const).map(f => (
                    <button 
                      key={f}
                      onClick={() => setConfig({ ...config, format: f })}
                      className={`flex-1 py-2 rounded-xl text-xs font-bold transition-all ${config.format === f ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-600/20' : 'bg-white/5 text-slate-400 hover:bg-white/10'}`}
                    >
                      {f}
                    </button>
                  ))}
               </div>
            </div>

            {/* PDF Specific Settings */}
            {config.format === 'PDF' && (
              <div className="p-4 bg-white/5 rounded-2xl border border-white/5 space-y-4 animate-in fade-in slide-in-from-top-2 duration-300">
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Page Orientation</label>
                   <div className="flex gap-2">
                      {(['landscape', 'portrait'] as const).map(o => (
                        <button 
                          key={o}
                          onClick={() => setConfig({ ...config, orientation: o })}
                          className={`flex-1 py-2 rounded-lg text-[10px] font-bold uppercase tracking-wide transition-all ${config.orientation === o ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}
                        >
                          {o}
                        </button>
                      ))}
                   </div>
                </div>
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Paper Size</label>
                   <div className="flex gap-2">
                      {(['a4', 'letter', 'legal'] as const).map(s => (
                        <button 
                          key={s}
                          onClick={() => setConfig({ ...config, paperSize: s })}
                          className={`flex-1 py-2 rounded-lg text-[10px] font-bold uppercase tracking-wide transition-all ${config.paperSize === s ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}
                        >
                          {s}
                        </button>
                      ))}
                   </div>
                </div>
              </div>
            )}

            {/* Metadata Toggle */}
            <div className="space-y-2">
               <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Metadata</label>
               <div className="grid grid-cols-2 gap-3">
                 <div className="flex items-center justify-between p-3 bg-white/5 rounded-xl border border-white/5 cursor-pointer hover:bg-white/10 transition-colors" onClick={() => setConfig({...config, includeTitle: !config.includeTitle})}>
                    <span className="text-xs font-bold text-slate-300">Include Title</span>
                    <div className={`w-4 h-4 rounded border flex items-center justify-center ${config.includeTitle ? 'bg-fuchsia-600 border-fuchsia-600' : 'border-slate-600'}`}>
                      {config.includeTitle && <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>}
                    </div>
                 </div>
                 <div className="flex items-center justify-between p-3 bg-white/5 rounded-xl border border-white/5 cursor-pointer hover:bg-white/10 transition-colors" onClick={() => setConfig({...config, includeDate: !config.includeDate})}>
                    <span className="text-xs font-bold text-slate-300">Timestamp</span>
                    <div className={`w-4 h-4 rounded border flex items-center justify-center ${config.includeDate ? 'bg-fuchsia-600 border-fuchsia-600' : 'border-slate-600'}`}>
                      {config.includeDate && <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>}
                    </div>
                 </div>
               </div>
            </div>

            {/* Resolution Control */}
            <div className="space-y-3">
               <div className="flex justify-between items-end">
                 <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Resolution (DPI)</label>
                 {useCustomDpi && <span className="text-[10px] font-bold text-fuchsia-400">{config.dpi} DPI</span>}
               </div>

               <div className="flex gap-2">
                  {[72, 144, 300].map(d => (
                    <button 
                      key={d}
                      onClick={() => handleDpiSelect(d)}
                      className={`flex-1 py-2 rounded-xl text-xs font-bold transition-all ${!useCustomDpi && config.dpi === d ? 'bg-indigo-600 text-white' : 'bg-white/5 text-slate-400 hover:bg-white/10'}`}
                    >
                      {d} <span className="opacity-50 text-[9px] block">{d === 72 ? 'Screen' : d === 144 ? 'Web' : 'Print'}</span>
                    </button>
                  ))}
                  <button 
                    onClick={() => handleDpiSelect('custom')}
                    className={`flex-1 py-2 rounded-xl text-xs font-bold transition-all ${useCustomDpi ? 'bg-indigo-600 text-white' : 'bg-white/5 text-slate-400 hover:bg-white/10'}`}
                  >
                    Custom
                  </button>
               </div>

               {useCustomDpi && (
                 <div className="animate-in fade-in slide-in-from-top-2 duration-200">
                   <input 
                      type="range" 
                      min="72" 
                      max="600" 
                      step="10"
                      value={config.dpi} 
                      onChange={(e) => setConfig({ ...config, dpi: Number(e.target.value) })}
                      className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500"
                   />
                 </div>
               )}
            </div>

            {/* Quality Control */}
            {(config.format === 'JPG' || config.format === 'PDF') && (
              <div className="space-y-2 animate-in fade-in slide-in-from-top-1 duration-200 bg-white/5 p-4 rounded-2xl border border-white/5">
                 <div className="flex justify-between items-center">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Compression / Quality</label>
                    <span className="text-xs font-bold text-fuchsia-400">{Math.round(config.quality * 100)}%</span>
                 </div>
                 <input 
                    type="range" 
                    min="10" 
                    max="100" 
                    value={config.quality * 100} 
                    onChange={(e) => setConfig({ ...config, quality: Number(e.target.value) / 100 })}
                    className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-fuchsia-600"
                 />
                 <p className="text-[10px] text-slate-500 pt-1">Lower quality reduces file size significantly.</p>
              </div>
            )}
         </div>

         <div className="flex gap-3 pt-4 border-t border-white/5">
            <button onClick={onClose} className="flex-1 py-3 text-xs font-black uppercase tracking-widest text-slate-400 hover:text-white transition-colors hover:bg-white/5 rounded-xl">Cancel</button>
            <button onClick={() => onConfirm(config)} className="flex-1 py-3 bg-white text-slate-900 rounded-xl text-xs font-black uppercase tracking-widest hover:bg-slate-200 transition-colors shadow-lg shadow-white/10">Download Snapshot</button>
         </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect, useCallback, useRef } from 'react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';
import { Icons } from './constants';
import { EditMode, WidgetConfig, AnalysisResult, GRID_SYSTEM, VizType } from './types';
import { inferSemanticModel } from './services/semanticEngine';
import { generateTemplates } from './services/templateService';
import { generateAnalysis } from './services/aiService';
import { WidgetContainer } from './components/WidgetContainer';
import { Sidebar } from './components/Sidebar';
import { MagicBar } from './components/MagicBar';
import { AnalysisPanel } from './components/AnalysisPanel';
import { useDataManager } from './hooks/useDataManager';
import { ExportModal, ExportConfig } from './components/ExportModal';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'catalog' | 'model' | 'trust'>('dashboard');
  const [mode, setMode] = useState<EditMode>(EditMode.SAFE);
  const [selectedTemplateId, setSelectedTemplateId] = useState('foh-sales-exec');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const [dashboardWidgets, setDashboardWidgets] = useState<WidgetConfig[]>([]);
  const [isAnalysisOpen, setIsAnalysisOpen] = useState(false);
  const [analyzingWidget, setAnalyzingWidget] = useState<WidgetConfig | null>(null);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isExportModalOpen, setIsExportModalOpen] = useState(false);

  const dashboardRef = useRef<HTMLDivElement>(null);

  const templates = useMemo(() => generateTemplates(), []);
  const currentTemplate = useMemo(() => 
    templates.find(t => t.id === selectedTemplateId) || templates[0], 
    [templates, selectedTemplateId]
  );

  const { data, isStreaming, setIsStreaming, handleFileUpload } = useDataManager(currentTemplate.name);
  const semanticModel = useMemo(() => inferSemanticModel(data), [data]);

  // Sync with Template or LocalStorage
  useEffect(() => {
    const savedLayout = localStorage.getItem(`flashfusion_layout_${selectedTemplateId}`);
    if (savedLayout) {
      try {
        setDashboardWidgets(JSON.parse(savedLayout));
      } catch (e) {
        setDashboardWidgets(currentTemplate.widgets);
      }
    } else {
      setDashboardWidgets(currentTemplate.widgets);
    }
  }, [currentTemplate, selectedTemplateId]);

  // Persist Layout Changes
  useEffect(() => {
    if (dashboardWidgets.length > 0) {
      localStorage.setItem(`flashfusion_layout_${selectedTemplateId}`, JSON.stringify(dashboardWidgets));
    }
  }, [dashboardWidgets, selectedTemplateId]);

  const checkCollision = (id: string, x: number, y: number, w: number, h: number, widgets: WidgetConfig[]): boolean => {
    return widgets.some(other => {
      if (other.id === id) return false;
      return (
        x < other.x + other.w &&
        x + w > other.x &&
        y < other.y + other.h &&
        y + h > other.y
      );
    });
  };

  const handleWidgetGenerated = (newWidget: WidgetConfig) => {
    setDashboardWidgets(prev => {
      let placed = false;
      let y = 0;
      const widgetToPlace = { ...newWidget };
      // Simple vertical search for first available slot
      while (!placed && y < 50) {
        for (let x = 0; x <= GRID_SYSTEM.COLS - widgetToPlace.w; x++) {
           if (!checkCollision(widgetToPlace.id, x, y, widgetToPlace.w, widgetToPlace.h, prev)) {
             widgetToPlace.x = x;
             widgetToPlace.y = y;
             placed = true;
             break;
           }
        }
        y++;
      }
      return [...prev, widgetToPlace];
    });
  };

  const handleWidgetResize = useCallback((id: string, newW: number, newH: number) => {
    setDashboardWidgets(prev => {
      const target = prev.find(w => w.id === id);
      if (!target) return prev;
      if (target.x + newW > GRID_SYSTEM.COLS) return prev;
      if (checkCollision(id, target.x, target.y, newW, newH, prev)) return prev;
      return prev.map(w => w.id === id ? { ...w, w: newW, h: newH } : w);
    });
  }, []);

  const handleWidgetMove = useCallback((id: string, newX: number, newY: number) => {
    setDashboardWidgets(prev => {
      const target = prev.find(w => w.id === id);
      if (!target) return prev;
      if (newX < 0 || newX + target.w > GRID_SYSTEM.COLS || newY < 0) return prev;
      if (checkCollision(id, newX, newY, target.w, target.h, prev)) return prev;
      return prev.map(w => w.id === id ? { ...w, x: newX, y: newY } : w);
    });
  }, []);

  const handleWidgetUpdate = useCallback((id: string, updates: Partial<WidgetConfig>) => {
    setDashboardWidgets(prev => prev.map(w => w.id === id ? { ...w, ...updates } : w));
  }, []);

  const handleAnalyze = async (widget: WidgetConfig, currentData: any[]) => {
    setAnalyzingWidget(widget);
    setIsAnalysisOpen(true);
    setAnalysisResult(null);
    setIsAnalyzing(true);
    const result = await generateAnalysis(widget.title, currentData);
    setAnalysisResult(result);
    setIsAnalyzing(false);
  };

  // -- Export Logic --
  const processExport = async (config: ExportConfig) => {
    if (!dashboardRef.current) return;
    setIsExportModalOpen(false);

    // Calculate Scale from DPI (Base 96)
    const scale = config.dpi / 96;

    const canvas = await html2canvas(dashboardRef.current, {
      backgroundColor: '#020617',
      scale: scale,
      useCORS: true,
      logging: false,
    });

    const filename = `${currentTemplate.name.replace(/\s+/g, '_')}_${config.dpi}dpi`;

    if (config.format === 'PDF') {
      const doc = new jsPDF({
        orientation: config.orientation,
        unit: 'mm',
        format: config.paperSize
      });

      const pageWidth = doc.internal.pageSize.getWidth();
      const pageHeight = doc.internal.pageSize.getHeight();
      const margin = 10; // mm

      // Use JPEG if quality < 1 for better compression
      const isCompressed = config.quality < 1.0;
      const imgData = canvas.toDataURL(isCompressed ? 'image/jpeg' : 'image/png', config.quality);
      const imgProps = doc.getImageProperties(imgData);

      // Calculate constraints
      const availWidth = pageWidth - (margin * 2);
      const availHeight = pageHeight - (margin * 2) - 15; // Extra space for header

      const ratio = Math.min(availWidth / imgProps.width, availHeight / imgProps.height);
      const finalW = imgProps.width * ratio;
      const finalH = imgProps.height * ratio;

      const x = (pageWidth - finalW) / 2;
      const y = margin + 15; // Push down below header

      // Render Header
      if (config.includeTitle || config.includeDate) {
         doc.setFont('helvetica', 'bold');
         doc.setFontSize(11);
         doc.setTextColor(50, 50, 60);

         if (config.includeTitle) {
            doc.text(currentTemplate.name.toUpperCase(), margin, margin + 5);
         }

         if (config.includeDate) {
            doc.setFont('helvetica', 'normal');
            doc.setFontSize(9);
            doc.setTextColor(100, 100, 100);
            const dateStr = new Date().toLocaleDateString();
            const dateWidth = doc.getTextWidth(dateStr);
            doc.text(dateStr, pageWidth - margin - dateWidth, margin + 5);
         }

         // Add separator line
         doc.setDrawColor(200, 200, 200);
         doc.line(margin, margin + 8, pageWidth - margin, margin + 8);
      }

      doc.addImage(imgData, isCompressed ? 'JPEG' : 'PNG', x, y, finalW, finalH, undefined, isCompressed ? 'FAST' : 'NONE');
      doc.save(`${filename}.pdf`);

    } else {
      // Image Export (PNG/JPG)
      let finalCanvas = canvas;

      // If metadata requested for image, create composite canvas
      if (config.includeTitle || config.includeDate) {
         const padding = 40 * scale;
         const headerHeight = ((config.includeTitle ? 40 : 0) + (config.includeDate ? 30 : 0)) * scale + padding;

         const composite = document.createElement('canvas');
         composite.width = canvas.width;
         composite.height = canvas.height + headerHeight;
         const ctx = composite.getContext('2d');

         if (ctx) {
            // Fill Background
            ctx.fillStyle = '#020617';
            ctx.fillRect(0, 0, composite.width, composite.height);

            // Draw Original
            ctx.drawImage(canvas, 0, headerHeight);

            // Draw Metadata
            ctx.textBaseline = 'top';
            let currentY = padding / 2;

            if (config.includeTitle) {
               ctx.font = `900 ${32 * scale}px Inter, sans-serif`;
               ctx.fillStyle = '#ffffff';
               ctx.fillText(currentTemplate.name, padding, currentY);
               currentY += 40 * scale;
            }

            if (config.includeDate) {
               ctx.font = `500 ${16 * scale}px Inter, sans-serif`;
               ctx.fillStyle = '#94a3b8';
               ctx.fillText(`Snapshot: ${new Date().toLocaleDateString()}`, padding, currentY);
            }

            finalCanvas = composite;
         }
      }

      const mime = config.format === 'PNG' ? 'image/png' : 'image/jpeg';
      const ext = config.format === 'PNG' ? 'png' : 'jpg';

      const link = document.createElement('a');
      link.download = `${filename}.${ext}`;
      // Note: toDataURL quality argument is ignored for image/png
      link.href = finalCanvas.toDataURL(mime, config.quality);
      link.click();
    }
  };

  const handleQuickExport = (format: 'PNG' | 'PDF') => {
    processExport({
        format,
        includeTitle: true,
        includeDate: true,
        dpi: 72,
        quality: 1.0,
        orientation: 'landscape',
        paperSize: 'a4'
    });
  };

  return (
    <div className="flex h-screen overflow-hidden text-slate-200 bg-cyber selection:bg-fuchsia-500/30">
      <ExportModal isOpen={isExportModalOpen} onClose={() => setIsExportModalOpen(false)} onConfirm={processExport} />

      <Sidebar 
        activeTab={activeTab}
        setActiveTab={setActiveTab}
        isSidebarOpen={isSidebarOpen}
        onImport={handleFileUpload}
        onExport={() => setIsExportModalOpen(true)}
        toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)}
      />

      <main className="flex-1 flex flex-col overflow-hidden relative">
        {/* Global Control Header */}
        <header className="h-20 px-8 flex items-center justify-between shrink-0 glass-panel border-b border-white/5 z-40">
          <div className="flex items-center gap-6">
             <div className="flex flex-col">
               <h1 className="text-2xl font-black text-transparent bg-clip-text bg-gradient-to-r from-white to-slate-400 uppercase tracking-tighter leading-none">FlashFusion</h1>
               <div className="flex items-center gap-2 mt-1">
                 <span className="text-[10px] font-bold text-fuchsia-500 uppercase tracking-widest">by IntInc</span>
                 <div className="w-1 h-1 rounded-full bg-slate-600"></div>
                 <span className="text-[10px] font-medium text-slate-500 uppercase tracking-widest">{currentTemplate.name}</span>
               </div>
             </div>
          </div>

          <div className="flex items-center gap-4">
             <div className="flex items-center gap-2 px-4 py-2 bg-white/5 rounded-full border border-white/5">
                <div className={`w-2 h-2 rounded-full ${isStreaming ? 'bg-emerald-500 animate-pulse shadow-[0_0_8px_#10b981]' : 'bg-slate-600'}`} />
                <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                  {isStreaming ? "Simulating Intelligence" : "Static Engine"}
                </span>
             </div>

             {/* Quick Export Buttons */}
             <div className="flex items-center bg-white/5 rounded-full p-1 border border-white/10 shadow-inner">
                <button 
                  onClick={() => handleQuickExport('PNG')}
                  className="px-4 py-1.5 text-[10px] font-black uppercase tracking-tighter text-slate-400 hover:text-white transition-all hover:bg-white/5 rounded-full"
                >
                  PNG
                </button>
                <button 
                  onClick={() => handleQuickExport('PDF')}
                  className="px-4 py-1.5 text-[10px] font-black uppercase tracking-tighter text-slate-400 hover:text-white transition-all hover:bg-white/5 rounded-full"
                >
                  PDF
                </button>
             </div>

             <button 
                onClick={() => setMode(mode === EditMode.SAFE ? EditMode.PRO : EditMode.SAFE)}
                className={`flex items-center gap-2 px-6 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all shadow-lg ${
                  mode === EditMode.PRO 
                    ? 'bg-fuchsia-600 text-white shadow-fuchsia-600/30 hover:bg-fuchsia-500' 
                    : 'bg-white/5 text-slate-400 border border-white/10 hover:border-white/20 hover:text-white'
                }`}
             >
                <Icons.Settings />
                {mode === EditMode.PRO ? "Save Layout" : "Edit Layout"}
             </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto custom-scrollbar relative p-6 lg:p-12">
          {activeTab === 'dashboard' && (
            <div className="max-w-screen-2xl mx-auto flex flex-col items-center">

              {/* Studio-Grade AI Input */}
              <div className="w-full max-w-4xl mb-16 relative z-30">
                <MagicBar 
                  onWidgetGenerated={handleWidgetGenerated} 
                  semanticModel={semanticModel} 
                  compact={dashboardWidgets.length > 0}
                />
              </div>

              {/* Zero-State Onboarding */}
              {dashboardWidgets.length === 0 && (
                <div className="text-center py-20 animate-in fade-in zoom-in duration-1000">
                   <div className="mb-8 inline-flex p-6 rounded-[2rem] bg-gradient-to-br from-fuchsia-600/20 to-indigo-600/20 text-fuchsia-400 border border-fuchsia-500/20 shadow-2xl shadow-fuchsia-500/10">
                      <Icons.Sparkles />
                   </div>
                   <h1 className="text-6xl font-black text-white tracking-tighter mb-6 drop-shadow-2xl">FlashFusion</h1>
                   <p className="text-slate-400 font-medium mb-12 max-w-xl mx-auto leading-relaxed text-lg">
                     The conversational intelligence studio. <br/> Describe your data story, and we'll build the dashboard.
                   </p>
                   <div className="flex justify-center gap-4">
                      <button onClick={() => setDashboardWidgets(currentTemplate.widgets)} className="px-8 py-4 bg-white text-slate-950 rounded-2xl font-black uppercase tracking-tighter hover:bg-slate-200 transition-all shadow-xl hover:scale-105">Load Blueprint</button>
                      <button onClick={() => setIsStreaming(true)} className="px-8 py-4 bg-white/5 border border-white/10 text-white rounded-2xl font-black uppercase tracking-tighter hover:bg-white/10 transition-all hover:scale-105">Watch Simulation</button>
                   </div>
                </div>
              )}

              {/* High-Fidelity Responsive Grid */}
              <div 
                ref={dashboardRef} 
                className="grid w-full pb-64 relative transition-all duration-500"
                style={{
                  gridTemplateColumns: `repeat(${GRID_SYSTEM.COLS}, minmax(0, 1fr))`,
                  gap: `${GRID_SYSTEM.GAP_PX}px`,
                  gridAutoRows: `${GRID_SYSTEM.ROW_HEIGHT_PX}px`
                }}
              >
                {dashboardWidgets.map(w => (
                  <WidgetContainer 
                    key={w.id} 
                    widget={w} 
                    mode={mode} 
                    data={data} 
                    onAnalyze={handleAnalyze}
                    onResize={handleWidgetResize}
                    onMove={handleWidgetMove}
                    onUpdate={handleWidgetUpdate}
                  />
                ))}
              </div>
            </div>
          )}

          {activeTab === 'catalog' && (
             <div className="max-w-screen-xl mx-auto">
               <div className="flex items-end justify-between mb-12">
                 <div>
                   <h1 className="text-4xl font-black text-white uppercase tracking-tighter">Blueprint Catalog</h1>
                   <p className="text-slate-500 font-bold mt-2 tracking-wide uppercase text-[10px]">Curated by FlashFusion Strategy</p>
                 </div>
               </div>
               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                 {templates.map(t => (
                   <button 
                    key={t.id} 
                    onClick={() => { setSelectedTemplateId(t.id); setActiveTab('dashboard'); }}
                    className="glass-panel p-8 rounded-[2.5rem] border border-white/5 hover:border-fuchsia-500/30 text-left transition-all group relative overflow-hidden"
                   >
                     <div className="absolute top-0 right-0 w-32 h-32 bg-fuchsia-600/5 blur-3xl group-hover:bg-fuchsia-600/10 transition-all" />
                     <span className="text-[10px] font-black text-fuchsia-400 uppercase tracking-widest">{t.category}</span>
                     <h3 className="text-2xl font-black text-white mt-2 group-hover:text-fuchsia-300 transition-colors">{t.name}</h3>
                     <p className="text-slate-400 text-sm mt-4 leading-relaxed line-clamp-2">{t.description}</p>
                     <div className="mt-8 flex items-center justify-between">
                        <span className="px-3 py-1 bg-white/5 border border-white/10 rounded-full text-[9px] font-black uppercase text-slate-500">{t.difficulty}</span>
                        <div className="text-fuchsia-500 opacity-0 group-hover:opacity-100 transition-all translate-x-4 group-hover:translate-x-0">
                          <Icons.Sparkles />
                        </div>
                     </div>
                   </button>
                 ))}
               </div>
             </div>
          )}
        </div>

        <AnalysisPanel 
          isOpen={isAnalysisOpen} 
          onClose={() => setIsAnalysisOpen(false)} 
          widget={analyzingWidget}
          analysis={analysisResult}
          isLoading={isAnalyzing}
        />
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';

export interface ExportConfig {
  format: 'PNG' | 'JPG' | 'PDF';
  includeTitle: boolean;
  includeDate: boolean;
  dpi: number;
  quality: number;
  orientation: 'landscape' | 'portrait';
  paperSize: 'a4' | 'letter' | 'legal';
}

interface ExportModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (config: ExportConfig) => void;
}

export const ExportModal: React.FC<ExportModalProps> = ({ isOpen, onClose, onConfirm }) => {
  const [config, setConfig] = useState<ExportConfig>({ 
    format: 'PNG', 
    includeTitle: true, 
    includeDate: true,
    dpi: 144,
    quality: 0.9,
    orientation: 'landscape',
    paperSize: 'a4'
  });

  const [useCustomDpi, setUseCustomDpi] = useState(false);

  if (!isOpen) return null;

  const handleDpiSelect = (val: number | 'custom') => {
    if (val === 'custom') {
      setUseCustomDpi(true);
    } else {
      setUseCustomDpi(false);
      setConfig({ ...config, dpi: val });
    }
  };

  const getQualityLabel = (q: number) => {
    if (q >= 0.9) return 'Maximum (Larger File)';
    if (q >= 0.7) return 'High';
    if (q >= 0.5) return 'Medium';
    return 'Low (Smaller File)';
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-950/80 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="w-[32rem] bg-slate-900 border border-white/10 rounded-[2rem] p-8 shadow-2xl">
         <h3 className="text-xl font-black text-white uppercase tracking-tighter mb-6">Export Snapshot</h3>

         <div className="space-y-6 mb-8 max-h-[60vh] overflow-y-auto custom-scrollbar pr-2">
            {/* Format Selection */}
            <div className="space-y-2">
               <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Format</label>
               <div className="flex gap-2">
                  {(['PNG', 'JPG', 'PDF'] as const).map(f => (
                    <button 
                      key={f}
                      onClick={() => setConfig({ ...config, format: f })}
                      className={`flex-1 py-2 rounded-xl text-xs font-bold transition-all ${config.format === f ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-600/20' : 'bg-white/5 text-slate-400 hover:bg-white/10'}`}
                    >
                      {f}
                    </button>
                  ))}
               </div>
            </div>

            {/* PDF Specific Settings */}
            {config.format === 'PDF' && (
              <div className="p-4 bg-white/5 rounded-2xl border border-white/5 space-y-4 animate-in fade-in slide-in-from-top-2 duration-300">
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Page Orientation</label>
                   <div className="flex gap-2">
                      {(['landscape', 'portrait'] as const).map(o => (
                        <button 
                          key={o}
                          onClick={() => setConfig({ ...config, orientation: o })}
                          className={`flex-1 py-2 rounded-lg text-[10px] font-bold uppercase tracking-wide transition-all ${config.orientation === o ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}
                        >
                          {o}
                        </button>
                      ))}
                   </div>
                </div>
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Paper Size</label>
                   <div className="flex gap-2">
                      {(['a4', 'letter', 'legal'] as const).map(s => (
                        <button 
                          key={s}
                          onClick={() => setConfig({ ...config, paperSize: s })}
                          className={`flex-1 py-2 rounded-lg text-[10px] font-bold uppercase tracking-wide transition-all ${config.paperSize === s ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}
                        >
                          {s}
                        </button>
                      ))}
                   </div>
                </div>
              </div>
            )}

            {/* Metadata Toggle */}
            <div className="space-y-2">
               <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Metadata</label>
               <div className="grid grid-cols-2 gap-3">
                 <div className="flex items-center justify-between p-3 bg-white/5 rounded-xl border border-white/5 cursor-pointer hover:bg-white/10 transition-colors" onClick={() => setConfig({...config, includeTitle: !config.includeTitle})}>
                    <span className="text-xs font-bold text-slate-300">Include Title</span>
                    <div className={`w-4 h-4 rounded border flex items-center justify-center ${config.includeTitle ? 'bg-fuchsia-600 border-fuchsia-600' : 'border-slate-600'}`}>
                      {config.includeTitle && <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>}
