              {/* Zero-State Onboarding */}
              {dashboardWidgets.length === 0 && (
                <div className="text-center py-20 animate-in fade-in zoom-in duration-1000">
                   <div className="mb-8 inline-flex p-6 rounded-[2rem] bg-gradient-to-br from-fuchsia-600/20 to-indigo-600/20 text-fuchsia-400 border border-fuchsia-500/20 shadow-2xl shadow-fuchsia-500/10">
                      <Icons.Sparkles />
                   </div>
                   <h1 className="text-6xl font-black text-white tracking-tighter mb-6 drop-shadow-2xl">FlashFusion</h1>
