                }`}
             >
                <Icons.Settings />
                {mode === EditMode.PRO ? "Done" : "Edit"}
             </button>
          </div>
        </header>

        {/* Global Filter Bar */}
        <GlobalFilterBar 
           semanticModel={semanticModel} 
           data={data} 
           filters={globalFilters} 
           onFilterChange={handleGlobalFilterChange} 
        />

        <div className="flex-1 overflow-y-auto custom-scrollbar relative p-6 lg:p-8">
          {activeTab === 'dashboard' && (
            <div className="max-w-[1920px] mx-auto flex flex-col items-center">

              {/* Magic Bar (Mobile / Zero State) */}
              <div className="lg:hidden w-full mb-8">
                 <MagicBar onWidgetGenerated={handleWidgetGenerated} semanticModel={semanticModel} />
              </div>

              {/* Zero-State Onboarding */}
              {dashboardWidgets.length === 0 && (
                <div className="text-center py-32 animate-in fade-in zoom-in duration-500">
                   <div className="mb-6 inline-flex p-5 rounded-[2rem] bg-white/5 text-fuchsia-400 border border-white/10">
                      <Icons.Sparkles />
                   </div>
                   <h1 className="text-4xl font-black text-white tracking-tighter mb-4">Start your story</h1>
                   <p className="text-slate-500 font-medium mb-8 max-w-md mx-auto">
                     Use the command bar above to generate insights, or load a blueprint to get started.
                   </p>
                   <button onClick={() => setDashboardWidgets(currentTemplate.widgets)} className="px-6 py-3 bg-white text-slate-950 rounded-xl font-bold uppercase tracking-tight hover:bg-slate-200 transition-all">Load Blueprint</button>
                </div>
              )}

              {/* High-Fidelity Responsive Grid */}
              <div 
                ref={dashboardRef} 
                className="grid w-full pb-32 relative transition-all duration-300"
                style={{
                  gridTemplateColumns: `repeat(${GRID_SYSTEM.COLS}, minmax(0, 1fr))`,
                  gap: `${GRID_SYSTEM.GAP_PX}px`,
                  gridAutoRows: `${GRID_SYSTEM.ROW_HEIGHT_PX}px`
                }}
              >
                {dashboardWidgets.map(w => (
                  <WidgetContainer 
                    key={w.id} 
                    widget={w} 
                    mode={mode} 
                    data={filteredData} // Pass filtered data
                    onAnalyze={handleAnalyze}
                    onResize={handleWidgetResize}
                    onMove={handleWidgetMove}
                    onUpdate={handleWidgetUpdate}
                    onMaximize={setFocusedWidget} // Enable Focus Mode
                  />
                ))}
              </div>
            </div>
          )}

          {activeTab === 'catalog' && (
             <div className="max-w-screen-xl mx-auto">
               <h1 className="text-3xl font-black text-white uppercase tracking-tighter mb-8">Blueprints</h1>
               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                 {templates.map(t => (
                   <button 
                    key={t.id} 
                    onClick={() => { setSelectedTemplateId(t.id); setActiveTab('dashboard'); }}
                    className="glass-panel p-6 rounded-3xl border border-white/5 hover:border-fuchsia-500/30 text-left transition-all group relative overflow-hidden bg-slate-900/40"
                   >
                     <div className="absolute top-0 right-0 w-24 h-24 bg-fuchsia-600/5 blur-3xl group-hover:bg-fuchsia-600/10 transition-all" />
                     <span className="text-[9px] font-black text-fuchsia-400 uppercase tracking-widest">{t.category}</span>
                     <h3 className="text-xl font-black text-white mt-1 group-hover:text-fuchsia-300 transition-colors">{t.name}</h3>
                     <p className="text-slate-400 text-xs mt-3 leading-relaxed line-clamp-2">{t.description}</p>
                   </button>
                 ))}
               </div>
             </div>
          )}
        </div>

        <AnalysisPanel 
          isOpen={isAnalysisOpen} 
          onClose={() => setIsAnalysisOpen(false)} 
          widget={analyzingWidget}
          analysis={analysisResult}
          isLoading={isAnalyzing}
        />
      </main>
    </div>
  );
};

export default App;

