/**
 * OmniGen Type Definitions
 * 
 * This file contains all shared interfaces and constants for the application.
 */

/**
 * Grid Layout Configuration
 * Corresponds to Tailwind classes: grid-cols-12, gap-6 (24px), auto-rows-[100px]
 */
export const GRID_SYSTEM = {
  COLS: 12,
  ROW_HEIGHT_PX: 100,
  GAP_PX: 24, // tailwind gap-6
};

export enum VizType {
  TABLE = 'table',
  PIVOT = 'pivot',
  TIME_SERIES = 'time-series',
  FUNNEL = 'funnel',
  COHORT = 'cohort',
  GEO_MAP = 'geo-map',
  SANKEY = 'sankey',
  NETWORK = 'network',
  BAR = 'bar',
  COLUMN = 'column',
  STACKED_BAR = 'stacked-bar',
  SCATTER = 'scatter',
  HISTOGRAM = 'histogram',
  HEATMAP = 'heatmap',
  TREEMAP = 'treemap',
  BOX_PLOT = 'box-plot',
  GAUGE = 'gauge',
  WATERFALL = 'waterfall',
  KPI_CARD = 'kpi-card'
}

/**
 * Represents the inferred semantic layer of the dataset.
 * Used by the AI to generate relevant visualizations.
 */
export interface SemanticModel {
  entities: { name: string; description: string; likely_keys: string[]; example_fields: string[] }[];
  metrics: { name: string; definition: string; aggregation: string; grain: string; caveats?: string }[];
  dimensions: { name: string; type: string; examples: string[] }[];
  relationships: { from_entity: string; to_entity: string; join_keys: string[]; join_type: string; confidence: number }[];
  kpis: { name: string; metric: string; goal_direction: 'up' | 'down'; target: string; alert_threshold: string }[];
  glossary: { term: string; meaning: string; synonyms: string[] }[];
  quality_flags: { issue: string; impacted_fields: string[]; severity: 'low' | 'medium' | 'high'; suggested_fix: string }[];
  assumptions: { assumption: string; impact: string; confirm_by: string }[];
}

/**
 * Configuration for a single dashboard widget.
 * x, y, w, h are in Grid Units (not pixels).
 */
export interface WidgetConfig {
  id: string;
  type: VizType;
  title: string;
  metric?: string;             // The primary numeric value to plot
  dimension?: string;          // The primary grouping key (X-Axis)
  secondaryDimension?: string; // The secondary grouping key (Legend/Y-Axis)
  filter?: Record<string, any>;
  w: number; // Width in grid columns (1-12)
  h: number; // Height in grid rows
  x: number; // Column start (0-11)
  y: number; // Row start
}

export interface DashboardTemplate {
  id: string;
  name: string;
  category: string;
  description: string;
  widgets: WidgetConfig[];
  difficulty: 'Basic' | 'Advanced';
}

export interface AnalysisResult {
  summary: string;
  drivers: string[];
  recommendations: string[];
  sentiment: 'positive' | 'negative' | 'neutral';
  marketContext?: string;
  sources?: { title: string; uri: string }[];
}

import { SemanticModel } from '../types';

/**
 * Infers a semantic model from raw dataset.
 * Updated to be domain-agnostic for the "Data Observatory" pivot.
 * 
 * @param data - The raw array of data objects.
 * @returns A structured SemanticModel.
 */
export const inferSemanticModel = (data: any[]): SemanticModel => {
  if (data.length === 0) return {
      entities: [], metrics: [], dimensions: [], relationships: [], kpis: [], glossary: [], quality_flags: [], assumptions: []
  };

  const sample = data[0];
  const keys = Object.keys(sample);

  // Basic heuristic inference
  const numericKeys = keys.filter(k => typeof sample[k] === 'number');
  const stringKeys = keys.filter(k => typeof sample[k] === 'string');
  const dateKey = stringKeys.find(k => k.toLowerCase().includes('date') || k.toLowerCase().includes('time'));
  const categoryKey = stringKeys.find(k => !k.includes('date') && !k.includes('id')) || stringKeys[0];

  const metrics = numericKeys.map(key => ({
      name: key.charAt(0).toUpperCase() + key.slice(1).replace(/_/g, ' '),
      definition: `Sum of ${key}`,
      aggregation: 'SUM',
      grain: 'Row'
  }));

  const dimensions = stringKeys.map(key => ({
      name: key.charAt(0).toUpperCase() + key.slice(1).replace(/_/g, ' '),
      type: key.includes('date') ? 'Temporal' : 'Categorical',
      examples: []
  }));

  return {
    entities: [
      { name: 'Record', description: 'Single data point', likely_keys: ['id'], example_fields: keys }
    ],
    metrics: metrics,
    dimensions: dimensions,
    relationships: [],
    kpis: metrics.slice(0, 3).map(m => ({
        name: `Avg ${m.name}`,
        metric: m.name,
        goal_direction: 'up',
        target: 'auto',
        alert_threshold: 'auto'
    })),
    glossary: [
      { term: 'Observation', meaning: 'A single recorded event or measurement', synonyms: ['Row', 'Entry'] }
    ],
    quality_flags: [],
    assumptions: []
  };
};

