import React, { useState, useMemo, useRef } from 'react';
import { WidgetConfig, VizType, GRID_SYSTEM } from '../types';
import { ChartRenderer } from './ChartRenderer';
import { Icons } from '../constants';

const DRILL_HIERARCHY = ['region', 'category', 'date'];

interface WidgetContainerProps {
  widget: WidgetConfig;
  isLocked: boolean;
  data: any[];
  onAnalyze: (widget: WidgetConfig, currentData: any[]) => void;
  onResize: (id: string, w: number, h: number) => void;
  onMove: (id: string, x: number, y: number) => void;
  onUpdate: (id: string, updates: Partial<WidgetConfig>) => void;
  onMaximize?: (widget: WidgetConfig) => void;
}

export const WidgetContainer: React.FC<WidgetContainerProps> = ({ widget, isLocked, data, onAnalyze, onResize, onMove, onUpdate, onMaximize }) => {
  const [drillPath, setDrillPath] = useState<string[]>([]);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isResizing, setIsResizing] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const [showSettings, setShowSettings] = useState(false);

  const currentLevelIndex = Math.min(drillPath.length, DRILL_HIERARCHY.length - 1);
  const currentLevel = DRILL_HIERARCHY[currentLevelIndex];
  const canDrill = drillPath.length < DRILL_HIERARCHY.length;

  const dataKeys = useMemo(() => data.length > 0 ? Object.keys(data[0]) : [], [data]);

  const filteredData = useMemo(() => {
    let result = data;
    drillPath.forEach((val, idx) => {
      const dim = DRILL_HIERARCHY[idx];
      result = result.filter(item => String(item[dim]) === val);
    });
    return result;
  }, [data, drillPath]);

  const handleDrill = (val: string) => {
    if (drillPath.length < DRILL_HIERARCHY.length) {
      setDrillPath([...drillPath, val]);
    }
  };

  const calculateGridCoords = (clientX: number, clientY: number, parent: HTMLElement) => {
    const rect = parent.getBoundingClientRect();
    const relativeX = clientX - rect.left;
    const relativeY = clientY - rect.top;

    const colWidth = (rect.width - (GRID_SYSTEM.COLS - 1) * GRID_SYSTEM.GAP_PX) / GRID_SYSTEM.COLS;
    const cellWidth = colWidth + GRID_SYSTEM.GAP_PX;
    const cellHeight = GRID_SYSTEM.ROW_HEIGHT_PX + GRID_SYSTEM.GAP_PX;

    return {
      x: Math.round(relativeX / cellWidth),
      y: Math.round(relativeY / cellHeight)
    };
  };

  const handleResizeStart = (e: React.MouseEvent) => {
    if (isLocked) return;
    e.preventDefault(); e.stopPropagation();
    setIsResizing(true);

    const parent = containerRef.current?.offsetParent as HTMLElement;
    if (!parent) return;

    const handleMouseMove = (moveEvent: MouseEvent) => {
      const coords = calculateGridCoords(moveEvent.clientX, moveEvent.clientY, parent);
      const newW = Math.max(2, coords.x - widget.x);
      const newH = Math.max(1, coords.y - widget.y);
      if (newW !== widget.w || newH !== widget.h) {
        onResize(widget.id, newW, newH);
      }
    };

    const handleMouseUp = () => {
      setIsResizing(false);
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };

    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  };

  const handleDragStart = (e: React.MouseEvent) => {
    if (isLocked) return;
    if ((e.target as HTMLElement).closest('button') || (e.target as HTMLElement).closest('select')) return;

    e.preventDefault();
    setIsDragging(true);

    const parent = containerRef.current?.offsetParent as HTMLElement;
    if (!parent) return;

    const rect = containerRef.current!.getBoundingClientRect();
    const offsetX = e.clientX - rect.left;
    const offsetY = e.clientY - rect.top;

    const handleMouseMove = (moveEvent: MouseEvent) => {
      const coords = calculateGridCoords(moveEvent.clientX - offsetX, moveEvent.clientY - offsetY, parent);
      if (coords.x !== widget.x || coords.y !== widget.y) {
        onMove(widget.id, coords.x, coords.y);
      }
    };

    const handleMouseUp = () => {
      setIsDragging(false);
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };

    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  };

  return (
    <div 
      ref={containerRef}
      className={`glass-panel rounded-3xl flex flex-col transition-all duration-200 relative group/widget bg-slate-900/40 backdrop-blur-md border border-white/5 
        ${isResizing || isDragging ? 'z-50 border-fuchsia-500 shadow-2xl scale-[1.01]' : 'hover:border-white/10 hover:bg-slate-900/60 shadow-lg'}
        ${!isLocked ? 'cursor-grab active:cursor-grabbing border-white/10 ring-1 ring-white/5' : ''}
      `}
      style={{ 
        gridColumn: `span ${widget.w}`, 
        gridRow: `span ${widget.h}`,
        gridColumnStart: widget.x + 1,
        gridRowStart: widget.y + 1,
        userSelect: isResizing || isDragging ? 'none' : 'auto'
      }}
      onMouseDown={handleDragStart}
    >
      <div className="px-5 py-4 flex items-center justify-between pointer-events-none">
        <div className="flex flex-col">
          <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-0.5">{widget.type}</span>
          <span className="text-xs font-black text-slate-200 tracking-tight uppercase truncate max-w-[150px]">{widget.title}</span>
        </div>

        <div className="flex items-center gap-1 opacity-0 group-hover/widget:opacity-100 transition-all duration-200 pointer-events-auto">
          {onMaximize && (
            <button
               onClick={(e) => { e.stopPropagation(); onMaximize(widget); }}
               className="p-1.5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-colors"
               title="Focus Mode"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" /></svg>
            </button>
          )}
          <button
             onClick={(e) => { e.stopPropagation(); onAnalyze(widget, filteredData); }}
             className="p-1.5 hover:bg-fuchsia-500/10 rounded-lg text-fuchsia-400 transition-colors"
             title="AI Analysis"
          >
            <Icons.Sparkles />
          </button>
          {!isLocked && (
             <button 
                onClick={(e) => { e.stopPropagation(); setShowSettings(!showSettings); }}
                className="p-1.5 hover:bg-white/10 rounded-lg text-slate-500 hover:text-white transition-colors"
             >
                <Icons.Settings />
             </button>
          )}
        </div>
      </div>

      <div className="flex-1 px-5 pb-5 pt-0 relative overflow-hidden" onMouseDown={(e) => e.stopPropagation()}>
        <ChartRenderer 
          config={widget} 
          data={filteredData} 
          onDrill={handleDrill} 
          currentLevel={currentLevel} 
          drillPath={drillPath} 
          canDrill={canDrill}
        />
      </div>

      {showSettings && (
        <div className="absolute inset-0 bg-slate-900/98 z-50 p-6 rounded-3xl animate-in fade-in zoom-in-95 duration-200" onMouseDown={e => e.stopPropagation()}>
           <div className="flex justify-between items-center mb-6">
              <h4 className="font-black text-white uppercase tracking-tighter text-sm">Widget Settings</h4>
              <button onClick={() => setShowSettings(false)} className="text-slate-500 hover:text-white"><Icons.Settings /></button>
           </div>
           <div className="space-y-4">
              <div className="space-y-1">
                 <label className="text-[9px] font-black text-slate-500 uppercase">Focus Dimension</label>
                 <select 
                    value={widget.dimension || ''}
                    onChange={(e) => onUpdate(widget.id, { dimension: e.target.value })}
                    className="w-full bg-black/50 border border-white/10 rounded-xl p-2.5 text-xs text-white focus:border-fuchsia-500 outline-none"
                 >
                    <option value="">Default</option>
                    {dataKeys.map(k => <option key={k} value={k}>{k}</option>)}
                 </select>
              </div>
           </div>
        </div>
      )}

      {!isLocked && (
        <div 
          onMouseDown={handleResizeStart}
          className="absolute bottom-2 right-2 w-6 h-6 cursor-se-resize z-20 flex items-center justify-center text-fuchsia-500 opacity-0 group-hover/widget:opacity-100 transition-opacity"
        >
          <svg className="w-4 h-4 transform rotate-45" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 5v14m7-14v14" /></svg>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect, useCallback, useRef } from 'react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';
import { Icons } from './constants';
import { WidgetConfig, AnalysisResult, GRID_SYSTEM } from './types';
import { inferSemanticModel } from './services/semanticEngine';
import { generateTemplates } from './services/templateService';
import { generateAnalysis } from './services/aiService';
import { WidgetContainer } from './components/WidgetContainer';
import { Sidebar } from './components/Sidebar';
import { MagicBar } from './components/MagicBar';
import { AnalysisPanel } from './components/AnalysisPanel';
import { useDataManager } from './hooks/useDataManager';
import { ExportModal, ExportConfig } from './components/ExportModal';
import { GlobalFilterBar } from './components/GlobalFilterBar';
import { ChartRenderer } from './components/ChartRenderer';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'library' | 'about'>('dashboard');
  const [isLocked, setIsLocked] = useState(true);
  const [selectedTemplateId, setSelectedTemplateId] = useState('personal-health');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const [dashboardWidgets, setDashboardWidgets] = useState<WidgetConfig[]>([]);
  const [isAnalysisOpen, setIsAnalysisOpen] = useState(false);
  const [analyzingWidget, setAnalyzingWidget] = useState<WidgetConfig | null>(null);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isExportModalOpen, setIsExportModalOpen] = useState(false);

  const [globalFilters, setGlobalFilters] = useState<Record<string, string>>({});
  const [focusedWidget, setFocusedWidget] = useState<WidgetConfig | null>(null);

  const dashboardRef = useRef<HTMLDivElement>(null);

  const templates = useMemo(() => generateTemplates(), []);
  const currentTemplate = useMemo(() => 
    templates.find(t => t.id === selectedTemplateId) || templates[0], 
    [templates, selectedTemplateId]
  );

  const { data, isStreaming, setIsStreaming, handleFileUpload } = useDataManager(currentTemplate.name);
  const semanticModel = useMemo(() => inferSemanticModel(data), [data]);

  // Apply Global Filters to Data
  const filteredData = useMemo(() => {
    let result = data;
    Object.entries(globalFilters).forEach(([key, value]) => {
        if (!value) return;
        result = result.filter(item => {
           const itemKey = Object.keys(item).find(k => k.toLowerCase() === key.toLowerCase());
           return itemKey ? String(item[itemKey]) === value : true;
        });
    });
    return result;
  }, [data, globalFilters]);

  const handleGlobalFilterChange = (key: string, value: string) => {
      setGlobalFilters(prev => ({ ...prev, [key]: value }));
  };

  useEffect(() => {
    const savedLayout = localStorage.getItem(`flashfusion_layout_${selectedTemplateId}`);
    if (savedLayout) {
      try {
        setDashboardWidgets(JSON.parse(savedLayout));
      } catch (e) {
        setDashboardWidgets(currentTemplate.widgets);
      }
    } else {
      setDashboardWidgets(currentTemplate.widgets);
    }
  }, [currentTemplate, selectedTemplateId]);

  useEffect(() => {
    if (dashboardWidgets.length > 0) {
      localStorage.setItem(`flashfusion_layout_${selectedTemplateId}`, JSON.stringify(dashboardWidgets));
    }
  }, [dashboardWidgets, selectedTemplateId]);

  const checkCollision = (id: string, x: number, y: number, w: number, h: number, widgets: WidgetConfig[]): boolean => {
    return widgets.some(other => {
      if (other.id === id) return false;
      return (
        x < other.x + other.w &&
        x + w > other.x &&
        y < other.y + other.h &&
        y + h > other.y
      );
    });
  };

  const handleWidgetGenerated = (newWidget: WidgetConfig) => {
    setDashboardWidgets(prev => {
      let placed = false;
      let y = 0;
      const widgetToPlace = { ...newWidget };
      while (!placed && y < 50) {
        for (let x = 0; x <= GRID_SYSTEM.COLS - widgetToPlace.w; x++) {
           if (!checkCollision(widgetToPlace.id, x, y, widgetToPlace.w, widgetToPlace.h, prev)) {
             widgetToPlace.x = x;
             widgetToPlace.y = y;
             placed = true;
             break;
           }
        }
        y++;
      }
      return [...prev, widgetToPlace];
    });
  };

  const handleWidgetResize = useCallback((id: string, newW: number, newH: number) => {
    setDashboardWidgets(prev => {
      const target = prev.find(w => w.id === id);
      if (!target) return prev;
      if (target.x + newW > GRID_SYSTEM.COLS) return prev;
      if (checkCollision(id, target.x, target.y, newW, newH, prev)) return prev;
      return prev.map(w => w.id === id ? { ...w, w: newW, h: newH } : w);
    });
  }, []);

  const handleWidgetMove = useCallback((id: string, newX: number, newY: number) => {
    setDashboardWidgets(prev => {
      const target = prev.find(w => w.id === id);
      if (!target) return prev;
      if (newX < 0 || newX + target.w > GRID_SYSTEM.COLS || newY < 0) return prev;
      if (checkCollision(id, newX, newY, target.w, target.h, prev)) return prev;
      return prev.map(w => w.id === id ? { ...w, x: newX, y: newY } : w);
    });
  }, []);

  const handleWidgetUpdate = useCallback((id: string, updates: Partial<WidgetConfig>) => {
    setDashboardWidgets(prev => prev.map(w => w.id === id ? { ...w, ...updates } : w));
  }, []);

  const handleAnalyze = async (widget: WidgetConfig, currentData: any[]) => {
    setAnalyzingWidget(widget);
    setIsAnalysisOpen(true);
    setAnalysisResult(null);
    setIsAnalyzing(true);
    const result = await generateAnalysis(widget.title, currentData);
    setAnalysisResult(result);
    setIsAnalyzing(false);
  };

  const processExport = async (config: ExportConfig) => {
    if (!dashboardRef.current) return;
    setIsExportModalOpen(false);
    const scale = config.dpi / 96;
    const canvas = await html2canvas(dashboardRef.current, {
      backgroundColor: '#020617',
      scale: scale,
      useCORS: true,
      logging: false,
    });
    const filename = `${currentTemplate.name.replace(/\s+/g, '_')}_${config.dpi}dpi`;
    const link = document.createElement('a');
    link.download = `${filename}.png`;
    link.href = canvas.toDataURL('image/png');
    link.click();
  };

  return (
    <div className="flex h-screen overflow-hidden text-slate-200 bg-cyber selection:bg-fuchsia-500/30 font-inter">
      <ExportModal 
        isOpen={isExportModalOpen} 
        onClose={() => setIsExportModalOpen(false)} 
        onConfirm={processExport} 
        contentDimensions={dashboardRef.current ? { 
            width: dashboardRef.current.scrollWidth, 
            height: dashboardRef.current.scrollHeight 
        } : undefined}
      />

      {focusedWidget && (
        <div className="fixed inset-0 z-[100] bg-slate-950/90 backdrop-blur-xl flex flex-col animate-in fade-in duration-200">
           <div className="flex items-center justify-between px-8 py-6 border-b border-white/10">
              <div className="flex flex-col">
                  <span className="text-xs font-black text-slate-500 uppercase tracking-widest mb-1">{focusedWidget.type} Focus</span>
                  <h2 className="text-2xl font-black text-white">{focusedWidget.title}</h2>
              </div>
              <button 
                onClick={() => setFocusedWidget(null)}
                className="p-3 bg-white/10 hover:bg-white/20 rounded-full text-white transition-colors"
              >
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
           </div>
           <div className="flex-1 p-12 overflow-hidden">
               <div className="w-full h-full bg-slate-900/50 rounded-[2rem] border border-white/5 p-8 shadow-2xl relative">
                   <ChartRenderer 
                     config={focusedWidget} 
                     data={filteredData}
                     onDrill={() => {}}
                     currentLevel="none"
                     drillPath={[]}
                     canDrill={false}
                   />
               </div>
           </div>
        </div>
      )}

      <Sidebar 
        activeTab={activeTab}
        setActiveTab={setActiveTab}
        isSidebarOpen={isSidebarOpen}
        onImport={handleFileUpload}
        onExport={() => setIsExportModalOpen(true)}
        toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)}
      />

      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-16 px-6 flex items-center justify-between shrink-0 glass-panel border-b border-white/5 z-40 bg-slate-900/60 backdrop-blur-xl">
          <div className="flex items-center gap-6 flex-1">
             <div className="flex items-center gap-3">
                <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-fuchsia-600 to-indigo-600 flex items-center justify-center text-white shadow-lg shadow-fuchsia-500/20">
                   <Icons.Sparkles />
                </div>
                <div className="flex flex-col">
                    <span className="text-sm font-black text-white tracking-tight leading-none">FLASHFUSION</span>
                    <span className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">{currentTemplate.name}</span>
                </div>
             </div>

             <div className="hidden lg:block flex-1 max-w-xl mx-6">
                <MagicBar 
                  onWidgetGenerated={handleWidgetGenerated} 
                  semanticModel={semanticModel} 
                  variant="header"
                />
             </div>
          </div>

          <div className="flex items-center gap-3">
             <div className="flex items-center gap-2 px-3 py-1.5 bg-white/5 rounded-full border border-white/5">
                <div className={`w-1.5 h-1.5 rounded-full ${isStreaming ? 'bg-emerald-500 animate-pulse shadow-[0_0_8px_#10b981]' : 'bg-slate-600'}`} />
                <span className="text-[9px] font-black uppercase tracking-widest text-slate-400">
                  {isStreaming ? "Live" : "Static"}
                </span>
             </div>

             <button 
                onClick={() => setIsLocked(!isLocked)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${
                  !isLocked 
                    ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-600/20' 
                    : 'bg-white/5 text-slate-400 border border-white/5 hover:bg-white/10'
                }`}
             >
                {isLocked ? <Icons.Lock /> : <Icons.Unlock />}
                {isLocked ? "Locked" : "Editing"}
             </button>
