import React from 'react';

interface VizKPIProps {
  title: string;
  value: string;
  trend: string;
  isPositive: boolean;

  // Computed numerical value for comparison
  rawValue?: number;
  // Threshold config
  referenceValue?: number;
  referenceType?: 'min' | 'max';
}

export const VizKPI: React.FC<VizKPIProps> = ({ title, value, trend, isPositive, rawValue, referenceValue, referenceType }) => {
  let statusColor = isPositive ? 'text-emerald-400' : 'text-rose-400';
  let barColor = isPositive ? 'bg-emerald-400' : 'bg-rose-400';
  let statusText = trend;

  // Threshold Logic
  if (referenceValue !== undefined && rawValue !== undefined) {
    const isMinGoal = referenceType === 'min'; // e.g. Steps > 10000
    const isMaxLimit = referenceType === 'max'; // e.g. Spending < 500

    let isSuccess = true;
    if (isMinGoal) isSuccess = rawValue >= referenceValue;
    if (isMaxLimit) isSuccess = rawValue <= referenceValue;

    if (!isSuccess) {
        statusColor = 'text-amber-500 animate-pulse'; // Warning
        barColor = 'bg-amber-500';
        statusText = `Off Track`;
    } else {
        statusColor = 'text-emerald-400';
        barColor = 'bg-emerald-400';
        statusText = 'On Track';
    }
  }

  const formattedRef = referenceValue !== undefined 
    ? new Intl.NumberFormat('en-US', { notation: "compact", compactDisplay: "short" }).format(referenceValue)
    : null;

  return (
    <div className="h-full flex flex-col justify-center relative">
      <div className="flex justify-between items-start">
        <div className="text-sm font-medium text-slate-400 uppercase tracking-wider">{title}</div>
        {referenceValue !== undefined && (
          <div className="text-[9px] font-bold px-2 py-1 rounded-md bg-white/5 text-slate-400 border border-white/5">
             {referenceType === 'min' ? 'Goal' : 'Limit'}: {formattedRef}
          </div>
        )}
      </div>

      <div className="mt-2 flex items-baseline gap-2">
        <span className={`text-3xl font-black text-white drop-shadow-[0_0_10px_rgba(255,255,255,0.2)]`}>{value}</span>
        <span className={`text-sm font-bold ${statusColor}`}>
          {statusText}
        </span>
      </div>

      <div className="mt-4 h-1 w-full bg-white/10 rounded-full overflow-hidden relative">
        <div className={`h-full rounded-full transition-all duration-1000 shadow-[0_0_8px_currentColor] ${barColor}`} style={{ width: '70%' }}></div>

        {/* Visual Marker for Threshold within bar if we could calculate % but standardized to 70% width for style currently */}
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { Icons } from '../constants';
import { VizType, WidgetConfig } from '../types';
import { VizArea } from './VizArea';
import { VizBar } from './VizBar';
import { VizKPI } from './VizKPI';
import { VizScatter } from './VizScatter';
import { VizHeatmap } from './VizHeatmap';
import { VizTreemap } from './VizTreemap';

interface ChartRendererProps {
  config: WidgetConfig;
  data: any[];
  onDrill: (value: string) => void;
  currentLevel: string;
  drillPath: string[];
  canDrill: boolean;
}

/**
 * Renders the appropriate visualization based on the widget configuration.
 * Handles data aggregation, transformation, and distribution to specific Viz components.
 */
export const ChartRenderer: React.FC<ChartRendererProps> = ({ config, data, onDrill, currentLevel, drillPath, canDrill }) => {

  // -- Standard Aggregation (Bar, Line, KPI) --
  const standardData = useMemo(() => {
    if ([VizType.SCATTER, VizType.HEATMAP, VizType.TREEMAP].includes(config.type)) return [];

    const metric = config.metric || 'sales';
    const dim = config.dimension || currentLevel;
    const agg: Record<string, any> = {};

    data.forEach(item => {
      const key = String(item[dim] || 'Unknown');

      if (!agg[key]) {
        agg[key] = { [dim]: key };
        agg[key][metric] = 0;

        if (metric !== 'sales' && 'sales' in item) agg[key]['sales'] = 0;
        if (metric !== 'users' && 'users' in item) agg[key]['users'] = 0;
      }

      const val = Number(item[metric]);
      if (!isNaN(val)) {
        agg[key][metric] += val;
      }

      if (metric !== 'sales' && item.sales) agg[key]['sales'] += Number(item.sales) || 0;
      if (metric !== 'users' && item.users) agg[key]['users'] += Number(item.users) || 0;
    });

    return Object.values(agg).sort((a, b) => String(a[dim]).localeCompare(String(b[dim])));
  }, [data, currentLevel, config.type, config.metric, config.dimension]);

  // -- Scatter Data --
  const scatterData = useMemo(() => {
    if (config.type !== VizType.SCATTER) return [];
    const xKey = config.dimension || 'sales';
    const yKey = config.secondaryDimension || 'users';
    const zKey = config.metric || 'conversion';

    return data.map(d => ({
        ...d,
        [xKey]: Number(d[xKey] || 0),
        [yKey]: Number(d[yKey] || 0),
        [zKey]: Number(d[zKey] || 0),
    }));
  }, [data, config.type, config.dimension, config.secondaryDimension, config.metric]);

  // -- Heatmap Data --
  const heatmapData = useMemo(() => {
    if (config.type !== VizType.HEATMAP) return [];
    const xKey = config.dimension || 'category';
    const yKey = config.secondaryDimension || 'region';
    const valKey = config.metric || 'sales';

    const agg: Record<string, any> = {};
    data.forEach(item => {
        const x = String(item[xKey] || 'N/A');
        const y = String(item[yKey] || 'N/A');
        const key = `${x}-${y}`;
        if(!agg[key]) agg[key] = { [xKey]: x, [yKey]: y, [valKey]: 0 };
        agg[key][valKey] += Number(item[valKey] || 0);
    });
    return Object.values(agg);
  }, [data, config.type, config.dimension, config.secondaryDimension, config.metric]);

  // -- Treemap Data --
  const treemapData = useMemo(() => {
      if (config.type !== VizType.TREEMAP) return [];
      const dimKey = config.dimension || currentLevel;
      const valKey = config.metric || 'sales';

      const agg: Record<string, number> = {};
      data.forEach(item => {
          const key = String(item[dimKey] || 'Unknown');
          agg[key] = (agg[key] || 0) + (Number(item[valKey]) || 0);
      });
      return Object.entries(agg).map(([name, size]) => ({ name, size }));
  }, [data, config.type, currentLevel, config.dimension, config.metric]);

  switch (config.type) {
    case VizType.TIME_SERIES:
      return <VizArea 
        data={standardData} 
        onDrill={onDrill} 
        currentLevel={config.dimension || currentLevel} 
        drillPath={drillPath} 
        canDrill={canDrill}
        metric={config.metric || 'sales'}
        referenceValue={config.referenceValue}
      />;

    case VizType.BAR:
      return <VizBar 
        data={standardData} 
        onDrill={onDrill} 
        currentLevel={config.dimension || currentLevel} 
        drillPath={drillPath} 
        canDrill={canDrill}
        metric={config.metric || 'sales'}
        referenceValue={config.referenceValue}
      />;

    case VizType.KPI_CARD:
      const metric = config.metric || 'sales';
      const total = standardData.reduce((acc, curr) => acc + (Number(curr[metric]) || 0), 0);
      const formattedTotal = new Intl.NumberFormat('en-US', { 
        notation: "compact", 
        compactDisplay: "short" 
      }).format(total);

      return <VizKPI 
        title={config.title} 
        value={formattedTotal} 
        trend="--" 
        isPositive={true} 
        rawValue={total}
        referenceValue={config.referenceValue}
        referenceType={config.referenceType}
      />;

    case VizType.SCATTER:
        return <VizScatter 
          data={scatterData} 
          xKey={config.dimension || 'sales'}
          yKey={config.secondaryDimension || 'users'}
          zKey={config.metric || 'conversion'}
        />;

    case VizType.HEATMAP:
        return <VizHeatmap 
          data={heatmapData} 
          xKey={config.dimension || 'category'} 
          yKey={config.secondaryDimension || 'region'} 
          valKey={config.metric || 'sales'} 
        />;

    case VizType.TREEMAP:
        return <VizTreemap data={treemapData} />;

    default:
      return (
        <div className="flex flex-col items-center justify-center h-full text-slate-600 gap-2">
          <Icons.Dashboard />
          <span className="text-xs font-semibold uppercase tracking-widest">{config.type} Placeholder</span>
        </div>
      );
  }
};

import React, { useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend, Cell, ReferenceLine } from 'recharts';
import { VizTooltip } from './VizTooltip';

interface VizBarProps {
  data: any[];
  onDrill: (value: string) => void;
  currentLevel: string;
  drillPath: string[];
  canDrill: boolean;
  metric?: string;
  referenceValue?: number;
}

export const VizBar: React.FC<VizBarProps> = ({ data, onDrill, currentLevel, drillPath, canDrill, metric = 'sales', referenceValue }) => {
  const [hiddenSeries, setHiddenSeries] = useState<Set<string>>(new Set());

  const handleLegendClick = (o: any) => {
    const { dataKey } = o;
    setHiddenSeries(prev => {
      const next = new Set(prev);
      if (next.has(dataKey)) next.delete(dataKey);
      else next.add(dataKey);
      return next;
    });
  };

  const handleClick = (state: any) => {
    if (state && state.activeLabel) {
      onDrill(String(state.activeLabel));
    } else if (state && state.activePayload && state.activePayload[0]) {
      const val = state.activePayload[0].payload[currentLevel];
      if (val) onDrill(String(val));
    }
  };

  const commonAxisProps = {
    axisLine: false,
    tickLine: false,
    tick: { fontSize: 10, fill: '#94a3b8', fontWeight: 600 }
  };

  return (
    <ResponsiveContainer width="100%" height="100%">
      <BarChart data={data} onClick={handleClick} cursor="pointer">
        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#334155" opacity={0.3} />
        <XAxis dataKey={currentLevel} {...commonAxisProps} />
        <YAxis {...commonAxisProps} />
        <Tooltip 
          content={<VizTooltip currentLevel={currentLevel} drillPath={drillPath} canDrill={canDrill} />}
          cursor={{ fill: '#a855f7', opacity: 0.1 }}
          allowEscapeViewBox={{ x: true, y: true }}
          wrapperStyle={{ zIndex: 50, outline: 'none' }}
        />
        <Legend 
          onClick={handleLegendClick}
          wrapperStyle={{ paddingTop: '10px', fontSize: '10px', fontWeight: 'bold', textTransform: 'uppercase', cursor: 'pointer', color: '#cbd5e1' }}
        />
        {!hiddenSeries.has(metric) && (
          <Bar name={metric} dataKey={metric} radius={[6, 6, 0, 0]}>
            {data.map((_, index) => (
              <Cell key={`cell-${metric}-${index}`} fill={index % 2 === 0 ? '#a855f7' : '#8b5cf6'} className="hover:opacity-80 transition-opacity filter drop-shadow-[0_0_8px_rgba(168,85,247,0.4)]" />
            ))}
          </Bar>
        )}
        {/* Fallback/Secondary bar if metrics are strictly sales/users and not dynamic */}
        {metric === 'sales' && !hiddenSeries.has('users') && (
           <Bar name="users" dataKey="users" radius={[6, 6, 0, 0]}>
             {data.map((_, index) => (
               <Cell key={`cell-users-${index}`} fill={index % 2 === 0 ? '#ec4899' : '#db2777'} className="hover:opacity-80 transition-opacity filter drop-shadow-[0_0_8px_rgba(236,72,153,0.4)]" />
             ))}
           </Bar>
        )}

        {referenceValue !== undefined && (
          <ReferenceLine 
            y={referenceValue} 
            stroke="#10b981" 
            strokeDasharray="3 3" 
            label={{ value: 'Target', position: 'insideTopRight', fill: '#10b981', fontSize: 10, fontWeight: 'bold' }} 
          />
        )}
      </BarChart>
    </ResponsiveContainer>
  );
};

