import React, { useState, useMemo } from 'react';

interface VizTableProps {
  data: any[];
}

type SortDirection = 'asc' | 'desc';

interface SortConfig {
  key: string;
  direction: SortDirection;
}

export const VizTable: React.FC<VizTableProps> = ({ data }) => {
  const [sortConfig, setSortConfig] = useState<SortConfig | null>(null);

  // 1. Extract Columns
  const columns = useMemo(() => {
    if (data.length === 0) return [];
    return Object.keys(data[0]);
  }, [data]);

  // 2. Compute Column Maxima for Heat Bars
  const columnMaxValues = useMemo(() => {
    const maxes: Record<string, number> = {};
    columns.forEach(col => {
      // Check if column is numeric
      if (typeof data[0][col] === 'number') {
        maxes[col] = Math.max(...data.map(d => Number(d[col]) || 0));
      }
    });
    return maxes;
  }, [data, columns]);

  // 3. Handle Sorting
  const sortedData = useMemo(() => {
    if (!sortConfig) return data;
    return [...data].sort((a, b) => {
      const valA = a[sortConfig.key];
      const valB = b[sortConfig.key];

      if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
      if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
      return 0;
    });
  }, [data, sortConfig]);

  const handleSort = (key: string) => {
    setSortConfig(current => {
      if (current?.key === key) {
        return { key, direction: current.direction === 'asc' ? 'desc' : 'asc' };
      }
      return { key, direction: 'asc' };
    });
  };

  if (data.length === 0) {
    return (
      <div className="flex items-center justify-center h-full text-slate-500 text-xs uppercase tracking-widest font-bold">
        No Data Available
      </div>
    );
  }

  return (
    <div className="h-full w-full overflow-auto custom-scrollbar rounded-xl border border-white/5 bg-slate-950/30">
      <table className="w-full text-left border-collapse min-w-[400px]">
        <thead className="sticky top-0 z-10 bg-slate-900 shadow-lg ring-1 ring-white/5">
          <tr>
            {columns.map(col => (
              <th 
                key={col}
                onClick={() => handleSort(col)}
                className="p-3 text-[10px] font-black uppercase tracking-widest text-slate-400 cursor-pointer hover:text-white hover:bg-white/5 transition-colors select-none whitespace-nowrap"
              >
                <div className="flex items-center gap-2">
                  {col}
                  {sortConfig?.key === col && (
                    <span className="text-fuchsia-400">
                      {sortConfig.direction === 'asc' ? '↑' : '↓'}
                    </span>
                  )}
                </div>
              </th>
            ))}
          </tr>
        </thead>
        <tbody className="divide-y divide-white/5">
          {sortedData.map((row, idx) => (
            <tr key={idx} className="hover:bg-white/5 transition-colors group">
              {columns.map(col => {
                const val = row[col];
                const isNum = typeof val === 'number';
                const max = columnMaxValues[col];
                const percentage = isNum && max > 0 ? (val / max) * 100 : 0;

                return (
                  <td key={col} className="p-3 text-xs font-medium text-slate-300 relative">
                    {/* Heat Bar Background */}
                    {isNum && (
                      <div 
                        className="absolute inset-y-1 left-0 bg-fuchsia-500/10 rounded-r-md transition-all duration-500"
                        style={{ width: `${percentage}%` }}
                      />
                    )}

                    {/* Content */}
                    <span className="relative z-0 font-mono">
                      {isNum 
                        ? new Intl.NumberFormat('en-US', { maximumFractionDigits: 2 }).format(val)
                        : String(val)
                      }
                    </span>
                  </td>
                );
              })}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

import React, { useMemo } from 'react';
import { Icons } from '../constants';
import { VizType, WidgetConfig } from '../types';
import { VizArea } from './VizArea';
import { VizBar } from './VizBar';
import { VizKPI } from './VizKPI';
import { VizScatter } from './VizScatter';
import { VizHeatmap } from './VizHeatmap';
import { VizTreemap } from './VizTreemap';
import { VizTable } from './VizTable';

interface ChartRendererProps {
  config: WidgetConfig;
  data: any[];
  onDrill: (value: string) => void;
  currentLevel: string;
  drillPath: string[];
  canDrill: boolean;
}

/**
 * Renders the appropriate visualization based on the widget configuration.
 * Handles data aggregation, transformation, and distribution to specific Viz components.
 */
export const ChartRenderer: React.FC<ChartRendererProps> = ({ config, data, onDrill, currentLevel, drillPath, canDrill }) => {

  // -- Standard Aggregation (Bar, Line, KPI) --
  const standardData = useMemo(() => {
    if ([VizType.SCATTER, VizType.HEATMAP, VizType.TREEMAP, VizType.TABLE].includes(config.type)) return [];

    const metric = config.metric || 'sales';
    const dim = config.dimension || currentLevel;
    const agg: Record<string, any> = {};

    data.forEach(item => {
      const key = String(item[dim] || 'Unknown');

      if (!agg[key]) {
        agg[key] = { [dim]: key };
        agg[key][metric] = 0;

        if (metric !== 'sales' && 'sales' in item) agg[key]['sales'] = 0;
        if (metric !== 'users' && 'users' in item) agg[key]['users'] = 0;
      }

      const val = Number(item[metric]);
      if (!isNaN(val)) {
        agg[key][metric] += val;
      }

      if (metric !== 'sales' && item.sales) agg[key]['sales'] += Number(item.sales) || 0;
      if (metric !== 'users' && item.users) agg[key]['users'] += Number(item.users) || 0;
    });

    return Object.values(agg).sort((a, b) => String(a[dim]).localeCompare(String(b[dim])));
  }, [data, currentLevel, config.type, config.metric, config.dimension]);

  // -- Scatter Data --
  const scatterData = useMemo(() => {
    if (config.type !== VizType.SCATTER) return [];
    const xKey = config.dimension || 'sales';
    const yKey = config.secondaryDimension || 'users';
    const zKey = config.metric || 'conversion';

    return data.map(d => ({
        ...d,
        [xKey]: Number(d[xKey] || 0),
        [yKey]: Number(d[yKey] || 0),
        [zKey]: Number(d[zKey] || 0),
    }));
  }, [data, config.type, config.dimension, config.secondaryDimension, config.metric]);

  // -- Heatmap Data --
  const heatmapData = useMemo(() => {
    if (config.type !== VizType.HEATMAP) return [];
    const xKey = config.dimension || 'category';
    const yKey = config.secondaryDimension || 'region';
    const valKey = config.metric || 'sales';

    const agg: Record<string, any> = {};
    data.forEach(item => {
        const x = String(item[xKey] || 'N/A');
        const y = String(item[yKey] || 'N/A');
        const key = `${x}-${y}`;
        if(!agg[key]) agg[key] = { [xKey]: x, [yKey]: y, [valKey]: 0 };
        agg[key][valKey] += Number(item[valKey] || 0);
    });
    return Object.values(agg);
  }, [data, config.type, config.dimension, config.secondaryDimension, config.metric]);

  // -- Treemap Data --
  const treemapData = useMemo(() => {
      if (config.type !== VizType.TREEMAP) return [];
      const dimKey = config.dimension || currentLevel;
      const valKey = config.metric || 'sales';

      const agg: Record<string, number> = {};
      data.forEach(item => {
          const key = String(item[dimKey] || 'Unknown');
          agg[key] = (agg[key] || 0) + (Number(item[valKey]) || 0);
      });
      return Object.entries(agg).map(([name, size]) => ({ name, size }));
  }, [data, config.type, currentLevel, config.dimension, config.metric]);

  switch (config.type) {
    case VizType.TIME_SERIES:
      return <VizArea 
        data={standardData} 
        onDrill={onDrill} 
        currentLevel={config.dimension || currentLevel} 
        drillPath={drillPath} 
        canDrill={canDrill}
        metric={config.metric || 'sales'}
        referenceValue={config.referenceValue}
      />;

    case VizType.BAR:
      return <VizBar 
        data={standardData} 
        onDrill={onDrill} 
        currentLevel={config.dimension || currentLevel} 
        drillPath={drillPath} 
        canDrill={canDrill}
        metric={config.metric || 'sales'}
        referenceValue={config.referenceValue}
      />;

    case VizType.KPI_CARD:
      const metric = config.metric || 'sales';
      const total = standardData.reduce((acc, curr) => acc + (Number(curr[metric]) || 0), 0);
      const formattedTotal = new Intl.NumberFormat('en-US', { 
        notation: "compact", 
        compactDisplay: "short" 
      }).format(total);

      return <VizKPI 
        title={config.title} 
        value={formattedTotal} 
        trend="--" 
        isPositive={true} 
        rawValue={total}
        referenceValue={config.referenceValue}
        referenceType={config.referenceType}
      />;

    case VizType.SCATTER:
        return <VizScatter 
          data={scatterData} 
          xKey={config.dimension || 'sales'}
          yKey={config.secondaryDimension || 'users'}
          zKey={config.metric || 'conversion'}
        />;

    case VizType.HEATMAP:
        return <VizHeatmap 
          data={heatmapData} 
          xKey={config.dimension || 'category'} 
          yKey={config.secondaryDimension || 'region'} 
          valKey={config.metric || 'sales'} 
        />;

    case VizType.TREEMAP:
        return <VizTreemap data={treemapData} />;

    case VizType.TABLE:
        // Pass raw filtered data directly to table
        return <VizTable data={data} />;

    default:
      return (
        <div className="flex flex-col items-center justify-center h-full text-slate-600 gap-2">
          <Icons.Dashboard />
          <span className="text-xs font-semibold uppercase tracking-widest">{config.type} Placeholder</span>
        </div>
      );
  }
};

/**
 * OmniGen Type Definitions
 * 
 * This file contains all shared interfaces and constants for the application.
 */

/**
 * Grid Layout Configuration
 * Corresponds to Tailwind classes: grid-cols-12, gap-6 (24px), auto-rows-[100px]
 */
export const GRID_SYSTEM = {
  COLS: 12,
  ROW_HEIGHT_PX: 100,
  GAP_PX: 24, // tailwind gap-6
};

export enum VizType {
  TABLE = 'table',
  PIVOT = 'pivot',
  TIME_SERIES = 'time-series',
  FUNNEL = 'funnel',
  COHORT = 'cohort',
  GEO_MAP = 'geo-map',
  SANKEY = 'sankey',
  NETWORK = 'network',
  BAR = 'bar',
  COLUMN = 'column',
  STACKED_BAR = 'stacked-bar',
  SCATTER = 'scatter',
  HISTOGRAM = 'histogram',
  HEATMAP = 'heatmap',
  TREEMAP = 'treemap',
  BOX_PLOT = 'box-plot',
  GAUGE = 'gauge',
  WATERFALL = 'waterfall',
  KPI_CARD = 'kpi-card',
  VIDEO = 'video'
}

/**
 * Represents the inferred semantic layer of the dataset.
 * Used by the AI to generate relevant visualizations.
 */
export interface SemanticModel {
  entities: { name: string; description: string; likely_keys: string[]; example_fields: string[] }[];
  metrics: { name: string; definition: string; aggregation: string; grain: string; caveats?: string }[];
  dimensions: { name: string; type: string; examples: string[] }[];
  relationships: { from_entity: string; to_entity: string; join_keys: string[]; join_type: string; confidence: number }[];
  kpis: { name: string; metric: string; goal_direction: 'up' | 'down'; target: string; alert_threshold: string }[];
  glossary: { term: string; meaning: string; synonyms: string[] }[];
  quality_flags: { issue: string; impacted_fields: string[]; severity: 'low' | 'medium' | 'high'; suggested_fix: string }[];
  assumptions: { assumption: string; impact: string; confirm_by: string }[];
}

export interface Annotation {
  id: string;
  text: string;
  timestamp: number;
}

/**
 * Configuration for a single dashboard widget.
 * x, y, w, h are in Grid Units (not pixels).
 */
export interface WidgetConfig {
  id: string;
  type: VizType;
  title: string;
  metric?: string;             // The primary numeric value to plot
  dimension?: string;          // The primary grouping key (X-Axis)
  secondaryDimension?: string; // The secondary grouping key (Legend/Y-Axis)
  filter?: Record<string, any>;

  // Threshold Monitoring
  referenceValue?: number;     // The target or limit value
  referenceType?: 'min' | 'max'; // 'min' = Goal (Must exceed), 'max' = Limit (Must stay under)

  // Video Specific
  videoUrl?: string;
  poster?: string;
  aspectRatio?: string; // e.g., "16/9", "4/3", "21/9"
  autoPlay?: boolean;

  // Observations
  annotations?: Annotation[];

  w: number; // Width in grid columns (1-12)
  h: number; // Height in grid rows
  x: number; // Column start (0-11)
  y: number; // Row start
}

export interface DashboardTemplate {
  id: string;
  name: string;
  category: string;
  description: string;
  widgets: WidgetConfig[];
  difficulty: 'Basic' | 'Advanced';
}

export interface AnalysisResult {
  summary: string;
  drivers: string[];
  recommendations: string[];
  sentiment: 'positive' | 'negative' | 'neutral';
  marketContext?: string;
  sources?: { title: string; uri: string }[];
}

import React, { useRef, useState, useEffect, useCallback } from 'react';

interface HeroVideoProps {
  src?: string;
  poster?: string;
  aspectRatio?: string; // e.g. "16/9"
  autoPlay?: boolean;
}

export const HeroVideo: React.FC<HeroVideoProps> = ({ 
  src = "https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/BigBuckBunny.mp4", 
  poster, 
  aspectRatio = "16/9", 
  autoPlay = false 
}) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [progress, setProgress] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [showControls, setShowControls] = useState(false);

  // Handle Aspect Ratio
  const ratioParts = aspectRatio.split('/').map(Number);
  const calculatedRatio = ratioParts.length === 2 ? `${ratioParts[0]} / ${ratioParts[1]}` : '16 / 9';

  // Keyboard Controls
  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (!videoRef.current) return;

    switch (e.key) {
      case ' ':
      case 'k':
        e.preventDefault();
        togglePlay();
        break;
      case 'm':
        e.preventDefault();
        toggleMute();
        break;
      case 'ArrowRight':
        e.preventDefault();
        videoRef.current.currentTime += 5;
        break;
      case 'ArrowLeft':
        e.preventDefault();
        videoRef.current.currentTime -= 5;
        break;
    }
  };

  const togglePlay = () => {
    if (!videoRef.current) return;
    if (videoRef.current.paused) {
      videoRef.current.play().catch(e => console.error("Play failed", e));
      setIsPlaying(true);
    } else {
      videoRef.current.pause();
      setIsPlaying(false);
    }
  };

  const toggleMute = () => {
    if (!videoRef.current) return;
    videoRef.current.muted = !videoRef.current.muted;
    setIsMuted(videoRef.current.muted);
  };

  const handleTimeUpdate = () => {
    if (videoRef.current) {
      const p = (videoRef.current.currentTime / videoRef.current.duration) * 100;
      setProgress(isNaN(p) ? 0 : p);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (videoRef.current) {
      const time = (Number(e.target.value) / 100) * videoRef.current.duration;
      videoRef.current.currentTime = time;
      setProgress(Number(e.target.value));
    }
  };

  // AutoPlay logic respecting reduced motion
  useEffect(() => {
    const video = videoRef.current;
    if (!video || !autoPlay) return;

    const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    if (prefersReducedMotion) return;

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            video.play().then(() => setIsPlaying(true)).catch(() => {
              // Autoplay might be blocked by browser policy without mute
              video.muted = true;
              setIsMuted(true);
              video.play().then(() => setIsPlaying(true)).catch(e => console.log("Autoplay blocked", e));
            });
          } else {
            video.pause();
            setIsPlaying(false);
          }
        });
      },
      { threshold: 0.5 }
    );

    observer.observe(video);
    return () => observer.disconnect();
  }, [autoPlay]);

  if (error) {
    return (
      <div 
        className="w-full h-full flex flex-col items-center justify-center bg-slate-900 border border-slate-700 rounded-xl p-6 text-center"
        style={{ aspectRatio: calculatedRatio }}
      >
        <svg className="w-10 h-10 text-rose-500 mb-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
        </svg>
        <p className="text-slate-300 font-bold">Video Unavailable</p>
        <p className="text-slate-500 text-xs mt-1">Unable to load media source.</p>
      </div>
    );
  }

  return (
    <div 
      ref={containerRef}
      className="relative group w-full bg-black rounded-xl overflow-hidden focus:ring-2 focus:ring-cyan-400 focus:outline-none"
      style={{ aspectRatio: calculatedRatio }}
      onMouseEnter={() => setShowControls(true)}
      onMouseLeave={() => setShowControls(false)}
      onKeyDown={handleKeyDown}
      tabIndex={0}
      role="region"
      aria-label="Video Player"
    >
      <video
        ref={videoRef}
        src={src}
        poster={poster}
        className="w-full h-full object-cover"
        onTimeUpdate={handleTimeUpdate}
        onError={() => setError("Failed to load video")}
        onEnded={() => setIsPlaying(false)}
        playsInline
      />

      {/* Controls Overlay */}
      <div className={`absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent transition-opacity duration-300 flex flex-col justify-end p-4 ${showControls || !isPlaying ? 'opacity-100' : 'opacity-0'}`}>

        {/* Seek Bar */}
        <input
          type="range"
          min="0"
          max="100"
          value={progress}
          onChange={handleSeek}
          className="w-full h-1 bg-slate-600 rounded-lg appearance-none cursor-pointer accent-cyan-400 mb-4 focus:outline-none focus:ring-2 focus:ring-cyan-400"
          aria-label="Seek"
        />

        <div className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button
              onClick={togglePlay}
              className="text-white hover:text-cyan-400 transition-colors focus:text-cyan-400 focus:outline-none"
              aria-label={isPlaying ? "Pause" : "Play"}
            >
              {isPlaying ? (
                <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M6 4h4v16H6V4zm8 0h4v16h-4V4z"/></svg>
              ) : (
                <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg>
              )}
            </button>

            <button
              onClick={toggleMute}
              className="text-white hover:text-cyan-400 transition-colors focus:text-cyan-400 focus:outline-none"
              aria-label={isMuted ? "Unmute" : "Mute"}
            >
              {isMuted ? (
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" strokeDasharray="20 2" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2" /></svg>
              ) : (
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" /></svg>
              )}
            </button>
          </div>

          <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
             {isPlaying ? 'Playing' : 'Paused'}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { Icons } from '../constants';
import { VizType, WidgetConfig } from '../types';
import { VizArea } from './VizArea';
import { VizBar } from './VizBar';
import { VizKPI } from './VizKPI';
import { VizScatter } from './VizScatter';
import { VizHeatmap } from './VizHeatmap';
import { VizTreemap } from './VizTreemap';
import { VizTable } from './VizTable';
import { HeroVideo } from './HeroVideo';

interface ChartRendererProps {
  config: WidgetConfig;
  data: any[];
  onDrill: (value: string) => void;
  currentLevel: string;
  drillPath: string[];
  canDrill: boolean;
}

/**
 * Renders the appropriate visualization based on the widget configuration.
 * Handles data aggregation, transformation, and distribution to specific Viz components.
 */
export const ChartRenderer: React.FC<ChartRendererProps> = ({ config, data, onDrill, currentLevel, drillPath, canDrill }) => {

  // -- Standard Aggregation (Bar, Line, KPI) --
  const standardData = useMemo(() => {
    if ([VizType.SCATTER, VizType.HEATMAP, VizType.TREEMAP, VizType.TABLE, VizType.VIDEO].includes(config.type)) return [];

    const metric = config.metric || 'sales';
    const dim = config.dimension || currentLevel;
    const agg: Record<string, any> = {};

    data.forEach(item => {
      const key = String(item[dim] || 'Unknown');

      if (!agg[key]) {
        agg[key] = { [dim]: key };
        agg[key][metric] = 0;

        if (metric !== 'sales' && 'sales' in item) agg[key]['sales'] = 0;
        if (metric !== 'users' && 'users' in item) agg[key]['users'] = 0;
      }

      const val = Number(item[metric]);
      if (!isNaN(val)) {
        agg[key][metric] += val;
      }

      if (metric !== 'sales' && item.sales) agg[key]['sales'] += Number(item.sales) || 0;
      if (metric !== 'users' && item.users) agg[key]['users'] += Number(item.users) || 0;
    });

    return Object.values(agg).sort((a, b) => String(a[dim]).localeCompare(String(b[dim])));
  }, [data, currentLevel, config.type, config.metric, config.dimension]);

  // -- Scatter Data --
  const scatterData = useMemo(() => {
    if (config.type !== VizType.SCATTER) return [];
    const xKey = config.dimension || 'sales';
    const yKey = config.secondaryDimension || 'users';
    const zKey = config.metric || 'conversion';

    return data.map(d => ({
        ...d,
        [xKey]: Number(d[xKey] || 0),
        [yKey]: Number(d[yKey] || 0),
        [zKey]: Number(d[zKey] || 0),
    }));
  }, [data, config.type, config.dimension, config.secondaryDimension, config.metric]);

  // -- Heatmap Data --
  const heatmapData = useMemo(() => {
    if (config.type !== VizType.HEATMAP) return [];
    const xKey = config.dimension || 'category';
    const yKey = config.secondaryDimension || 'region';
    const valKey = config.metric || 'sales';

    const agg: Record<string, any> = {};
    data.forEach(item => {
        const x = String(item[xKey] || 'N/A');
        const y = String(item[yKey] || 'N/A');
        const key = `${x}-${y}`;
        if(!agg[key]) agg[key] = { [xKey]: x, [yKey]: y, [valKey]: 0 };
        agg[key][valKey] += Number(item[valKey] || 0);
    });
    return Object.values(agg);
  }, [data, config.type, config.dimension, config.secondaryDimension, config.metric]);

  // -- Treemap Data --
  const treemapData = useMemo(() => {
      if (config.type !== VizType.TREEMAP) return [];
      const dimKey = config.dimension || currentLevel;
      const valKey = config.metric || 'sales';

      const agg: Record<string, number> = {};
      data.forEach(item => {
          const key = String(item[dimKey] || 'Unknown');
          agg[key] = (agg[key] || 0) + (Number(item[valKey]) || 0);
      });
      return Object.entries(agg).map(([name, size]) => ({ name, size }));
  }, [data, config.type, currentLevel, config.dimension, config.metric]);

  switch (config.type) {
    case VizType.TIME_SERIES:
      return <VizArea 
        data={standardData} 
        onDrill={onDrill} 
        currentLevel={config.dimension || currentLevel} 
        drillPath={drillPath} 
        canDrill={canDrill}
        metric={config.metric || 'sales'}
        referenceValue={config.referenceValue}
      />;

    case VizType.BAR:
      return <VizBar 
        data={standardData} 
        onDrill={onDrill} 
        currentLevel={config.dimension || currentLevel} 
        drillPath={drillPath} 
        canDrill={canDrill}
        metric={config.metric || 'sales'}
        referenceValue={config.referenceValue}
      />;

    case VizType.KPI_CARD:
      const metric = config.metric || 'sales';
      const total = standardData.reduce((acc, curr) => acc + (Number(curr[metric]) || 0), 0);
      const formattedTotal = new Intl.NumberFormat('en-US', { 
        notation: "compact", 
        compactDisplay: "short" 
      }).format(total);

      return <VizKPI 
        title={config.title} 
        value={formattedTotal} 
        trend="--" 
        isPositive={true} 
        rawValue={total}
        referenceValue={config.referenceValue}
        referenceType={config.referenceType}
      />;

    case VizType.SCATTER:
        return <VizScatter 
          data={scatterData} 
          xKey={config.dimension || 'sales'}
          yKey={config.secondaryDimension || 'users'}
          zKey={config.metric || 'conversion'}
        />;

    case VizType.HEATMAP:
        return <VizHeatmap 
          data={heatmapData} 
          xKey={config.dimension || 'category'} 
          yKey={config.secondaryDimension || 'region'} 
          valKey={config.metric || 'sales'} 
        />;

    case VizType.TREEMAP:
        return <VizTreemap data={treemapData} />;

    case VizType.TABLE:
        // Pass raw filtered data directly to table
        return <VizTable data={data} />;

    case VizType.VIDEO:
      return <HeroVideo 
        src={config.videoUrl} 
        poster={config.poster}
        aspectRatio={config.aspectRatio}
        autoPlay={config.autoPlay}
      />;

    default:
      return (
        <div className="flex flex-col items-center justify-center h-full text-slate-500 gap-2">
          <Icons.Dashboard />
          <span className="text-xs font-semibold uppercase tracking-widest">{config.type} Placeholder</span>
        </div>
      );
  }
};

import React, { useState, useMemo, useEffect, useCallback, useRef } from 'react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';
import { Icons } from './constants';
import { WidgetConfig, AnalysisResult, GRID_SYSTEM } from './types';
import { inferSemanticModel } from './services/semanticEngine';
import { generateTemplates } from './services/templateService';
import { generateAnalysis } from './services/aiService';
import { WidgetContainer } from './components/WidgetContainer';
import { Sidebar } from './components/Sidebar';
import { MagicBar } from './components/MagicBar';
import { AnalysisPanel } from './components/AnalysisPanel';
import { useDataManager } from './hooks/useDataManager';
import { ExportModal, ExportConfig } from './components/ExportModal';
import { GlobalFilterBar } from './components/GlobalFilterBar';
import { ChartRenderer } from './components/ChartRenderer';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'library' | 'about'>('dashboard');
  const [isLocked, setIsLocked] = useState(true);
  const [selectedTemplateId, setSelectedTemplateId] = useState('personal-health');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const [dashboardWidgets, setDashboardWidgets] = useState<WidgetConfig[]>([]);
  const [isAnalysisOpen, setIsAnalysisOpen] = useState(false);
  const [analyzingWidget, setAnalyzingWidget] = useState<WidgetConfig | null>(null);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isExportModalOpen, setIsExportModalOpen] = useState(false);

  const [globalFilters, setGlobalFilters] = useState<Record<string, string>>({});
  const [focusedWidget, setFocusedWidget] = useState<WidgetConfig | null>(null);

  const dashboardRef = useRef<HTMLDivElement>(null);

  const templates = useMemo(() => generateTemplates(), []);
  const currentTemplate = useMemo(() => 
    templates.find(t => t.id === selectedTemplateId) || templates[0], 
    [templates, selectedTemplateId]
  );

  const { data, isStreaming, setIsStreaming, handleFileUpload } = useDataManager(currentTemplate.name);
  const semanticModel = useMemo(() => inferSemanticModel(data), [data]);

  // Apply Global Filters to Data
  const filteredData = useMemo(() => {
    let result = data;
    Object.entries(globalFilters).forEach(([key, value]) => {
        if (!value) return;
        result = result.filter(item => {
           const itemKey = Object.keys(item).find(k => k.toLowerCase() === key.toLowerCase());
           return itemKey ? String(item[itemKey]) === value : true;
        });
    });
    return result;
  }, [data, globalFilters]);

  const handleGlobalFilterChange = (key: string, value: string) => {
      setGlobalFilters(prev => ({ ...prev, [key]: value }));
  };

  useEffect(() => {
    const savedLayout = localStorage.getItem(`flashfusion_layout_${selectedTemplateId}`);
    if (savedLayout) {
      try {
        setDashboardWidgets(JSON.parse(savedLayout));
      } catch (e) {
        setDashboardWidgets(currentTemplate.widgets);
      }
    } else {
      setDashboardWidgets(currentTemplate.widgets);
    }
  }, [currentTemplate, selectedTemplateId]);

  useEffect(() => {
    if (dashboardWidgets.length > 0) {
      localStorage.setItem(`flashfusion_layout_${selectedTemplateId}`, JSON.stringify(dashboardWidgets));
    }
  }, [dashboardWidgets, selectedTemplateId]);

  const checkCollision = (id: string, x: number, y: number, w: number, h: number, widgets: WidgetConfig[]): boolean => {
    return widgets.some(other => {
      if (other.id === id) return false;
      return (
        x < other.x + other.w &&
        x + w > other.x &&
        y < other.y + other.h &&
        y + h > other.y
      );
    });
  };

  const handleWidgetGenerated = (newWidget: WidgetConfig) => {
    setDashboardWidgets(prev => {
      let placed = false;
      let y = 0;
      const widgetToPlace = { ...newWidget };
      while (!placed && y < 50) {
        for (let x = 0; x <= GRID_SYSTEM.COLS - widgetToPlace.w; x++) {
           if (!checkCollision(widgetToPlace.id, x, y, widgetToPlace.w, widgetToPlace.h, prev)) {
             widgetToPlace.x = x;
             widgetToPlace.y = y;
             placed = true;
             break;
           }
        }
        y++;
      }
      return [...prev, widgetToPlace];
    });
  };

  const handleWidgetResize = useCallback((id: string, newW: number, newH: number) => {
    setDashboardWidgets(prev => {
      const target = prev.find(w => w.id === id);
      if (!target) return prev;
      if (target.x + newW > GRID_SYSTEM.COLS) return prev;
      if (checkCollision(id, target.x, target.y, newW, newH, prev)) return prev;
      return prev.map(w => w.id === id ? { ...w, w: newW, h: newH } : w);
    });
  }, []);

  const handleWidgetMove = useCallback((id: string, newX: number, newY: number) => {
    setDashboardWidgets(prev => {
      const target = prev.find(w => w.id === id);
      if (!target) return prev;
      if (newX < 0 || newX + target.w > GRID_SYSTEM.COLS || newY < 0) return prev;
      if (checkCollision(id, newX, newY, target.w, target.h, prev)) return prev;
      return prev.map(w => w.id === id ? { ...w, x: newX, y: newY } : w);
    });
  }, []);

  const handleWidgetUpdate = useCallback((id: string, updates: Partial<WidgetConfig>) => {
    setDashboardWidgets(prev => prev.map(w => w.id === id ? { ...w, ...updates } : w));
  }, []);

  const handleAnalyze = async (widget: WidgetConfig, currentData: any[]) => {
    setAnalyzingWidget(widget);
    setIsAnalysisOpen(true);
    setAnalysisResult(null);
    setIsAnalyzing(true);
    const result = await generateAnalysis(widget.title, currentData);
    setAnalysisResult(result);
    setIsAnalyzing(false);
  };

  const processExport = async (config: ExportConfig) => {
    if (!dashboardRef.current) return;
    setIsExportModalOpen(false);

    // 1. Capture Dashboard Canvas
    const scale = config.dpi / 96;
    const canvas = await html2canvas(dashboardRef.current, {
      backgroundColor: '#020617',
      scale: scale,
      useCORS: true,
      logging: false,
    });

    // 2. Prepare Composition Canvas (for metadata)
    let finalCanvas = canvas;

    if (config.includeTitle || config.includeDate) {
        const titleHeight = config.includeTitle ? 60 * scale : 0;
        const dateHeight = config.includeDate ? 30 * scale : 0;
        const padding = 40 * scale;
        const totalHeaderHeight = titleHeight + dateHeight + (config.includeTitle || config.includeDate ? padding : 0);

        const compositCanvas = document.createElement('canvas');
        compositCanvas.width = canvas.width + (padding * 2);
        compositCanvas.height = canvas.height + totalHeaderHeight + padding;

        const ctx = compositCanvas.getContext('2d');
        if (ctx) {
            // Fill Background
            ctx.fillStyle = '#020617';
            ctx.fillRect(0, 0, compositCanvas.width, compositCanvas.height);

            // Draw Metadata
            ctx.textAlign = 'left';
            ctx.textBaseline = 'top';
            let currentY = padding;

            if (config.includeTitle) {
                ctx.fillStyle = '#f1f5f9'; // slate-100
                ctx.font = `900 ${32 * scale}px Inter, sans-serif`;
                ctx.fillText(currentTemplate.name, padding, currentY);
                currentY += titleHeight;
            }

            if (config.includeDate) {
                ctx.fillStyle = '#94a3b8'; // slate-400
                ctx.font = `500 ${14 * scale}px Inter, sans-serif`;
                ctx.fillText(new Date().toLocaleDateString(undefined, { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }), padding, currentY);
                currentY += dateHeight;
            }

            if (config.includeTitle || config.includeDate) {
                currentY += (10 * scale); // spacer
            }

            // Draw captured dashboard
            ctx.drawImage(canvas, padding, currentY);
            finalCanvas = compositCanvas;
        }
    }

    // 3. Output Generation
    const filename = `${currentTemplate.name.replace(/\s+/g, '_')}`;

    if (config.format === 'PDF') {
        const pdf = new jsPDF({
            orientation: config.orientation,
            unit: 'mm',
            format: config.paperSize
        });

        const pageWidth = pdf.internal.pageSize.getWidth();
        const pageHeight = pdf.internal.pageSize.getHeight();

        // Convert canvas to image data
        const imgData = finalCanvas.toDataURL('image/jpeg', config.quality);

        // Calculate fit dimensions
        const imgRatio = finalCanvas.width / finalCanvas.height;
        let finalW = pageWidth;
        let finalH = pageWidth / imgRatio;

        if (finalH > pageHeight) {
            finalH = pageHeight;
            finalW = pageHeight * imgRatio;
        }

        // Center alignment
        const x = (pageWidth - finalW) / 2;
        const y = (pageHeight - finalH) / 2;

        pdf.addImage(imgData, 'JPEG', x, y, finalW, finalH);
        pdf.save(`${filename}.pdf`);
    } else {
        const mime = config.format === 'JPG' ? 'image/jpeg' : 'image/png';
        const ext = config.format === 'JPG' ? 'jpg' : 'png';
        const dataUrl = finalCanvas.toDataURL(mime, config.quality);

        const link = document.createElement('a');
        link.download = `${filename}.${ext}`;
        link.href = dataUrl;
        link.click();
    }
  };

  return (
    <div className="flex h-screen overflow-hidden text-slate-200 bg-cyber selection:bg-cyan-500/30 font-inter">
      <ExportModal 
        isOpen={isExportModalOpen} 
        onClose={() => setIsExportModalOpen(false)} 
        onConfirm={processExport} 
        contentDimensions={dashboardRef.current ? { 
            width: dashboardRef.current.scrollWidth, 
            height: dashboardRef.current.scrollHeight 
        } : undefined}
      />

      {focusedWidget && (
        <div className="fixed inset-0 z-[100] bg-slate-950/90 backdrop-blur-xl flex flex-col animate-in fade-in duration-200">
           <div className="flex items-center justify-between px-8 py-6 border-b border-white/10">
              <div className="flex flex-col">
                  <span className="text-xs font-black text-slate-400 uppercase tracking-widest mb-1">{focusedWidget.type} Focus</span>
                  <h2 className="text-2xl font-black text-white">{focusedWidget.title}</h2>
              </div>
              <button 
                onClick={() => setFocusedWidget(null)}
                className="p-3 bg-white/10 hover:bg-white/20 rounded-full text-white transition-colors"
                aria-label="Close Focus View"
              >
                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
           </div>
           <div className="flex-1 p-12 overflow-hidden">
               <div className="w-full h-full bg-slate-900/50 rounded-[2rem] border border-white/5 p-8 shadow-2xl relative">
                   <ChartRenderer 
                     config={focusedWidget} 
                     data={filteredData}
                     onDrill={() => {}}
                     currentLevel="none"
                     drillPath={[]}
                     canDrill={false}
                   />
               </div>
           </div>
        </div>
      )}

      <Sidebar 
        activeTab={activeTab}
        setActiveTab={setActiveTab}
        isSidebarOpen={isSidebarOpen}
        onImport={handleFileUpload}
        onExport={() => setIsExportModalOpen(true)}
        toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)}
      />

      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-16 px-6 flex items-center justify-between shrink-0 glass-panel border-b border-white/5 z-40 bg-slate-900/80 backdrop-blur-xl">
          <div className="flex items-center gap-6 flex-1">
             <div className="flex items-center gap-3">
                <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-cyan-500 to-blue-600 flex items-center justify-center text-white shadow-lg shadow-cyan-500/20">
                   <Icons.Sparkles />
                </div>
                <div className="flex flex-col">
                    <span className="text-sm font-black text-white tracking-tight leading-none">FLASHFUSION</span>
                    <span className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{currentTemplate.name}</span>
                </div>
             </div>

             <div className="hidden lg:block flex-1 max-w-xl mx-6">
                <MagicBar 
                  onWidgetGenerated={handleWidgetGenerated} 
                  semanticModel={semanticModel} 
                  variant="header"
                />
             </div>
          </div>

          <div className="flex items-center gap-3">
             <div className="flex items-center gap-2 px-3 py-1.5 bg-white/5 rounded-full border border-white/5">
                <div className={`w-1.5 h-1.5 rounded-full ${isStreaming ? 'bg-emerald-400 animate-pulse shadow-[0_0_8px_#34d399]' : 'bg-slate-500'}`} />
                <span className="text-[9px] font-black uppercase tracking-widest text-slate-300">
                  {isStreaming ? "Live" : "Static"}
                </span>
             </div>

             <button 
                onClick={() => setIsLocked(!isLocked)}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${
                  !isLocked 
                    ? 'bg-cyan-600 text-white shadow-lg shadow-cyan-600/20' 
                    : 'bg-white/5 text-slate-300 border border-white/5 hover:bg-white/10'
                }`}
                aria-label={isLocked ? "Unlock Dashboard" : "Lock Dashboard"}
             >
                {isLocked ? <Icons.Lock /> : <Icons.Unlock />}
                {isLocked ? "Locked" : "Editing"}
             </button>
          </div>
        </header>

        <GlobalFilterBar 
           semanticModel={semanticModel} 
           data={data} 
           filters={globalFilters} 
           onFilterChange={handleGlobalFilterChange} 
        />

        <div className="flex-1 overflow-y-auto custom-scrollbar relative p-6 lg:p-8">
          {activeTab === 'dashboard' && (
            <div className="max-w-[1920px] mx-auto flex flex-col items-center">

              <div className="lg:hidden w-full mb-8">
                 <MagicBar onWidgetGenerated={handleWidgetGenerated} semanticModel={semanticModel} />
              </div>

              {dashboardWidgets.length === 0 && (
                <div className="text-center py-32 animate-in fade-in zoom-in duration-500">
                   <div className="mb-6 inline-flex p-5 rounded-[2rem] bg-white/5 text-cyan-400 border border-white/10">
                      <Icons.Sparkles />
                   </div>
                   <h1 className="text-4xl font-black text-white tracking-tighter mb-4">Start your story</h1>
                   <p className="text-slate-400 font-medium mb-8 max-w-md mx-auto">
                     Use the command bar above to generate insights, or load a blueprint to get started.
                   </p>
                   <button onClick={() => setDashboardWidgets(currentTemplate.widgets)} className="px-6 py-3 bg-white text-slate-950 rounded-xl font-bold uppercase tracking-tight hover:bg-slate-200 transition-all">Load Blueprint</button>
                </div>
              )}

              <div 
                ref={dashboardRef} 
                className="grid w-full pb-32 relative transition-all duration-300"
                style={{
                  gridTemplateColumns: `repeat(${GRID_SYSTEM.COLS}, minmax(0, 1fr))`,
                  gap: `${GRID_SYSTEM.GAP_PX}px`,
                  gridAutoRows: `${GRID_SYSTEM.ROW_HEIGHT_PX}px`
                }}
              >
                {dashboardWidgets.map(w => (
                  <WidgetContainer 
                    key={w.id} 
                    widget={w} 
                    isLocked={isLocked}
                    data={filteredData} 
                    onAnalyze={handleAnalyze}
                    onResize={handleWidgetResize}
                    onMove={handleWidgetMove}
                    onUpdate={handleWidgetUpdate}
                    onMaximize={setFocusedWidget} 
                  />
                ))}
              </div>
            </div>
          )}

          {activeTab === 'library' && (
             <div className="max-w-screen-xl mx-auto">
               <h1 className="text-3xl font-black text-white uppercase tracking-tighter mb-8">Library</h1>
               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                 {templates.map(t => (
                   <button 
                    key={t.id} 
                    onClick={() => { setSelectedTemplateId(t.id); setActiveTab('dashboard'); }}
                    className="glass-panel p-6 rounded-3xl border border-white/5 hover:border-cyan-500/30 text-left transition-all group relative overflow-hidden bg-slate-900/40 focus:ring-2 focus:ring-cyan-500 outline-none"
                   >
                     <div className="absolute top-0 right-0 w-24 h-24 bg-cyan-600/5 blur-3xl group-hover:bg-cyan-600/10 transition-all" />
                     <span className="text-[9px] font-black text-cyan-400 uppercase tracking-widest">{t.category}</span>
                     <h3 className="text-xl font-black text-white mt-1 group-hover:text-cyan-300 transition-colors">{t.name}</h3>
                     <p className="text-slate-400 text-xs mt-3 leading-relaxed line-clamp-2">{t.description}</p>
                   </button>
                 ))}
               </div>
             </div>
          )}

          {activeTab === 'about' && (
             <div className="max-w-3xl mx-auto text-center py-20">
                <div className="inline-flex p-6 rounded-full bg-white/5 border border-white/10 mb-8">
                   <Icons.Shield />
                </div>
                <h2 className="text-3xl font-black text-white mb-4">Privacy First</h2>
                <p className="text-slate-300 leading-relaxed mb-8 text-lg">
                   FlashFusion Observatory runs entirely in your browser. Your personal data is processed locally and never sent to our servers.
                </p>
             </div>
          )}
        </div>

        <AnalysisPanel 
          isOpen={isAnalysisOpen} 
          onClose={() => setIsAnalysisOpen(false)} 
          widget={analyzingWidget}
          analysis={analysisResult}
          isLoading={isAnalyzing}
        />
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useRef } from 'react';
import { WidgetConfig, VizType, GRID_SYSTEM, Annotation } from '../types';
import { ChartRenderer } from './ChartRenderer';
import { Icons } from '../constants';

const DRILL_HIERARCHY = ['region', 'category', 'date'];

interface WidgetContainerProps {
  widget: WidgetConfig;
  isLocked: boolean;
  data: any[];
  onAnalyze: (widget: WidgetConfig, currentData: any[]) => void;
  onResize: (id: string, w: number, h: number) => void;
  onMove: (id: string, x: number, y: number) => void;
  onUpdate: (id: string, updates: Partial<WidgetConfig>) => void;
  onMaximize?: (widget: WidgetConfig) => void;
}

export const WidgetContainer: React.FC<WidgetContainerProps> = ({ widget, isLocked, data, onAnalyze, onResize, onMove, onUpdate, onMaximize }) => {
  const [drillPath, setDrillPath] = useState<string[]>([]);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isResizing, setIsResizing] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showObservations, setShowObservations] = useState(false);
  const [newAnnotation, setNewAnnotation] = useState('');

  const currentLevelIndex = Math.min(drillPath.length, DRILL_HIERARCHY.length - 1);
  const currentLevel = DRILL_HIERARCHY[currentLevelIndex];
  const canDrill = drillPath.length < DRILL_HIERARCHY.length;

  const dataKeys = useMemo(() => data.length > 0 ? Object.keys(data[0]) : [], [data]);

  const filteredData = useMemo(() => {
    let result = data;
    drillPath.forEach((val, idx) => {
      const dim = DRILL_HIERARCHY[idx];
      result = result.filter(item => String(item[dim]) === val);
    });
    return result;
  }, [data, drillPath]);

  const handleDrill = (val: string) => {
    if (drillPath.length < DRILL_HIERARCHY.length) {
      setDrillPath([...drillPath, val]);
    }
  };

  const handleAddAnnotation = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAnnotation.trim()) return;

    const annotation: Annotation = {
      id: Date.now().toString(),
      text: newAnnotation.trim(),
      timestamp: Date.now()
    };

    const updated = [...(widget.annotations || []), annotation];
    onUpdate(widget.id, { annotations: updated });
    setNewAnnotation('');
  };

  const handleDeleteAnnotation = (id: string) => {
    const updated = (widget.annotations || []).filter(a => a.id !== id);
    onUpdate(widget.id, { annotations: updated });
  };

  const calculateGridCoords = (clientX: number, clientY: number, parent: HTMLElement) => {
    const rect = parent.getBoundingClientRect();
    const relativeX = clientX - rect.left;
    const relativeY = clientY - rect.top;

    const colWidth = (rect.width - (GRID_SYSTEM.COLS - 1) * GRID_SYSTEM.GAP_PX) / GRID_SYSTEM.COLS;
    const cellWidth = colWidth + GRID_SYSTEM.GAP_PX;
    const cellHeight = GRID_SYSTEM.ROW_HEIGHT_PX + GRID_SYSTEM.GAP_PX;

    return {
      x: Math.round(relativeX / cellWidth),
      y: Math.round(relativeY / cellHeight)
    };
  };

  const handleResizeStart = (e: React.MouseEvent) => {
    if (isLocked) return;
    e.preventDefault(); e.stopPropagation();
    setIsResizing(true);

    const parent = containerRef.current?.offsetParent as HTMLElement;
    if (!parent) return;

    const handleMouseMove = (moveEvent: MouseEvent) => {
      const coords = calculateGridCoords(moveEvent.clientX, moveEvent.clientY, parent);
      const newW = Math.max(2, coords.x - widget.x);
      const newH = Math.max(1, coords.y - widget.y);
      if (newW !== widget.w || newH !== widget.h) {
        onResize(widget.id, newW, newH);
      }
    };

    const handleMouseUp = () => {
      setIsResizing(false);
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };

    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  };

  const handleDragStart = (e: React.MouseEvent) => {
    if (isLocked) return;
    if ((e.target as HTMLElement).closest('button') || (e.target as HTMLElement).closest('select') || (e.target as HTMLElement).closest('input') || (e.target as HTMLElement).closest('video')) return;

    e.preventDefault();
    setIsDragging(true);

    const parent = containerRef.current?.offsetParent as HTMLElement;
    if (!parent) return;

    const rect = containerRef.current!.getBoundingClientRect();
    const offsetX = e.clientX - rect.left;
    const offsetY = e.clientY - rect.top;

    const handleMouseMove = (moveEvent: MouseEvent) => {
      const coords = calculateGridCoords(moveEvent.clientX - offsetX, moveEvent.clientY - offsetY, parent);
      if (coords.x !== widget.x || coords.y !== widget.y) {
        onMove(widget.id, coords.x, coords.y);
      }
    };

    const handleMouseUp = () => {
      setIsDragging(false);
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };

    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  };

  const annotationCount = widget.annotations?.length || 0;

  return (
    <div 
      ref={containerRef}
      className={`glass-panel rounded-3xl flex flex-col transition-all duration-200 relative group/widget bg-slate-900/60 backdrop-blur-md border border-white/5 
        ${isResizing || isDragging ? 'z-50 border-cyan-500 shadow-2xl scale-[1.01]' : 'hover:border-white/20 hover:bg-slate-900/80 shadow-lg'}
        ${!isLocked ? 'cursor-grab active:cursor-grabbing border-white/10 ring-1 ring-white/5' : ''}
      `}
      style={{ 
        gridColumn: `span ${widget.w}`, 
        gridRow: `span ${widget.h}`,
        gridColumnStart: widget.x + 1,
        gridRowStart: widget.y + 1,
        userSelect: isResizing || isDragging ? 'none' : 'auto'
      }}
      onMouseDown={handleDragStart}
      role="article"
      aria-label={`${widget.title} widget`}
    >
      <div className="px-5 py-4 flex items-center justify-between pointer-events-none">
        <div className="flex flex-col">
          <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5">{widget.type.replace('-', ' ')}</span>
          <span className="text-xs font-black text-slate-200 tracking-tight uppercase truncate max-w-[150px]">{widget.title}</span>
        </div>

        <div className="flex items-center gap-1 opacity-0 group-hover/widget:opacity-100 transition-all duration-200 pointer-events-auto">
          {onMaximize && (
            <button
               onClick={(e) => { e.stopPropagation(); onMaximize(widget); }}
               className="p-1.5 hover:bg-white/10 rounded-lg text-slate-400 hover:text-white transition-colors focus:ring-2 focus:ring-cyan-400 focus:outline-none"
               title="Focus Mode"
               aria-label="Maximize Widget"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" /></svg>
            </button>
          )}

          <button
             onClick={(e) => { e.stopPropagation(); setShowObservations(!showObservations); }}
             className={`p-1.5 rounded-lg transition-all flex items-center gap-1 focus:ring-2 focus:ring-cyan-400 focus:outline-none ${showObservations || annotationCount > 0 ? 'text-cyan-400 bg-cyan-500/10' : 'text-slate-500 hover:text-cyan-400 hover:bg-cyan-500/10'}`}
             title="Observations"
             aria-label="Toggle Observations"
          >
            <Icons.Pin />
            {annotationCount > 0 && <span className="text-[9px] font-black">{annotationCount}</span>}
          </button>

          <button
             onClick={(e) => { e.stopPropagation(); onAnalyze(widget, filteredData); }}
             className="p-1.5 hover:bg-cyan-500/10 rounded-lg text-cyan-400 transition-colors focus:ring-2 focus:ring-cyan-400 focus:outline-none"
             title="AI Analysis"
             aria-label="Analyze with AI"
          >
            <Icons.Sparkles />
          </button>
          {!isLocked && (
             <button 
                onClick={(e) => { e.stopPropagation(); setShowSettings(!showSettings); }}
                className="p-1.5 hover:bg-white/10 rounded-lg text-slate-500 hover:text-white transition-colors focus:ring-2 focus:ring-cyan-400 focus:outline-none"
                aria-label="Widget Settings"
             >
                <Icons.Settings />
             </button>
          )}
        </div>
      </div>

      <div className="flex-1 px-5 pb-5 pt-0 relative overflow-hidden flex flex-col" onMouseDown={(e) => e.stopPropagation()}>
        <ChartRenderer 
          config={widget} 
          data={filteredData} 
          onDrill={handleDrill} 
          currentLevel={currentLevel} 
          drillPath={drillPath} 
          canDrill={canDrill}
        />
      </div>

      {/* Observations Overlay */}
      {showObservations && (
        <div className="absolute inset-0 bg-slate-900/98 z-40 p-5 rounded-3xl animate-in fade-in zoom-in-95 duration-200 flex flex-col border border-white/10" onMouseDown={e => e.stopPropagation()}>
           <div className="flex justify-between items-center mb-4 shrink-0">
              <h4 className="font-black text-white uppercase tracking-tighter text-sm flex items-center gap-2">
                 <span className="text-cyan-400"><Icons.Pin /></span>
                 Observations
              </h4>
              <button onClick={() => setShowObservations(false)} className="text-slate-500 hover:text-white transition-colors">
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
           </div>

           <div className="flex-1 overflow-y-auto custom-scrollbar space-y-3 mb-4">
              {widget.annotations?.length ? (
                widget.annotations.map(note => (
                  <div key={note.id} className="p-3 rounded-xl bg-white/5 border border-white/5 group relative hover:bg-white/10 transition-colors">
                     <p className="text-sm text-slate-300 font-medium leading-relaxed">{note.text}</p>
                     <div className="flex justify-between items-center mt-2">
                        <span className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">{new Date(note.timestamp).toLocaleDateString()}</span>
                        <button onClick={() => handleDeleteAnnotation(note.id)} className="text-slate-600 hover:text-rose-400 opacity-0 group-hover:opacity-100 transition-all focus:opacity-100" aria-label="Delete note">
                           <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                        </button>
                     </div>
                  </div>
                ))
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-slate-600">
                   <div className="mb-2 opacity-50"><Icons.Pin /></div>
                   <p className="text-xs font-medium text-center">No observations recorded.<br/>Add context to your data.</p>
                </div>
              )}
           </div>

           <form onSubmit={handleAddAnnotation} className="shrink-0 relative">
              <input 
                type="text" 
                value={newAnnotation}
                onChange={(e) => setNewAnnotation(e.target.value)}
                placeholder="Type an observation..."
                className="w-full bg-black/50 border border-white/10 rounded-xl py-3 pl-4 pr-12 text-sm text-white focus:border-cyan-500 outline-none transition-all placeholder-slate-600 focus:ring-1 focus:ring-cyan-500"
              />
              <button 
                type="submit" 
                disabled={!newAnnotation.trim()}
                className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 rounded-lg bg-cyan-600 text-white disabled:opacity-0 disabled:pointer-events-none transition-all hover:bg-cyan-500"
                aria-label="Add Note"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
              </button>
           </form>
        </div>
      )}

      {showSettings && (
        <div className="absolute inset-0 bg-slate-900/98 z-50 p-6 rounded-3xl animate-in fade-in zoom-in-95 duration-200 overflow-y-auto custom-scrollbar border border-white/10" onMouseDown={e => e.stopPropagation()}>
           <div className="flex justify-between items-center mb-6">
              <h4 className="font-black text-white uppercase tracking-tighter text-sm">Widget Settings</h4>
              <button onClick={() => setShowSettings(false)} className="text-slate-500 hover:text-white"><Icons.Settings /></button>
           </div>

           <div className="space-y-5">
              <div className="space-y-1">
                 <label className="text-[9px] font-black text-slate-500 uppercase">Metric & Dimension</label>
                 <div className="grid grid-cols-2 gap-2">
                   <select 
                      value={widget.metric || ''}
                      onChange={(e) => onUpdate(widget.id, { metric: e.target.value })}
                      className="w-full bg-black/50 border border-white/10 rounded-xl p-2.5 text-xs text-white focus:border-cyan-500 outline-none"
                   >
                      <option value="">Auto Metric</option>
                      {dataKeys.filter(k => typeof data[0]?.[k] === 'number').map(k => <option key={k} value={k}>{k}</option>)}
                   </select>
                   <select 
                      value={widget.dimension || ''}
                      onChange={(e) => onUpdate(widget.id, { dimension: e.target.value })}
                      className="w-full bg-black/50 border border-white/10 rounded-xl p-2.5 text-xs text-white focus:border-cyan-500 outline-none"
                   >
                      <option value="">Auto Dimension</option>
                      {dataKeys.map(k => <option key={k} value={k}>{k}</option>)}
                   </select>
                 </div>
              </div>

              {widget.type === VizType.VIDEO && (
                 <div className="space-y-2 pt-2 border-t border-white/10">
                   <label className="text-[9px] font-black text-cyan-500 uppercase">Video Options</label>
                   <input 
                      type="text" 
                      placeholder="Video URL"
                      value={widget.videoUrl || ''}
                      onChange={(e) => onUpdate(widget.id, { videoUrl: e.target.value })}
                      className="w-full bg-black/50 border border-white/10 rounded-xl p-2.5 text-xs text-white focus:border-cyan-500 outline-none placeholder-slate-600 mb-2"
                   />
                   <div className="flex gap-2">
                     <input 
                        type="text" 
                        placeholder="Aspect Ratio (e.g. 16/9)"
                        value={widget.aspectRatio || ''}
                        onChange={(e) => onUpdate(widget.id, { aspectRatio: e.target.value })}
                        className="w-1/2 bg-black/50 border border-white/10 rounded-xl p-2.5 text-xs text-white focus:border-cyan-500 outline-none"
                     />
                     <div className="flex items-center gap-2 p-2 w-1/2">
                       <input 
                         type="checkbox"
                         checked={widget.autoPlay || false}
                         onChange={(e) => onUpdate(widget.id, { autoPlay: e.target.checked })}
                         className="rounded bg-black/50 border-white/10 text-cyan-500 focus:ring-cyan-500"
                       />
                       <span className="text-xs text-slate-300">AutoPlay</span>
                     </div>
                   </div>
                 </div>
              )}

              {/* Threshold Configuration */}
              <div className="space-y-2 pt-2 border-t border-white/10">
                 <label className="text-[9px] font-black text-emerald-500 uppercase flex items-center gap-1">
                   <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                   Reference & Goals
                 </label>
                 <div className="flex gap-2">
                   <input 
                      type="number" 
                      placeholder="Value"
                      value={widget.referenceValue || ''}
                      onChange={(e) => onUpdate(widget.id, { referenceValue: e.target.value ? Number(e.target.value) : undefined })}
                      className="w-1/2 bg-black/50 border border-white/10 rounded-xl p-2.5 text-xs text-white focus:border-emerald-500 outline-none placeholder-slate-600"
                   />
                   <select 
                      value={widget.referenceType || 'max'}
                      onChange={(e) => onUpdate(widget.id, { referenceType: e.target.value as 'min' | 'max' })}
                      className="w-1/2 bg-black/50 border border-white/10 rounded-xl p-2.5 text-xs text-white focus:border-emerald-500 outline-none"
                   >
                      <option value="min">Goal (Min)</option>
                      <option value="max">Limit (Max)</option>
                   </select>
                 </div>
                 <p className="text-[9px] text-slate-500 leading-tight">
                   {widget.referenceType === 'min' ? 'Metrics should stay ABOVE this value.' : 'Metrics should stay BELOW this value.'}
                 </p>
              </div>
           </div>
        </div>
      )}

      {!isLocked && (
        <div 
          onMouseDown={handleResizeStart}
          className="absolute bottom-2 right-2 w-6 h-6 cursor-se-resize z-20 flex items-center justify-center text-cyan-500 opacity-0 group-hover/widget:opacity-100 transition-opacity"
        >
          <svg className="w-4 h-4 transform rotate-45" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 5v14m7-14v14" /></svg>
        </div>
      )}
    </div>
  );
};

/**
 * OmniGen Type Definitions
 * 
 * This file contains all shared interfaces and constants for the application.
 */

/**
 * Grid Layout Configuration
 * Corresponds to Tailwind classes: grid-cols-12, gap-6 (24px), auto-rows-[100px]
 */
export const GRID_SYSTEM = {
  COLS: 12,
  ROW_HEIGHT_PX: 100,
  GAP_PX: 24, // tailwind gap-6
};

export enum VizType {
  TABLE = 'table',
  PIVOT = 'pivot',
  TIME_SERIES = 'time-series',
  FUNNEL = 'funnel',
  COHORT = 'cohort',
  GEO_MAP = 'geo-map',
  SANKEY = 'sankey',
  NETWORK = 'network',
  BAR = 'bar',
  COLUMN = 'column',
  STACKED_BAR = 'stacked-bar',
  SCATTER = 'scatter',
  HISTOGRAM = 'histogram',
  HEATMAP = 'heatmap',
  TREEMAP = 'treemap',
  BOX_PLOT = 'box-plot',
  GAUGE = 'gauge',
  WATERFALL = 'waterfall',
  KPI_CARD = 'kpi-card',
  VIDEO = 'video'
}

/**
 * Represents the inferred semantic layer of the dataset.
 * Used by the AI to generate relevant visualizations.
 */
export interface SemanticModel {
  entities: { name: string; description: string; likely_keys: string[]; example_fields: string[] }[];
  metrics: { name: string; definition: string; aggregation: string; grain: string; caveats?: string }[];
  dimensions: { name: string; type: string; examples: string[] }[];
  relationships: { from_entity: string; to_entity: string; join_keys: string[]; join_type: string; confidence: number }[];
  kpis: { name: string; metric: string; goal_direction: 'up' | 'down'; target: string; alert_threshold: string }[];
  glossary: { term: string; meaning: string; synonyms: string[] }[];
  quality_flags: { issue: string; impacted_fields: string[]; severity: 'low' | 'medium' | 'high'; suggested_fix: string }[];
  assumptions: { assumption: string; impact: string; confirm_by: string }[];
}

export interface Annotation {
  id: string;
  text: string;
  timestamp: number;
}

/**
 * Configuration for a single dashboard widget.
 * x, y, w, h are in Grid Units (not pixels).
 */
export interface WidgetConfig {
  id: string;
  type: VizType;
  title: string;
  metric?: string;             // The primary numeric value to plot
  dimension?: string;          // The primary grouping key (X-Axis)
  secondaryDimension?: string; // The secondary grouping key (Legend/Y-Axis)
  filter?: Record<string, any>;

  // Threshold Monitoring
  referenceValue?: number;     // The target or limit value
  referenceType?: 'min' | 'max'; // 'min' = Goal (Must exceed), 'max' = Limit (Must stay under)

  // Video Specific
  videoUrl?: string;
  poster?: string;
  aspectRatio?: string; // e.g., "16/9", "4/3", "21/9"
  autoPlay?: boolean;

  // Observations
  annotations?: Annotation[];

  w: number; // Width in grid columns (1-12)
  h: number; // Height in grid rows
  x: number; // Column start (0-11)
  y: number; // Row start
}

export interface DashboardTemplate {
  id: string;
  name: string;
  category: string;
  description: string;
  widgets: WidgetConfig[];
  difficulty: 'Basic' | 'Advanced';
}

export interface AnalysisResult {
  summary: string;
  drivers: string[];
  recommendations: string[];
  sentiment: 'positive' | 'negative' | 'neutral';
  marketContext?: string;
  sources?: { title: string; uri: string }[];
}

import React, { useRef, useState, useEffect, useCallback } from 'react';

interface HeroVideoProps {
  src?: string;
  poster?: string;
  aspectRatio?: string; // e.g. "16/9"
  autoPlay?: boolean;
}

export const HeroVideo: React.FC<HeroVideoProps> = ({ 
  src = "https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/BigBuckBunny.mp4", 
  poster, 
  aspectRatio = "16/9", 
  autoPlay = false 
}) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [progress, setProgress] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [showControls, setShowControls] = useState(false);

  // Handle Aspect Ratio
  const ratioParts = aspectRatio.split('/').map(Number);
  const calculatedRatio = ratioParts.length === 2 ? `${ratioParts[0]} / ${ratioParts[1]}` : '16 / 9';

  // Keyboard Controls
  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (!videoRef.current) return;

    switch (e.key) {
      case ' ':
      case 'k':
        e.preventDefault();
        togglePlay();
        break;
      case 'm':
        e.preventDefault();
        toggleMute();
        break;
      case 'ArrowRight':
        e.preventDefault();
        videoRef.current.currentTime += 5;
        break;
      case 'ArrowLeft':
        e.preventDefault();
        videoRef.current.currentTime -= 5;
        break;
    }
  };

  const togglePlay = () => {
    if (!videoRef.current) return;
    if (videoRef.current.paused) {
      videoRef.current.play().catch(e => console.error("Play failed", e));
      setIsPlaying(true);
    } else {
      videoRef.current.pause();
      setIsPlaying(false);
    }
  };

  const toggleMute = () => {
    if (!videoRef.current) return;
    videoRef.current.muted = !videoRef.current.muted;
    setIsMuted(videoRef.current.muted);
  };

  const handleTimeUpdate = () => {
    if (videoRef.current) {
      const p = (videoRef.current.currentTime / videoRef.current.duration) * 100;
      setProgress(isNaN(p) ? 0 : p);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (videoRef.current) {
      const time = (Number(e.target.value) / 100) * videoRef.current.duration;
      videoRef.current.currentTime = time;
      setProgress(Number(e.target.value));
    }
  };

  // AutoPlay logic respecting reduced motion
  useEffect(() => {
    const video = videoRef.current;
    if (!video || !autoPlay) return;

    const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    if (prefersReducedMotion) return;

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            video.play().then(() => setIsPlaying(true)).catch(() => {
              // Autoplay might be blocked by browser policy without mute
              video.muted = true;
              setIsMuted(true);
              video.play().then(() => setIsPlaying(true)).catch(e => console.log("Autoplay blocked", e));
            });
          } else {
            video.pause();
            setIsPlaying(false);
          }
        });
      },
      { threshold: 0.5 }
    );

    observer.observe(video);
    return () => observer.disconnect();
  }, [autoPlay]);

  if (error) {
    return (
      <div 
        className="w-full h-full flex flex-col items-center justify-center bg-slate-900 border border-slate-700 rounded-xl p-6 text-center"
        style={{ aspectRatio: calculatedRatio }}
      >
        <svg className="w-10 h-10 text-rose-500 mb-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
        </svg>
        <p className="text-slate-300 font-bold">Video Unavailable</p>
        <p className="text-slate-500 text-xs mt-1">Unable to load media source.</p>
      </div>
    );
  }

  return (
    <div 
      ref={containerRef}
      className="relative group w-full bg-black rounded-xl overflow-hidden focus:ring-2 focus:ring-cyan-400 focus:outline-none"
      style={{ aspectRatio: calculatedRatio }}
      onMouseEnter={() => setShowControls(true)}
      onMouseLeave={() => setShowControls(false)}
      onKeyDown={handleKeyDown}
      tabIndex={0}
      role="region"
      aria-label="Video Player"
    >
      <video
        ref={videoRef}
        src={src}
        poster={poster}
        className="w-full h-full object-cover"
        onTimeUpdate={handleTimeUpdate}
        onError={() => setError("Failed to load video")}
        onEnded={() => setIsPlaying(false)}
        playsInline
      />

      {/* Controls Overlay */}
      <div className={`absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent transition-opacity duration-300 flex flex-col justify-end p-4 ${showControls || !isPlaying ? 'opacity-100' : 'opacity-0'}`}>

        {/* Seek Bar */}
        <input
          type="range"
          min="0"
          max="100"
          value={progress}
          onChange={handleSeek}
          className="w-full h-1 bg-slate-600 rounded-lg appearance-none cursor-pointer accent-cyan-400 mb-4 focus:outline-none focus:ring-2 focus:ring-cyan-400"
          aria-label="Seek"
        />

        <div className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button
              onClick={togglePlay}
              className="text-white hover:text-cyan-400 transition-colors focus:text-cyan-400 focus:outline-none"
              aria-label={isPlaying ? "Pause" : "Play"}
            >
              {isPlaying ? (
                <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M6 4h4v16H6V4zm8 0h4v16h-4V4z"/></svg>
              ) : (
                <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg>
              )}
            </button>

            <button
              onClick={toggleMute}
              className="text-white hover:text-cyan-400 transition-colors focus:text-cyan-400 focus:outline-none"
              aria-label={isMuted ? "Unmute" : "Mute"}
            >
              {isMuted ? (
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" strokeDasharray="20 2" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2" /></svg>
              ) : (
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" /></svg>
              )}
            </button>
          </div>

          <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
             {isPlaying ? 'Playing' : 'Paused'}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { Icons } from '../constants';
import { VizType, WidgetConfig } from '../types';
import { VizArea } from './VizArea';
import { VizBar } from './VizBar';
import { VizKPI } from './VizKPI';
import { VizScatter } from './VizScatter';
import { VizHeatmap } from './VizHeatmap';
import { VizTreemap } from './VizTreemap';
import { VizTable } from './VizTable';
import { HeroVideo } from './HeroVideo';

interface ChartRendererProps {
  config: WidgetConfig;
  data: any[];
  onDrill: (value: string) => void;
  currentLevel: string;
  drillPath: string[];
  canDrill: boolean;
}

/**
 * Renders the appropriate visualization based on the widget configuration.
 * Handles data aggregation, transformation, and distribution to specific Viz components.
 */
export const ChartRenderer: React.FC<ChartRendererProps> = ({ config, data, onDrill, currentLevel, drillPath, canDrill }) => {

  // -- Standard Aggregation (Bar, Line, KPI) --
  const standardData = useMemo(() => {
    if ([VizType.SCATTER, VizType.HEATMAP, VizType.TREEMAP, VizType.TABLE, VizType.VIDEO].includes(config.type)) return [];

    const metric = config.metric || 'sales';
    const dim = config.dimension || currentLevel;
    const agg: Record<string, any> = {};

    data.forEach(item => {
      const key = String(item[dim] || 'Unknown');

      if (!agg[key]) {
        agg[key] = { [dim]: key };
        agg[key][metric] = 0;

        if (metric !== 'sales' && 'sales' in item) agg[key]['sales'] = 0;
        if (metric !== 'users' && 'users' in item) agg[key]['users'] = 0;
      }

      const val = Number(item[metric]);
      if (!isNaN(val)) {
        agg[key][metric] += val;
      }

      if (metric !== 'sales' && item.sales) agg[key]['sales'] += Number(item.sales) || 0;
      if (metric !== 'users' && item.users) agg[key]['users'] += Number(item.users) || 0;
    });

    return Object.values(agg).sort((a, b) => String(a[dim]).localeCompare(String(b[dim])));
  }, [data, currentLevel, config.type, config.metric, config.dimension]);

  // -- Scatter Data --
  const scatterData = useMemo(() => {
    if (config.type !== VizType.SCATTER) return [];
    const xKey = config.dimension || 'sales';
    const yKey = config.secondaryDimension || 'users';
    const zKey = config.metric || 'conversion';

    return data.map(d => ({
        ...d,
        [xKey]: Number(d[xKey] || 0),
        [yKey]: Number(d[yKey] || 0),
        [zKey]: Number(d[zKey] || 0),
    }));
  }, [data, config.type, config.dimension, config.secondaryDimension, config.metric]);

  // -- Heatmap Data --
  const heatmapData = useMemo(() => {
    if (config.type !== VizType.HEATMAP) return [];
    const xKey = config.dimension || 'category';
    const yKey = config.secondaryDimension || 'region';
    const valKey = config.metric || 'sales';

    const agg: Record<string, any> = {};
    data.forEach(item => {
        const x = String(item[xKey] || 'N/A');
        const y = String(item[yKey] || 'N/A');
        const key = `${x}-${y}`;
        if(!agg[key]) agg[key] = { [xKey]: x, [yKey]: y, [valKey]: 0 };
        agg[key][valKey] += Number(item[valKey] || 0);
    });
    return Object.values(agg);
  }, [data, config.type, config.dimension, config.secondaryDimension, config.metric]);

  // -- Treemap Data --
  const treemapData = useMemo(() => {
      if (config.type !== VizType.TREEMAP) return [];
      const dimKey = config.dimension || currentLevel;
      const valKey = config.metric || 'sales';

      const agg: Record<string, number> = {};
      data.forEach(item => {
          const key = String(item[dimKey] || 'Unknown');
          agg[key] = (agg[key] || 0) + (Number(item[valKey]) || 0);
      });
      return Object.entries(agg).map(([name, size]) => ({ name, size }));
  }, [data, config.type, currentLevel, config.dimension, config.metric]);

  switch (config.type) {
    case VizType.TIME_SERIES:
      return <VizArea 
        data={standardData} 
        onDrill={onDrill} 
        currentLevel={config.dimension || currentLevel} 
        drillPath={drillPath} 
        canDrill={canDrill}
        metric={config.metric || 'sales'}
        referenceValue={config.referenceValue}
      />;

    case VizType.BAR:
      return <VizBar 
        data={standardData} 
        onDrill={onDrill} 
        currentLevel={config.dimension || currentLevel} 
        drillPath={drillPath} 
        canDrill={canDrill}
        metric={config.metric || 'sales'}
        referenceValue={config.referenceValue}
      />;

    case VizType.KPI_CARD:
      const metric = config.metric || 'sales';
      const total = standardData.reduce((acc, curr) => acc + (Number(curr[metric]) || 0), 0);
      const formattedTotal = new Intl.NumberFormat('en-US', { 
        notation: "compact", 
        compactDisplay: "short" 
      }).format(total);

      return <VizKPI 
        title={config.title} 
        value={formattedTotal} 
        trend="--" 
        isPositive={true} 
        rawValue={total}
        referenceValue={config.referenceValue}
        referenceType={config.referenceType}
      />;

    case VizType.SCATTER:
        return <VizScatter 
          data={scatterData} 
          xKey={config.dimension || 'sales'}
          yKey={config.secondaryDimension || 'users'}
          zKey={config.metric || 'conversion'}
        />;

    case VizType.HEATMAP:
        return <VizHeatmap 
          data={heatmapData} 
          xKey={config.dimension || 'category'} 
          yKey={config.secondaryDimension || 'region'} 
          valKey={config.metric || 'sales'} 
        />;

    case VizType.TREEMAP:
        return <VizTreemap data={treemapData} />;

    case VizType.TABLE:
        // Pass raw filtered data directly to table
        return <VizTable data={data} />;

    case VizType.VIDEO:
      return <HeroVideo 
        src={config.videoUrl} 
        poster={config.poster}
        aspectRatio={config.aspectRatio}
        autoPlay={config.autoPlay}
      />;

    default:
      return (
        <div className="flex flex-col items-center justify-center h-full text-slate-500 gap-2">
          <Icons.Dashboard />
          <span className="text-xs font-semibold uppercase tracking-widest">{config.type} Placeholder</span>
        </div>
      );
  }
};

import React, { useState, useMemo, useEffect, useCallback, useRef } from 'react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';
import { Icons } from './constants';
import { WidgetConfig, AnalysisResult, GRID_SYSTEM } from './types';
import { inferSemanticModel } from './services/semanticEngine';
import { generateTemplates } from './services/templateService';
import { generateAnalysis } from './services/aiService';
import { WidgetContainer } from './components/WidgetContainer';
import { Sidebar } from './components/Sidebar';
import { MagicBar } from './components/MagicBar';
import { AnalysisPanel } from './components/AnalysisPanel';
import { useDataManager } from './hooks/useDataManager';
import { ExportModal, ExportConfig } from './components/ExportModal';
import { GlobalFilterBar } from './components/GlobalFilterBar';
import { ChartRenderer } from './components/ChartRenderer';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'library' | 'about'>('dashboard');
  const [isLocked, setIsLocked] = useState(true);
  const [selectedTemplateId, setSelectedTemplateId] = useState('personal-health');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const [dashboardWidgets, setDashboardWidgets] = useState<WidgetConfig[]>([]);
  const [isAnalysisOpen, setIsAnalysisOpen] = useState(false);
  const [analyzingWidget, setAnalyzingWidget] = useState<WidgetConfig | null>(null);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isExportModalOpen, setIsExportModalOpen] = useState(false);

  const [globalFilters, setGlobalFilters] = useState<Record<string, string>>({});
  const [focusedWidget, setFocusedWidget] = useState<WidgetConfig | null>(null);

  const dashboardRef = useRef<HTMLDivElement>(null);

  const templates = useMemo(() => generateTemplates(), []);
  const currentTemplate = useMemo(() => 
    templates.find(t => t.id === selectedTemplateId) || templates[0], 
    [templates, selectedTemplateId]
  );

  const { data, isStreaming, setIsStreaming, handleFileUpload } = useDataManager(currentTemplate.name);
  const semanticModel = useMemo(() => inferSemanticModel(data), [data]);

  // Apply Global Filters to Data
  const filteredData = useMemo(() => {
    let result = data;
    Object.entries(globalFilters).forEach(([key, value]) => {
        if (!value) return;
        result = result.filter(item => {
           const itemKey = Object.keys(item).find(k => k.toLowerCase() === key.toLowerCase());
           return itemKey ? String(item[itemKey]) === value : true;
        });
    });
    return result;
  }, [data, globalFilters]);

  const handleGlobalFilterChange = (key: string, value: string) => {
      setGlobalFilters(prev => ({ ...prev, [key]: value }));
  };

  useEffect(() => {
    const savedLayout = localStorage.getItem(`flashfusion_layout_${selectedTemplateId}`);
    if (savedLayout) {
      try {
        setDashboardWidgets(JSON.parse(savedLayout));
      } catch (e) {
        setDashboardWidgets(currentTemplate.widgets);
      }
    } else {
      setDashboardWidgets(currentTemplate.widgets);
    }
  }, [currentTemplate, selectedTemplateId]);

  useEffect(() => {
    if (dashboardWidgets.length > 0) {
      localStorage.setItem(`flashfusion_layout_${selectedTemplateId}`, JSON.stringify(dashboardWidgets));
    }
  }, [dashboardWidgets, selectedTemplateId]);

  const checkCollision = (id: string, x: number, y: number, w: number, h: number, widgets: WidgetConfig[]): boolean => {
    return widgets.some(other => {
      if (other.id === id) return false;
      return (
        x < other.x + other.w &&
        x + w > other.x &&
        y < other.y + other.h &&
        y + h > other.y
      );
    });
  };

  const handleWidgetGenerated = (newWidget: WidgetConfig) => {
    setDashboardWidgets(prev => {
      let placed = false;
      let y = 0;
      const widgetToPlace = { ...newWidget };
      while (!placed && y < 50) {
        for (let x = 0; x <= GRID_SYSTEM.COLS - widgetToPlace.w; x++) {
           if (!checkCollision(widgetToPlace.id, x, y, widgetToPlace.w, widgetToPlace.h, prev)) {
             widgetToPlace.x = x;
             widgetToPlace.y = y;
             placed = true;
             break;
           }
        }
        y++;
      }
      return [...prev, widgetToPlace];
    });
  };

  const handleWidgetResize = useCallback((id: string, newW: number, newH: number) => {
    setDashboardWidgets(prev => {
      const target = prev.find(w => w.id === id);
      if (!target) return prev;
      if (target.x + newW > GRID_SYSTEM.COLS) return prev;
      if (checkCollision(id, target.x, target.y, newW, newH, prev)) return prev;
      return prev.map(w => w.id === id ? { ...w, w: newW, h: newH } : w);
    });
  }, []);

  const handleWidgetMove = useCallback((id: string, newX: number, newY: number) => {
    setDashboardWidgets(prev => {
      const target = prev.find(w => w.id === id);
      if (!target) return prev;
      if (newX < 0 || newX + target.w > GRID_SYSTEM.COLS || newY < 0) return prev;
      if (checkCollision(id, newX, newY, target.w, target.h, prev)) return prev;
      return prev.map(w => w.id === id ? { ...w, x: newX, y: newY } : w);
    });
  }, []);

  const handleWidgetUpdate = useCallback((id: string, updates: Partial<WidgetConfig>) => {
    setDashboardWidgets(prev => prev.map(w => w.id === id ? { ...w, ...updates } : w));
  }, []);

  const handleAnalyze = async (widget: WidgetConfig, currentData: any[]) => {
    setAnalyzingWidget(widget);
    setIsAnalysisOpen(true);
    setAnalysisResult(null);
    setIsAnalyzing(true);
    const result = await generateAnalysis(widget.title, currentData);
    setAnalysisResult(result);
    setIsAnalyzing(false);
  };

  const processExport = async (config: ExportConfig) => {
    if (!dashboardRef.current) return;
    setIsExportModalOpen(false);

    // 1. Capture Dashboard Canvas
    const scale = config.dpi / 96;
    const canvas = await html2canvas(dashboardRef.current, {
      backgroundColor: '#020617',
      scale: scale,
      useCORS: true,
      logging: false,
    });

    // 2. Prepare Composition Canvas (for metadata)
    let finalCanvas = canvas;

    if (config.includeTitle || config.includeDate) {
        const titleHeight = config.includeTitle ? 60 * scale : 0;
        const dateHeight = config.includeDate ? 30 * scale : 0;
        const padding = 40 * scale;
        const totalHeaderHeight = titleHeight + dateHeight + (config.includeTitle || config.includeDate ? padding : 0);

        const compositCanvas = document.createElement('canvas');
        compositCanvas.width = canvas.width + (padding * 2);
        compositCanvas.height = canvas.height + totalHeaderHeight + padding;

        const ctx = compositCanvas.getContext('2d');
        if (ctx) {
            // Fill Background
            ctx.fillStyle = '#020617';
            ctx.fillRect(0, 0, compositCanvas.width, compositCanvas.height);

            // Draw Metadata
            ctx.textAlign = 'left';
            ctx.textBaseline = 'top';
            let currentY = padding;

            if (config.includeTitle) {
                ctx.fillStyle = '#f1f5f9'; // slate-100
                ctx.font = `900 ${32 * scale}px Inter, sans-serif`;
                ctx.fillText(currentTemplate.name, padding, currentY);
                currentY += titleHeight;
            }

            if (config.includeDate) {
                ctx.fillStyle = '#94a3b8'; // slate-400
                ctx.font = `500 ${14 * scale}px Inter, sans-serif`;
                ctx.fillText(new Date().toLocaleDateString(undefined, { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }), padding, currentY);
                currentY += dateHeight;
            }

            if (config.includeTitle || config.includeDate) {
                currentY += (10 * scale); // spacer
            }

            // Draw captured dashboard
            ctx.drawImage(canvas, padding, currentY);
            finalCanvas = compositCanvas;
        }
    }

    // 3. Output Generation
    const filename = `${currentTemplate.name.replace(/\s+/g, '_')}`;

    if (config.format === 'PDF') {
        const pdf = new jsPDF({
            orientation: config.orientation,
            unit: 'mm',
            format: config.paperSize
        });

        const pageWidth = pdf.internal.pageSize.getWidth();
        const pageHeight = pdf.internal.pageSize.getHeight();

        // Convert canvas to image data
        const imgData = finalCanvas.toDataURL('image/jpeg', config.quality);

        // Calculate fit dimensions
        const imgRatio = finalCanvas.width / finalCanvas.height;
        let finalW = pageWidth;
        let finalH = pageWidth / imgRatio;

        if (finalH > pageHeight) {
            finalH = pageHeight;
            finalW = pageHeight * imgRatio;
        }

        // Center alignment
        const x = (pageWidth - finalW) / 2;
        const y = (pageHeight - finalH) / 2;

        pdf.addImage(imgData, 'JPEG', x, y, finalW, finalH);
        pdf.save(`${filename}.pdf`);
    } else {
        const mime = config.format === 'JPG' ? 'image/jpeg' : 'image/png';
        const ext = config.format === 'JPG' ? 'jpg' : 'png';
        const dataUrl = finalCanvas.toDataURL(mime, config.quality);

        const link = document.createElement('a');
        link.download = `${filename}.${ext}`;
        link.href = dataUrl;
        link.click();
    }
  };

  return (
    <div className="flex h-screen overflow-hidden text-slate-200 bg-cyber selection:bg-cyan-500/30 font-inter">
      <ExportModal 
        isOpen={isExportModalOpen} 
        onClose={() => setIsExportModalOpen(false)} 
