import React, { useMemo } from 'react';
import { SemanticModel } from '../types';

interface GlobalFilterBarProps {
  semanticModel: SemanticModel;
  data: any[];
  filters: Record<string, string>;
  onFilterChange: (key: string, value: string) => void;
}

export const GlobalFilterBar: React.FC<GlobalFilterBarProps> = ({ semanticModel, data, filters, onFilterChange }) => {
  // Extract categorical dimensions that are useful for filtering
  const filterableDimensions = useMemo(() => 
    semanticModel.dimensions.filter(d => d.type === 'Categorical' || d.name.includes('Date')), 
  [semanticModel]);

  // Get unique values for each dimension from the actual data
  const options = useMemo(() => {
    const opts: Record<string, string[]> = {};
    if (data.length === 0) return opts;

    filterableDimensions.forEach(dim => {
      // Find the actual data key (simple matching strategy)
      const sample = data[0];
      const key = Object.keys(sample).find(k => k.toLowerCase() === dim.name.toLowerCase()) || dim.name.toLowerCase();

      // Get unique values
      const unique = Array.from(new Set(data.map(item => String(item[key] || '')))).filter(Boolean) as string[];
      opts[dim.name] = unique.sort().slice(0, 50); // Limit dropdown size for perf
    });
    return opts;
  }, [data, filterableDimensions]);

  return (
    <div className="flex items-center gap-3 px-8 py-3 border-b border-white/5 bg-slate-900/40 backdrop-blur-md sticky top-0 z-30 overflow-x-auto custom-scrollbar">
      <div className="flex items-center gap-2 text-slate-500 mr-2 shrink-0">
        <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" /></svg>
        <span className="text-[10px] font-black uppercase tracking-widest">Filters</span>
      </div>

      {filterableDimensions.map(dim => (
        <div key={dim.name} className="relative group shrink-0">
           <select
             value={filters[dim.name] || ''}
             onChange={(e) => onFilterChange(dim.name, e.target.value)}
             className="appearance-none bg-white/5 hover:bg-white/10 border border-white/5 hover:border-white/20 text-[11px] font-bold text-slate-300 rounded-lg py-1.5 pl-3 pr-8 outline-none focus:ring-1 focus:ring-cyan-500 transition-all cursor-pointer min-w-[120px]"
           >
             <option value="">All {dim.name}s</option>
             {options[dim.name]?.map(opt => (
               <option key={opt} value={opt}>{opt}</option>
             ))}
           </select>
           <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500">
             <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
           </div>
        </div>
      ))}

      {Object.keys(filters).length > 0 && (
        <button 
          onClick={() => Object.keys(filters).forEach(k => onFilterChange(k, ''))}
          className="ml-auto text-[9px] font-bold text-cyan-400 hover:text-cyan-300 uppercase tracking-wider px-3 py-1 bg-cyan-500/10 rounded-full border border-cyan-500/20"
        >
          Clear Active
        </button>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';

interface VizTableProps {
  data: any[];
}

type SortDirection = 'asc' | 'desc';

interface SortConfig {
  key: string;
  direction: SortDirection;
}

export const VizTable: React.FC<VizTableProps> = ({ data }) => {
  const [sortConfig, setSortConfig] = useState<SortConfig | null>(null);

  // 1. Extract Columns
  const columns = useMemo(() => {
    if (data.length === 0) return [];
    return Object.keys(data[0]);
  }, [data]);

  // 2. Compute Column Maxima for Heat Bars
  const columnMaxValues = useMemo(() => {
    const maxes: Record<string, number> = {};
    columns.forEach(col => {
      // Check if column is numeric
      if (typeof data[0][col] === 'number') {
        maxes[col] = Math.max(...data.map(d => Number(d[col]) || 0));
      }
    });
    return maxes;
  }, [data, columns]);

  // 3. Handle Sorting
  const sortedData = useMemo(() => {
    if (!sortConfig) return data;
    return [...data].sort((a, b) => {
      const valA = a[sortConfig.key];
      const valB = b[sortConfig.key];

      if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
      if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
      return 0;
    });
  }, [data, sortConfig]);

  const handleSort = (key: string) => {
    setSortConfig(current => {
      if (current?.key === key) {
        return { key, direction: current.direction === 'asc' ? 'desc' : 'asc' };
      }
      return { key, direction: 'asc' };
    });
  };

  if (data.length === 0) {
    return (
      <div className="flex items-center justify-center h-full text-slate-500 text-xs uppercase tracking-widest font-bold">
        No Data Available
      </div>
    );
  }

  return (
    <div className="h-full w-full overflow-auto custom-scrollbar rounded-xl border border-white/5 bg-slate-950/30">
      <table className="w-full text-left border-collapse min-w-[400px]">
        <thead className="sticky top-0 z-10 bg-slate-900 shadow-lg ring-1 ring-white/5">
          <tr>
            {columns.map(col => (
              <th 
                key={col}
                onClick={() => handleSort(col)}
                className="p-3 text-[10px] font-black uppercase tracking-widest text-slate-400 cursor-pointer hover:text-white hover:bg-white/5 transition-colors select-none whitespace-nowrap"
              >
                <div className="flex items-center gap-2">
                  {col}
                  {sortConfig?.key === col && (
                    <span className="text-cyan-400">
                      {sortConfig.direction === 'asc' ? '↑' : '↓'}
                    </span>
                  )}
                </div>
              </th>
            ))}
          </tr>
        </thead>
        <tbody className="divide-y divide-white/5">
          {sortedData.map((row, idx) => (
            <tr key={idx} className="hover:bg-white/5 transition-colors group">
              {columns.map(col => {
                const val = row[col];
                const isNum = typeof val === 'number';
                const max = columnMaxValues[col];
                const percentage = isNum && max > 0 ? (val / max) * 100 : 0;

                return (
                  <td key={col} className="p-3 text-xs font-medium text-slate-300 relative">
                    {/* Heat Bar Background */}
                    {isNum && (
                      <div 
                        className="absolute inset-y-1 left-0 bg-cyan-500/10 rounded-r-md transition-all duration-500"
                        style={{ width: `${percentage}%` }}
                      />
                    )}

                    {/* Content */}
                    <span className="relative z-0 font-mono">
                      {isNum 
                        ? new Intl.NumberFormat('en-US', { maximumFractionDigits: 2 }).format(val)
                        : String(val)
                      }
                    </span>
                  </td>
                );
              })}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

import React from 'react';
import { TooltipProps } from 'recharts';

interface CustomTooltipProps extends TooltipProps<number, string> {
  currentLevel: string;
  drillPath: string[];
  canDrill: boolean;
}

export const VizTooltip: React.FC<CustomTooltipProps> = ({ active, payload, label, currentLevel, drillPath, canDrill }) => {
  if (active && payload && payload.length) {
    const total = payload.reduce((acc, entry) => acc + (typeof entry.value === 'number' ? entry.value : 0), 0);

    return (
      <div className="bg-slate-900/90 backdrop-blur-xl p-5 rounded-2xl shadow-2xl border border-white/20 min-w-[260px] animate-in fade-in zoom-in-95 duration-200 z-50">
        {/* Header */}
        <div className="flex flex-col gap-1.5 mb-4 pb-3 border-b border-white/10">
          <div className="flex items-center justify-between">
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
              {currentLevel}
            </span>
             {canDrill && (
                <span className="flex items-center gap-1 text-[9px] font-black text-cyan-400 uppercase tracking-wider bg-cyan-500/10 px-2 py-0.5 rounded-full border border-cyan-500/20">
                  Drill Down →
                </span>
             )}
          </div>
          <span className="text-xl font-black text-white tracking-tight leading-none">{label}</span>
        </div>

        {/* Metrics */}
        <div className="space-y-3">
          {payload.map((entry, index) => {
            const val = Number(entry.value);
            const percent = total > 0 ? ((val / total) * 100).toFixed(1) : '0.0';
            const isSales = entry.name.toLowerCase().includes('sales') || entry.name.toLowerCase().includes('revenue');

            return (
              <div key={index} className="group/item">
                <div className="flex items-center justify-between mb-1">
                  <div className="flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full ring-2 ring-slate-900 shadow-sm transition-transform group-hover/item:scale-125" style={{ backgroundColor: entry.color }}></div>
                    <span className="text-xs font-bold text-slate-400 capitalize group-hover/item:text-white transition-colors">{entry.name}</span>
                  </div>
                  <span className="text-sm font-black text-white font-mono tracking-tight">
                    {isSales 
                      ? new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(val)
                      : new Intl.NumberFormat('en-US').format(val)
                    }
                  </span>
                </div>
                {/* Progress Bar */}
                <div className="flex items-center gap-3">
                   <div className="flex-1 bg-slate-800 h-1.5 rounded-full overflow-hidden">
                     <div 
                       className="h-full rounded-full transition-all duration-500 ease-out shadow-[0_0_8px_currentColor]" 
                       style={{ width: `${percent}%`, backgroundColor: entry.color, color: entry.color }} 
                     />
                   </div>
                   <span className="text-[10px] font-semibold text-slate-500 w-9 text-right">{percent}%</span>
                </div>
              </div>
            );
          })}
        </div>

        {/* Total Footer */}
        {payload.length > 1 && (
            <div className="mt-4 pt-3 border-t border-white/10 flex justify-between items-end">
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">Total Volume</span>
                <span className="text-base font-black text-white font-mono">
                  {new Intl.NumberFormat('en-US', { notation: "compact", compactDisplay: "short" }).format(total)}
                </span>
            </div>
        )}

        {/* Filters Context */}
        {drillPath.length > 0 && (
          <div className="mt-4 pt-3 border-t border-white/10">
            <span className="text-[9px] font-bold text-cyan-400 uppercase tracking-widest mb-2 block">
              Applied Filters
            </span>
            <div className="flex flex-wrap gap-1.5">
              {drillPath.map((filter, i) => (
                <span key={i} className="px-2 py-1 bg-cyan-500/10 text-cyan-300 border border-cyan-500/20 rounded-lg text-[9px] font-bold shadow-sm">
                  {filter}
                </span>
              ))}
            </div>
          </div>
        )}
      </div>
    );
  }
  return null;
};

